uvre/","label":"VOIR LA CARTE"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"last_updated":"2026-03-22","menu_items":[{"category_type":"starter","display_label":"Entrées","items":[{"name":"Salade de Tofu frité","price_cents":480},{"name":"Algues marinées au sésame","price_cents":450},{"name":"Pommes de terre à la vinaigrette de Xi’an","price_cents":420},{"name":"Oreilles de porc pimentées","price_cents":550},{"name":"Concombre frappé à l’ail","price_cents":450},{"name":"Raviolis Porc & Chou (8 pièces)","price_cents":1200},{"name":"Raviolis Poulet & Champignon (8 pièces)","price_cents":1200},{"name":"Raviolis Végétariens (8 pièces)","price_cents":1150},{"name":"Assiette dégustation (12 pièces)","price_cents":1600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Mo au Porc mijoté","price_cents":650,"description":"Pain pita croustillant"},{"name":"Mo au Bœuf au curry","price_cents":700},{"name":"Mo au Canard laqué","price_cents":750},{"name":"Mo Végétarien","price_cents":600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Biang Biang au Bœuf mijoté","price_cents":1280,"description":"Nouilles larges maison, épices"},{"name":"Biang Biang au Porc haché","price_cents":1150},{"name":"Biang Biang Poulet croustillant","price_cents":1300},{"name":"Biang Biang Tomate & Œuf","price_cents":1080,"description":"Option végétarienne iconique"},{"name":"Biang Biang Canard laqué","price_cents":1450}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Mochi glacé (2)","price_cents":450},{"name":"Perles de coco","price_cents":480}]}],"dish_price":11.5}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-louvre/gallery_4.jpg"]', NULL, '{"text":"Une taverne vibrante dédiée aux saveurs de Xi''an, où l''authenticité se goûte dans chaque bol de nouilles tirées à la main.","must_eat":"Cuisine chinoise. Biang Biang & Mo (Pain traditionnel).","le_secret":"La pâte est pétrie et étirée sous vos yeux, une technique ancestrale qui donne aux nouilles cette mâche unique.","le_son":"Le bruit sourd des pâtes que l''on claque sur le plan de travail et l''animation joyeuse des convives.","le_must":"Le Mo au porc mijoté, un réconfort absolu."}', 'À quelques pas du Louvre, cette taverne est sans doute la plus raffinée du groupe. Avec son décor qui mêle pierres apparentes et design contemporain, elle offre une parenthèse de sérénité au cœur du 1er arrondissement. On y déguste les spécialités de Xi’an avec une élégance rare.', '• C’est l''adresse idéale si vous cherchez un déjeuner chic et authentique après une visite au Musée.
INSERT INTO places_fts VALUES ('poi-zhao-louvre', 'La Taverne de Zhao', 'restaurant', 'chinois', '22 rue Molière, 75001 Paris, France', '', 'À quelques pas du Louvre, cette taverne est sans doute la plus raffinée du groupe. Avec son décor qui mêle pierres apparentes et design contemporain, elle offre une parenthèse de sérénité au cœur du 1er arrondissement. On y déguste les spécialités de Xi’an avec une élégance rare.');
