2026-03-23","menu_items":[{"category_type":"starter","display_label":"Les Entrées","items":[{"name":"Les Berlingots iconiques (Soba et café)","price_cents":4500,"description":"Cœur coulant au Brillat-Savarin"},{"name":"Betterave plurielle (Longuemare)","price_cents":3200,"description":"Infusée au café et poivron"},{"name":"Huître Marennes d’Oléron fumée","price_cents":3800,"description":"Bois de cerisier et mélisse"},{"name":"Tourteau de casier au géranium","price_cents":4200,"description":"Petits pois et fraises vertes"},{"name":"Caviar Baeri et glace plancton","price_cents":6500},{"name":"Soupe de l’Himalaya aux lentilles","price_cents":2800}]},{"category_type":"main","display_label":"Les Plats","items":[{"name":"Pigeon de la Drôme fumé au café","price_cents":6200,"description":"Accompagné de petits pois"},{"name":"Lotte de petits bateaux (Tasmanie)","price_cents":5800,"description":"Poivre et asperges blanches"},{"name":"Wagyu Japonais A5 (Supplément)","price_cents":5000},{"name":"Sériole de ligne à la bergamote","price_cents":5400},{"name":"Saint-Jacques de la Baie de Seine","price_cents":5600},{"name":"Ris de veau croustillant au combawa","price_cents":6400},{"name":"Bar de ligne au poivre blanc","price_cents":6000},{"name":"Volaille de Bresse à la truffe","price_cents":6800}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Millefeuille Blanc au poivre Cubèbe","price_cents":2400,"description":"La signature d’Anne-Sophie Pic"},{"name":"Chocolat de la Drôme et genévrier","price_cents":2200},{"name":"Rhubarbe et Mélisse en textures","price_cents":2000},{"name":"Fraise Gariguette et Shiso","price_cents":2200},{"name":"Miel de forêt et glace onctueuse","price_cents":1800},{"name":"Café gourmand (5 mignardises)","price_cents":2500}]},{"category_type":"drink","display_label":"La Cave / Boissons","items":[{"name":"Accord Mets & Vins (Séquence Plaisir)","price_cents":9500},{"name":"Accord Mets & Boissons sans alcool","price_cents":7500},{"name":"Coupe de Champagne ASP","price_cents":2800},{"name":"Sélection de Thés Rares","price_cents":1200}]}],"dish_price":59}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-dame-de-pic/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Gastronomie moderne. Berlingots & Millefeuille Blanc","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'À quelques pas du Louvre, La Dame de Pic est l’ambassade parisienne de la cheffe Anne-Sophie Pic. Dans un cadre poudré et épuré, elle déploie une cuisine d’une sensibilité rare, jouant sur l’imprégnation et les arômes complexes. Chaque plat est une dentelle de saveurs, souvent sublimée par des accords parfumés inédits. Une expérience gastronomique d''une élégance absolue, étoilée au guide Michelin.', '• Pensez à réserver plusieurs semaines à l’avance pour le dîner, le lieu est très convoité.\n• Le Millefeuille Blanc est un passage obligé, c’est l’un des desserts les plus sophistiqués de Paris.\n• La cheffe déménagera à la Fondation Cartier en 2026, profitez de l’écrin historique de la rue du Louvre tant qu’il en est temps.', 'Louvre - Rivoli', '[1,7]', '[]', 'ChIJaWy42CNu5kcRSLqIejQtI7s', 1, 0);
INSERT INTO places_fts VALUES ('poi-la-dame-de-pic', 'La Dame de Pic', 'restaurant', 'gastronomique', '20 Rue du Louvre, 75001 Paris, France', '', 'À quelques pas du Louvre, La Dame de Pic est l’ambassade parisienne de la cheffe Anne-Sophie Pic. Dans un cadre poudré et épuré, elle déploie une cuisine d’une sensibilité rare, jouant sur l’imprégnation et les arômes complexes. Chaque plat est une dentelle de saveurs, souvent sublimée par des accords parfumés inédits. Une expérience gastronomique d''une élégance absolue, étoilée au guide Michelin.');
