rées","items":[{"name":"Salade de Tofu frité","price_cents":480},{"name":"Algues marinées au sésame","price_cents":450},{"name":"Pommes de terre à la vinaigrette de Xi’an","price_cents":420},{"name":"Oreilles de porc pimentées","price_cents":550},{"name":"Concombre frappé à l’ail","price_cents":450},{"name":"Raviolis Porc & Chou (8 pièces)","price_cents":1200},{"name":"Raviolis Poulet & Champignon (8 pièces)","price_cents":1200},{"name":"Raviolis Végétariens (8 pièces)","price_cents":1150},{"name":"Assiette dégustation (12 pièces)","price_cents":1600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Mo au Porc mijoté","price_cents":650,"description":"Pain pita croustillant"},{"name":"Mo au Bœuf au curry","price_cents":700},{"name":"Mo au Canard laqué","price_cents":750},{"name":"Mo Végétarien","price_cents":600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Biang Biang au Bœuf mijoté","price_cents":1280,"description":"Nouilles larges maison, épices"},{"name":"Biang Biang au Porc haché","price_cents":1150},{"name":"Biang Biang Poulet croustillant","price_cents":1300},{"name":"Biang Biang Tomate & Œuf","price_cents":1080,"description":"Option végétarienne iconique"},{"name":"Biang Biang Canard laqué","price_cents":1450}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Mochi glacé (2)","price_cents":450},{"name":"Perles de coco","price_cents":480}]}],"dish_price":11.5}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-saint-germain/gallery_4.jpg"]', NULL, '{"text":"Une taverne vibrante dédiée aux saveurs de Xi''an, où l''authenticité se goûte dans chaque bol de nouilles tirées à la main.","must_eat":"Cuisine chinoise. Biang Biang & Mo (Pain traditionnel).","le_secret":"La pâte est pétrie et étirée sous vos yeux, une technique ancestrale qui donne aux nouilles cette mâche unique.","le_son":"Le bruit sourd des pâtes que l''on claque sur le plan de travail et l''animation joyeuse des convives.","le_must":"Le Mo au porc mijoté, un réconfort absolu."}', 'À deux pas de l’Odéon, cette taverne est l’une des plus esthétiques du groupe. Inaugurée en juillet 2024, elle s’intègre au chic du 6e arrondissement tout en conservant l’âme brute de Xi’an. Le lieu est idéal pour un dîner élégant, sublimant l''art des nouilles Biang Biang dans un cadre épuré.', '• C’est l’adresse la plus ’cosy’ de la Rive Gauche : idéale pour faire découvrir la cuisine chinoise authentique dans un cadre soigné.
INSERT INTO places_fts VALUES ('poi-zhao-st-germain', 'La Taverne de Zhao', 'restaurant', 'chinois', '82 rue Mazarine, 75006 Paris, France', '', 'À deux pas de l’Odéon, cette taverne est l’une des plus esthétiques du groupe. Inaugurée en juillet 2024, elle s’intègre au chic du 6e arrondissement tout en conservant l’âme brute de Xi’an. Le lieu est idéal pour un dîner élégant, sublimant l''art des nouilles Biang Biang dans un cadre épuré.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-172', 'Café de la Mairie', 'cafe-mairie-6', 'café', 'cafe-terrasse', 'chill', 48.851508, 2.333704, 6, '8 Pl. Saint-Sulpice', '#8ccaf7', 'pin', 1, 3.2, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/hero.jpg', NULL, 3, 0, '€', NULL, NULL, NULL, 3, 14, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-terrasse"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3,"dish_price":14,"menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-mairie-6/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cafe-terrasse. Café de la Mairie.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Café de la Mairie est l’un des secrets les mieux gardés du 6e arrondissement. Face à l’église Saint-Sulpice, sa terrasse ombragée est un havre de calme absolu. Ici, le café est servi à l’ancienne et le service est d’une politesse rare. On y vient pour lire le journal, discuter à voix basse ou simplement observer la lumière sur la pierre de l’église. C’est le Paris éternel, celui des écrivains et des penseurs, qui s’offre ici en toute simplicité.', 'L’adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-172', 'Café de la Mairie', 'café', 'cafe-terrasse', '8 Pl. Saint-Sulpice', '', 'Le Café de la Mairie est l’un des secrets les mieux gardés du 6e arrondissement. Face à l’église Saint-Sulpice, sa terrasse ombragée est un havre de calme absolu. Ici, le café est servi à l’ancienne et le service est d’une politesse rare. On y vient pour lire le journal, discuter à voix basse ou simplement observer la lumière sur la pierre de l’église. C’est le Paris éternel, celui des écrivains et des penseurs, qui s’offre ici en toute simplicité.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-joayo-lux-75006', 'Joayo Luxembourg', 'joayo-luxembourg-paris-6', 'restaurant', 'coreen, barbecue, bibimbap, fait-maison', 'chill', 48.8464963, 2.3306421, 6, '54 Rue d’Assas, 75006 Paris', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/hero.jpg', 'joayoparis', 22, 0, '€', 6.8, NULL, NULL, NULL, 22, 50, '{"chill":70,"festif":40,"culturel":20}', '{}', '["restaurant","coreen","barbecue","bibimbap","fait-maison"]', '{"standard":"Lundi-Dimanche: 12:00-14:30, 19:00-22:30","display":"Lundi-Dimanche: 12:00-14:30, 19:00-22:30","detailed":"Lundi-Dimanche: 12:00-14:30, 19:00-22:30"}', '{"reservation_policy":"resa_conseillee","accessibility":true,"terrace":false,"opening_hours_raw":"Lundi-Dimanche: 12:00-14:30, 19:00-22:30","main_action":{"type":"site","url":"https://joayo-luxembourg.fr/fr","label":"RÉSERVER"},"menu_url":"https://joayo-luxembourg.fr/fr/notre-carte","terrasse":false,"viande_exception":false,"happy_hour":null}', '{"is_free":false,"avg_budget":30,"dish_price":22,"index_price":23,"pint_price":6.8,"soft_price":4,"smart_tip":"Le rapport qualité-quantité est imbattable grâce aux ’Banchans'' (accompagnements) et au riz servis à volonté avec les BBQs. Pour les petits budgets, le Bibimbap à 17€ est extrêmement généreux.","menu_items":[{"category_type":"main","display_label":"Barbecue Coréen (Riz & Banchans Illimités)","items":[{"name":"Bœuf Mariné (200g)","price_cents":2300,"description":"Bulgogi classique."},{"name":"Poulet Mariné Pimenté (200g)","price_cents":2200},{"name":"Porc Mariné Pimenté (200g)","price_cents":2200},{"name":"Canard Mariné (200g)","price_cents":2400},{"name":"Entrecôte Marinée (200g)","price_cents":2500},{"name":"Calamar Mariné Pimenté (150g)","price_cents":2300},{"name":"BBQ Végétarien (Tofu & Champignons)","price_cents":2200}]},{"category_type":"main","display_label":"Bibimbaps & Plats","items":[{"name":"Bibimbap Bœuf","price_cents":1700,"description":"Servi en bol de pierre chaud."},{"name":"Bibimbap Tofu","price_cents":1700},{"name":"Japchae Bœuf","price_cents":1900,"description":"Vermicelles de patate douce sautés."},{"name":"Kimbap Bœuf","price_cents":1400}]},{"category_type":"starter","display_label":"Entrées & Boissons","items":[{"name":"Mandu (Raviolis grillés - 6pcs)","price_cents":950},{"name":"Kimchi maison","price_cents":600},{"name":"Soju (Tous parfums - 32cl)","price_cents":1600},{"name":"Bière Cass Coréenne (33cl)","price_cents":650},{"name":"Bière Kloud (33cl)","price_cents":680}]}],"last_updated":"2026-03-04"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/joayo-luxembourg-paris-6/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Coreen. Joayo Luxembourg.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Situé à deux pas du Jardin du Luxembourg, Joayo Luxembourg est l’une des adresses les plus authentiques de la rive gauche pour le Barbecue Coréen. Le décor, mariant briques apparentes et boiseries chaleureuses, crée une atmosphère de taverne séoulite moderne. Chaque table est équipée de son propre système de grillade intégré, permettant une immersion totale. La promesse du lieu tient dans la fraîcheur des marinades et la générosité des banchan (petits plats d''accompagnement typiques) qui ponctuent tout le repas.', '• Ne commandez pas trop d’entrées : le riz et les 4 types de banchans (souvent kimchi, pousses de soja, radis marine, algues) sont servis à volonté avec tous les barbecues.
INSERT INTO places_fts VALUES ('poi-joayo-lux-75006', 'Joayo Luxembourg', 'restaurant', 'coreen barbecue bibimbap fait-maison', '54 Rue d’Assas, 75006 Paris', '', 'Situé à deux pas du Jardin du Luxembourg, Joayo Luxembourg est l’une des adresses les plus authentiques de la rive gauche pour le Barbecue Coréen. Le décor, mariant briques apparentes et boiseries chaleureuses, crée une atmosphère de taverne séoulite moderne. Chaque table est équipée de son propre système de grillade intégré, permettant une immersion totale. La promesse du lieu tient dans la fraîcheur des marinades et la générosité des banchan (petits plats d''accompagnement typiques) qui ponctuent tout le repas.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-136', 'Les Éditeurs', 'les-editeurs', 'café', 'cafe-litteraire', 'chill', 48.851941, 2.338382, 6, '4 Carr de l’Odéon', '#8ccaf7', 'pin', 1, 4.3, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/hero.jpg', NULL, 3.6, 0, '€', NULL, NULL, NULL, 3.6, 22, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-litteraire"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.6,"dish_price":22,"menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-editeurs/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cafe-litteraire. Les Éditeurs.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Installé dans une magnifique bâtisse à l’angle du Boulevard Saint-Germain, Les Éditeurs est le café littéraire par excellence. Entre les milliers de livres qui ornent les murs, les fauteuils en cuir rouge et la vue sur l’Odéon, l’ambiance est studieuse et feutrée. On y croise souvent des auteurs et des gens de l’édition, venus discuter de leur prochain manuscrit autour d’un café ou d''un club sandwich exemplaire. Une bulle de culture et de confort parisien.', 'L’adresse préférée des locaux, loin des foules habituelles.', 'À proximité', '[]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-136', 'Les Éditeurs', 'café', 'cafe-litteraire', '4 Carr de l’Odéon', '', 'Installé dans une magnifique bâtisse à l’angle du Boulevard Saint-Germain, Les Éditeurs est le café littéraire par excellence. Entre les milliers de livres qui ornent les murs, les fauteuils en cuir rouge et la vue sur l’Odéon, l’ambiance est studieuse et feutrée. On y croise souvent des auteurs et des gens de l’édition, venus discuter de leur prochain manuscrit autour d’un café ou d''un club sandwich exemplaire. Une bulle de culture et de confort parisien.');
