jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-de-flore/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-de-flore/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-de-flore/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-de-flore/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-de-flore/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cafe-litteraire. Café de Flore.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le mythe parisien par excellence. S’asseoir à une table du Flore, c’est prendre place dans le fantôme de Sartre, Simone de Beauvoir ou Picasso. Le décor Art Déco, avec ses banquettes rouges et ses miroirs, n’a pas bougé. Oui, c’est touristique, oui, le chocolat chaud est cher, mais il est servi dans des pichets en argent par des garçons de café qui sont des personnages de roman. On y vient autant pour voir que pour être vu, pour lire le journal en terrasse ou simplement pour toucher du doigt l’histoire littéraire de Saint-Germain-des-Prés.', 'Commandez le chocolat chaud, il est assez copieux pour deux.', 'Saint-Germain-des-Prés', '[4]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-003', 'Café de Flore', 'café', 'cafe-litteraire', '172 Boulevard Saint-Germain', '', 'Le mythe parisien par excellence. S’asseoir à une table du Flore, c’est prendre place dans le fantôme de Sartre, Simone de Beauvoir ou Picasso. Le décor Art Déco, avec ses banquettes rouges et ses miroirs, n’a pas bougé. Oui, c’est touristique, oui, le chocolat chaud est cher, mais il est servi dans des pichets en argent par des garçons de café qui sont des personnages de roman. On y vient autant pour voir que pour être vu, pour lire le journal en terrasse ou simplement pour toucher du doigt l’histoire littéraire de Saint-Germain-des-Prés.');
