:"Burgers & Hot Dog","items":[{"name":"Le Cavale (Steak haché, Saint-Nectaire)","price_cents":2000},{"name":"Le Gros cochon (Porc confit, cheddar)","price_cents":2000},{"name":"Le Guezmer Vege (Merguez veggie)","price_cents":2000}]},{"category_type":"dessert","display_label":"Pour Finir (Desserts & Fromages)","items":[{"name":"Fromage au choix","price_cents":600},{"name":"Assiette 3 fromages","price_cents":1200},{"name":"Mookie (Crème anglaise praliné, glace)","price_cents":1100},{"name":"Millefeuille","price_cents":1000},{"name":"Riz au lait de coco","price_cents":1100},{"name":"Des fruits, des fruits, des fruits","price_cents":1000},{"name":"Brioche perdue","price_cents":1000},{"name":"Mont blanc","price_cents":1100},{"name":"Café gourmand","price_cents":1000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cavale/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Street-food. Incontournables : les croquetas truffade, le magret de canard au sirop d’érable, et la fameuse brioche perdue en dessert.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Installée rue des Petites Écuries, Cavale est la brasserie moderne par excellence du 10ème arrondissement. Dotée d’une architecture singulière avec son plafond miroir, sa décoration léchée et sa terrasse couverte, le lieu vibre au rythme des bandes de copains qui s’y retrouvent pour de grandes tablées animées. Côté assiette, c’est une cuisine française créative, généreuse, et redoutablement efficace qui fait le pont entre classiques bistrotiers et street-food pointue.', '• Si vous cherchez un dîner romantique et calme, fuyez : l’endroit est réputé pour son niveau sonore extrêmement festif (et bruyant) en soirée.
INSERT INTO places_fts VALUES ('poi-cavale', 'Cavale', 'restaurant', 'street-food terrasse', '40 Rue des Petites Écuries', '', 'Installée rue des Petites Écuries, Cavale est la brasserie moderne par excellence du 10ème arrondissement. Dotée d’une architecture singulière avec son plafond miroir, sa décoration léchée et sa terrasse couverte, le lieu vibre au rythme des bandes de copains qui s’y retrouvent pour de grandes tablées animées. Côté assiette, c’est une cuisine française créative, généreuse, et redoutablement efficace qui fait le pont entre classiques bistrotiers et street-food pointue.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-307', 'L’Attirail Café', 'l-attirail-cafe', 'bar', 'bar de quartier, afterwork', 'festif', 48.8688572, 2.3579085, 10, '8 Boulevard Saint-Martin', '#ffab60', 'pin', 1, 3.9, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/hero.jpg', NULL, 3.8, 0, '€', 3.8, 6, 4.5, 0, 0, 50, '{"chill":15,"festif":22,"culturel":5}', '{}', '["bar","bar de quartier","afterwork","terrasse"]', '{"standard":"Lundi-Dimanche: 15h00 - 02h00","display":"Lundi-Dimanche: 15h00 - 02h00","detailed":"Lundi-Dimanche: 15h00 - 02h00"}', '{"reservation_policy":"sans_resa","accessibility":false,"wifi_gratuit":true,"terrace":true,"opening_hours_raw":"Lundi-Dimanche: 15h00 - 02h00","action_type":"site","action_url":"https://timetobar.com/sites/l-attirail-caf-","terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":8,"is_free":false,"pint_price":3.8,"cocktail_price":6,"wine_glass":4.5,"coffee_price":0,"dish_price":0,"last_updated":"2026-02-28","menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-attirail-cafe/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Bar de quartier. L’Attirail Café.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Planqué juste à côté de la Porte Saint-Martin, L’Attirail est le genre de bar où le temps s’arrête et la pinte coûte moins cher qu’un café ailleurs. Anciennement l’Absinthe Café, le lieu a gardé son âme de rade populaire avec une terrasse chauffée ouverte dès 15h et des prix plancher qui attirent une clientèle jeune et étudiante. L’ambiance est bruyante, chaleureuse, souvent bondée — on y va pour la convivialité et les prix, pas pour le calme. Certains soirs, le lieu accueille des concerts de jazz live.', 'Les potatoes aux herbes sont offertes gratuitement avec ta consommation — c’est le vrai game-changer du lieu, mentionné par quasiment tous les habitués. Les bières sont à 3,80€ la pinte fixe, pas de Happy Hour (malgré ce qu’affiche TimeToBar, les avis récents confirment qu’il n’est pas appliqué). Demande la croziflette si elle est au menu du jour, un régulier Google 5 étoiles n’en revient toujours pas.', 'Strasbourg - Saint-Denis', '[4,8,9]', '[]', 'TODO', NULL, 1);
INSERT INTO places_fts VALUES ('poi-307', 'L’Attirail Café', 'bar', 'bar de quartier afterwork terrasse', '8 Boulevard Saint-Martin', '', 'Planqué juste à côté de la Porte Saint-Martin, L’Attirail est le genre de bar où le temps s’arrête et la pinte coûte moins cher qu’un café ailleurs. Anciennement l’Absinthe Café, le lieu a gardé son âme de rade populaire avec une terrasse chauffée ouverte dès 15h et des prix plancher qui attirent une clientèle jeune et étudiante. L’ambiance est bruyante, chaleureuse, souvent bondée — on y va pour la convivialité et les prix, pas pour le calme. Certains soirs, le lieu accueille des concerts de jazz live.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-chez-maman', 'Chez Maman', 'chez-maman', 'restaurant', 'bistrot, authentique', 'chill', 48.860123, 2.371258, 11, '24 Rue de la Folie-Méricourt, 75011 Paris', '#8ccaf7', 'pin', 0, 4.3, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/hero.jpg', NULL, 12, 0, '€', NULL, NULL, NULL, NULL, 12, 50, '{"chill":90,"festif":30,"culturel":20}', '{}', '["restaurant","bistrot","authentique","terrasse"]', '{"standard":"lundi-samedi: 12:00–14:30, 19:30–22:30","display":"lundi-samedi: 12:00–14:30, 19:30–22:30","detailed":"lundi-samedi: 12:00–14:30, 19:30–22:30"}', '{"opening_hours_raw":"lundi-samedi: 12:00–14:30, 19:30–22:30","reservation_policy":"sans_resa","terrace":true,"ferme_tard":false,"accessibility":true,"main_action":{"type":"site","url":"https://www.chezmaman.paris/","label":"VOIR LE SITE"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":30,"is_free":false,"dish_price":12,"menu_items":[{"category_type":"main","display_label":"Cuisine de Maman","items":[{"name":"Plat mijoté du jour","price_cents":1600},{"name":"Dessert maison","price_cents":800}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-maman/gallery_4.jpg"]', NULL, '{"text":"Une expérience gourmande conviviale, authentique et d''une grande générosité culinaire.","must_eat":"Cuisine de Tradition. Plats Mijotés & Desserts Maison.","le_secret":"L''équipe prépare chaque matin des bouillons et des sauces maison, signature d''un savoir-faire artisanal qui donne tout son relief à cette cuisine du cœur.","le_son":"Brouhaha joyeux et convivial.","le_must":"Les portions généreuses."}', 'Chez Maman est une adresse d''une grande sincérité et d''une générosité absolue située rue de la Folie-Méricourt. Fidèle à son nom, l''établissement propose une cuisine familiale honnête, mettant à l''honneur les recettes de tradition avec talent et simplicité. Dans un cadre convivial, boisé et d''une belle énergie, on y déguste des plats aux saveurs justes qui rappellent les repas de l''enfance. Une adresse de quartier d''une grande fiabilité pour un moment savoureux et sans chichis.', 'Une adresse parfaite pour un déjeuner réconfortant ou un dîner entre amis. L''ambiance y est toujours joyeuse, décontractée et d''une grande simplicité. Très bon rapport qualité-prix pour le quartier. Leur plat mijoté est une référence de gourmandise. L''accueil y est d''une grande sincérité, comme à la maison.', 'Saint-Ambroise', '[9]', '[]', 'ChIJZ3U2S0hx5kcR0Q2nQ0qH2Q', NULL, 1);
INSERT INTO places_fts VALUES ('poi-chez-maman', 'Chez Maman', 'restaurant', 'bistrot authentique terrasse', '24 Rue de la Folie-Méricourt, 75011 Paris', '', 'Chez Maman est une adresse d''une grande sincérité et d''une générosité absolue située rue de la Folie-Méricourt. Fidèle à son nom, l''établissement propose une cuisine familiale honnête, mettant à l''honneur les recettes de tradition avec talent et simplicité. Dans un cadre convivial, boisé et d''une belle énergie, on y déguste des plats aux saveurs justes qui rappellent les repas de l''enfance. Une adresse de quartier d''une grande fiabilité pour un moment savoureux et sans chichis.');
