.co/storage/v1/object/public/place-media/goguette/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/goguette/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Faites confiance à l’inspiration du jour : Gianmarco Gorni a une maîtrise folle des assaisonnements et des jus corsés.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Derrière sa discrète devanture de la rue Amelot, Goguette (mené par le chef Gianmarco Gorni, vu dans Top Chef) envoie une bistronomie délurée et percutante. Le soir, on y partage des assiettes canailles et créatives (souvent très riches en umami) au comptoir ou sur les tables hautes, en éclusant des quilles de vin nature.', '• Merveilleuse cave à vins natures, n’hésitez pas à demander conseil à l’équipe, experte en ’jus vivants’.
INSERT INTO places_fts VALUES ('poi-goguette', 'Goguette', 'restaurant', 'français', '108 Rue Amelot', '', 'Derrière sa discrète devanture de la rue Amelot, Goguette (mené par le chef Gianmarco Gorni, vu dans Top Chef) envoie une bistronomie délurée et percutante. Le soir, on y partage des assiettes canailles et créatives (souvent très riches en umami) au comptoir ou sur les tables hautes, en éclusant des quilles de vin nature.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-korus', 'Korus', 'korus', 'restaurant', 'français', 'chill', 48.857879, 2.366843, 11, '73 Rue Amelot', '#8ccaf7', 'pin', 1, 4.7, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/hero.jpg', NULL, 34, 0, '€', NULL, NULL, 10, 3.5, 34, 50, '{"chill":70,"festif":20,"culturel":20}', '{}', '["restaurant","français"]', '{"standard":"Monday: Closed\nTuesday: Closed\nWednesday: 7:30–11:00 PM\nThursday: 7:00–11:00 PM\nFriday: 7:00–11:00 PM\nSaturday: 12:00–2:30 PM, 7:00–11:00 PM\nSunday: 12:00–2:30 PM, 7:00–11:00 PM","display":"Monday: Closed","detailed":"Monday: Closed\nTuesday: Closed\nWednesday: 7:30–11:00 PM\nThursday: 7:00–11:00 PM\nFriday: 7:00–11:00 PM\nSaturday: 12:00–2:30 PM, 7:00–11:00 PM\nSunday: 12:00–2:30 PM, 7:00–11:00 PM"}', '{"opening_hours_raw":"Monday: Closed\nTuesday: Closed\nWednesday: 7:30–11:00 PM\nThursday: 7:00–11:00 PM\nFriday: 7:00–11:00 PM\nSaturday: 12:00–2:30 PM, 7:00–11:00 PM\nSunday: 12:00–2:30 PM, 7:00–11:00 PM","reservation_policy":"resa_conseillee","terrace":false,"accessibility":false,"main_action":{"type":"site","url":"https://restaurantkorus.com/","label":"RÉSERVER"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":65,"is_free":false,"pint_price":0,"wine_glass":10,"coffee_price":3.5,"dish_price":34,"menu_type":"fixed","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category_type":"tasting_menu","display_label":"Menus Dégustation","items":[{"name":"Menu TEMPO (Déjeuner)","price_cents":4500,"description":"Menu découverte en 4 temps servi le midi."},{"name":"Menu OPUS (Dîner)","price_cents":7900,"description":"Menu dégustation en 6 temps, l’expérience signature."},{"name":"Menu CHORUS (Dîner)","price_cents":9700,"description":"Le grand voyage en 8 temps pour l’ensemble de la table."},{"name":"Accord Mets & Vins (Tempo)","price_cents":3000,"description":"3 verres en accord avec le menu déjeuner."},{"name":"Accord Mets & Vins (Opus/Chorus)","price_cents":5500,"description":"Sélection pointue du sommelier pour le dîner."}]},{"category_type":"other","display_label":"Exemples de Créations du Chef (Selon arrivage)","items":[{"name":"Tartare de Haddock","price_cents":1800,"description":"Radis croquants, herbes fraîches, émulsion légère"},{"name":"Thon Cru mariné","price_cents":2100,"description":"Condiments de saison, huile de sésame torréfié"},{"name":"Crabe effiloché","price_cents":2200,"description":"Gelée de pomme verte, céleri branche"},{"name":"Coeur de Canard snacké","price_cents":2500,"description":"Jus réduit corsé, purée soyeuse"},{"name":"Raie au beurre noisette","price_cents":3200,"description":"Câpres, citron confit, tombée d’épinards"},{"name":"Paleron de Boeuf","price_cents":3600,"description":"Cuisson basse température, sauce cacao, légumes racines"},{"name":"Bavette Angus","price_cents":3400,"description":"Échalotes confites, pommes grenailles rôties"}]},{"category_type":"dessert","display_label":"Desserts & Fromages","items":[{"name":"Assiette de fromages affinés","price_cents":1200,"description":"Sélection du fromager, chutney maison"},{"name":"Déclinaison autour de la poire","price_cents":1400,"description":"Poire rôtie, glace vanille, tuile croustillante"},{"name":"Chocolat grand cru","price_cents":1500,"description":"Crémeux chocolat, praliné noisette, glace au grué"}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/korus/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. L’audacieux paleron de bœuf relevé par une étonnante sauce au cacao, signature de la maison.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Recommandé par le Guide Michelin, Korus est l’incarnation parfaite du néo-bistrot du 11ème arrondissement. Dans une salle intimiste aux murs grattés et au mobilier vintage, on y déguste une cuisine d''auteur vive et moderne, articulée autour de trois menus dégustation (Tempo, Opus, Chorus). Le sourcing des produits est irréprochable et la cave fait la part belle aux vins naturels de vignerons pointus.', '• Excellent spot pour un dîner romantique ou entre amateurs de grande gastronomie décontractée.
INSERT INTO places_fts VALUES ('poi-korus', 'Korus', 'restaurant', 'français', '73 Rue Amelot', '', 'Recommandé par le Guide Michelin, Korus est l’incarnation parfaite du néo-bistrot du 11ème arrondissement. Dans une salle intimiste aux murs grattés et au mobilier vintage, on y déguste une cuisine d''auteur vive et moderne, articulée autour de trois menus dégustation (Tempo, Opus, Chorus). Le sourcing des produits est irréprochable et la cave fait la part belle aux vins naturels de vignerons pointus.');
