INSERT INTO places_fts VALUES ('poi-east-mamma', 'East Mamma', 'restaurant', 'italien', '133 Rue du Faubourg Saint-Antoine, 75011 Paris', '', 'L’établissement qui a lancé la révolution Big Mamma à Paris. East Mamma est une trattoria vibrante où l’on parle fort, on mange bien et on boit du bon vin italien. Tout est sourcé directement auprès des petits producteurs de la botte. Entre le four à bois rutilant et les banquettes conviviales, l’ambiance est électrique et généreuse.');
