ice_cents":1500},{"name":"Ceviche de Truite, vinaigrette mangue","price_cents":1500},{"name":"Pavé de Colin en papillote","price_cents":1500},{"name":"Assiette Végétarienne de saison","price_cents":1350}]},{"category_type":"other","display_label":"Carte du Soir (Bistro Classics)","items":[{"name":"Steak Frites, sauce au poivre","price_cents":1900},{"name":"Tartare de Bœuf préparé","price_cents":1800},{"name":"Pavé de Saumon à l’unilatérale","price_cents":2000},{"name":"Salade César au poulet croustillant","price_cents":1650}]},{"category_type":"starter","display_label":"Entrées & Desserts","items":[{"name":"Œuf dur Mayonnaise","price_cents":580},{"name":"Rillettes de canard maison","price_cents":800},{"name":"Mousse au Chocolat noir","price_cents":750},{"name":"Crème Brûlée vanille","price_cents":800},{"name":"Tarte Tatin & glace vanille","price_cents":850}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-pure-cafe/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Bistro-traditionnel. Le Pure Café.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Véritable décor de cinéma (immortalisé dans ’Before Sunset’), Le Pure Café est l’archétype du beau bistrot d’angle parisien. Avec son bar circulaire en bois, ses boiseries patinées et ses larges miroirs, il dégage une atmosphère intemporelle et chaleureuse. C’est l''endroit idéal pour un café matinal avec un livre, un déjeuner de quartier efficace ou un verre entre amis dans une ambiance feutrée et authentique.', 'La table dans l’angle vitré est la plus prisée pour observer la vie de la rue Jean Macé. C''est exactement là que se déroule la scène culte du film.', 'Charonne', '[9]', '[]', 'ChIJN-v--jM--jM--jM--jM--jM--jM', NULL, 1);
INSERT INTO places_fts VALUES ('poi-067', 'Le Pure Café', 'restaurant', 'bistro-traditionnel cinema terrasse brunch terrasse', '14 Rue Jean Macé', '', 'Véritable décor de cinéma (immortalisé dans ’Before Sunset’), Le Pure Café est l’archétype du beau bistrot d’angle parisien. Avec son bar circulaire en bois, ses boiseries patinées et ses larges miroirs, il dégage une atmosphère intemporelle et chaleureuse. C’est l''endroit idéal pour un café matinal avec un livre, un déjeuner de quartier efficace ou un verre entre amis dans une ambiance feutrée et authentique.');
