INSERT INTO places_fts VALUES ('poi-septime-la-cave', 'Septime La Cave', 'restaurant', 'français', '3 Rue Basfroi, 75011 Paris', '', 'L’antichambre du célébrissime Septime. Ici, on ne réserve pas, on vient pour l’atmosphère vibrante, les vins natures dénichés aux quatre coins de l’Europe et des grignotages de haute volée. Dans un espace exigu et chaleureux, on déguste des produits sourcés avec une précision chirurgicale (charcuteries ibériques, fromages affinés, petites assiettes créatives). C’est l’essence même de l''apéro parisien moderne.');
