,{"name":"Double Espresso","price_cents":600},{"name":"Décaféiné à l’eau","price_cents":450}]},{"category_type":"drink","display_label":"Eaux & Softs (Boissons)","items":[{"name":"Eau micro-filtrée Septime (75cl)","price_cents":450},{"name":"Jus de fruits frais (Sourcing direct)","price_cents":800},{"name":"Kombucha Maison ’Verveine''","price_cents":900,"is_highlight":true},{"name":"Limonade Artisanale","price_cents":700},{"name":"Badoit (75cl)","price_cents":650}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/septime/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie. Il n’y a pas de carte mais une suite d’assiettes improvisées chaque matin selon l’arrivage de micro-producteurs d’Île-de-France.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'La pierre angulaire de la gastronomie moderne parisienne. Couronné d’une étoile Michelin et constamment classé parmi les meilleurs restaurants du monde (World’s 50 Best), le chef Bertrand Grébaut y sert une cuisine d’une justesse fulgurante, épurée à l’extrême (souvent trois ingrédients par assiette), axée sur le végétal et le sourcing d’exception.', '• Obtenir une table est l’un des plus grands défis de Paris. Les réservations ouvrent exactement 3 semaines à l’avance à 10h00 pétantes : soyez prêt à rafraîchir la page.
INSERT INTO places_fts VALUES ('poi-septime', 'Septime', 'restaurant', 'gastronomique terrasse', '80 Rue de Charonne', '', 'La pierre angulaire de la gastronomie moderne parisienne. Couronné d’une étoile Michelin et constamment classé parmi les meilleurs restaurants du monde (World’s 50 Best), le chef Bertrand Grébaut y sert une cuisine d’une justesse fulgurante, épurée à l’extrême (souvent trois ingrédients par assiette), axée sur le végétal et le sourcing d’exception.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-vaisseau', 'Vaisseau', 'vaisseau', 'restaurant', 'gastronomique', 'culturel', 48.8531565, 2.3826492, 11, '35 Rue Faidherbe', '#c499ff', 'pin', 1, 4.6, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/hero.jpg', NULL, 60, 0, '€', NULL, NULL, 15, 5, 60, 50, '{"chill":40,"festif":30,"culturel":95}', '{}', '["restaurant","gastronomique"]', '{"standard":"Lun-Ven: 12:00–14:00, 19:30–22:00; Fermé Sam-Dim","display":"Lun-Ven: 12:00–14:00, 19:30–22:00; Fermé Sam-Dim","detailed":"Lun-Ven: 12:00–14:00, 19:30–22:00; Fermé Sam-Dim"}', '{"opening_hours_raw":"Lun-Ven: 12:00–14:00, 19:30–22:00; Fermé Sam-Dim","reservation_policy":"resa_obligatoire","terrace":false,"accessibility":true,"main_action":{"type":"site","url":"https://www.restaurant-vaisseau.com","label":"RÉSERVER"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":120,"is_free":false,"pint_price":0,"wine_glass":15,"coffee_price":5,"dish_price":60,"menu_type":"fixed","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category_type":"tasting_menu","display_label":"Menus Dégustation (Carte Blanche)","items":[{"name":"Le ’Menu Quoi'' (Déjeuner)","price_cents":6000,"description":"Menu surprise en plusieurs étapes."},{"name":"Le ’Menu N’importe quoi’ (Dîner)","price_cents":12000,"description":"L’expérience complète Adrien Cachot."},{"name":"Le ’Menu Grand n’importe quoi’","price_cents":18000,"description":"Immersion totale sans limites."}]},{"category_type":"drink","display_label":"Accords Mets & Boissons","items":[{"name":"Accord Boissons (Déjeuner)","price_cents":4000},{"name":"Accord Boissons (Dîner)","price_cents":8000},{"name":"Accord ’Grand n’importe quoi’","price_cents":10000}]},{"category_type":"other","display_label":"Inspirations (Séquences Adrien Cachot)","items":[{"name":"Mochi Cacio e Pepe","price_cents":0,"description":"Réinterprétation culte mêlant textures japonaises et saveurs romaines."},{"name":"Gaspach-eau de tomates & piment","price_cents":0},{"name":"Cervelle de veau Karaage & gribiche","price_cents":0},{"name":"Os à moelle & anchois de la Maison Dehesa","price_cents":0},{"name":"Bulots au persil plat & ail noir","price_cents":0},{"name":"Lentilles beluga & Caviar Osciètre","price_cents":0},{"name":"Ris de veau à la réglisse & purée de blettes","price_cents":0},{"name":"Anguille fumée & betterave laquée","price_cents":0},{"name":"Coeur de pigeon, sang et hibiscus","price_cents":0},{"name":"Mont-Blanc aux champignons de Paris","price_cents":0},{"name":"Dessert à la levure de boulanger & miel","price_cents":0},{"name":"Eau micro-filtrée","price_cents":0},{"name":"Mignardises insolentes","price_cents":0}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vaisseau/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie. Le Mochi Cacio e Pepe, si présent sur le menu ce jour-là.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Vaisseau est le projet tant attendu d’Adrien Cachot, finaliste prodige de Top Chef. Dans un décor minimaliste quasi-monacal du 11ème, le chef livre une partition libre, sans barrières, où les produits mal aimés (abats, algues) côtoient la noblesse du geste. Élu meilleur restaurant de Paris 2025 par Time Out, Vaisseau est plus qu’un restaurant : c’est une expérience sensorielle, intellectuelle et gustative unique au monde.', 'Les réservations s’envolent en quelques secondes lors de l’ouverture des créneaux (généralement le 1er du mois à midi). Soyez plus rapide qu’un bot. Le menu ’N’importe quoi'' est celui qui permet de saisir tout le génie de Cachot.', 'Charonne', '[9]', '[]', 'ChIJA73L0W9z5kcRqULmP_W05uw', NULL, 0);
INSERT INTO places_fts VALUES ('poi-vaisseau', 'Vaisseau', 'restaurant', 'gastronomique', '35 Rue Faidherbe', '', 'Vaisseau est le projet tant attendu d’Adrien Cachot, finaliste prodige de Top Chef. Dans un décor minimaliste quasi-monacal du 11ème, le chef livre une partition libre, sans barrières, où les produits mal aimés (abats, algues) côtoient la noblesse du geste. Élu meilleur restaurant de Paris 2025 par Time Out, Vaisseau est plus qu’un restaurant : c’est une expérience sensorielle, intellectuelle et gustative unique au monde.');
