":null}', '{"avg_budget":45,"is_free":false,"pint_price":0,"wine_glass":9,"coffee_price":3.5,"dish_price":24.5,"last_updated":"2026-03-06","menu_items":[{"category_type":"other","display_label":"Antipasti","items":[{"name":"Burrata des Pouilles, haricots verts, amandes","price_cents":1500},{"name":"Tarte à la tomate, ricotta salata, fleurs de courgette","price_cents":1600},{"name":"Vitello tonnato classique","price_cents":1800},{"name":"Jambon de Parme affiné 24 mois","price_cents":1450},{"name":"Focaccia maison à l’origan et sel noir","price_cents":600},{"name":"Carpaccio de thon rouge, câpres et citron","price_cents":1900}]},{"category_type":"main","display_label":"Primi & Secondi (Plats)","items":[{"name":"Mezzi paccheri aux langoustines crues","price_cents":2400},{"name":"Ris d’agneau, fenouil rôti, jus citron/thym","price_cents":2400},{"name":"Calamarata ragoût de saucisse au vin rouge","price_cents":2200},{"name":"Pêche du jour, légumes croquants","price_cents":2800},{"name":"Raviolis del plin à la piémontaise","price_cents":2600},{"name":"Linguine alle vongole","price_cents":2500},{"name":"Tagliatelle au ragoût de canard et cacao","price_cents":2400},{"name":"Caille rôtie farcie à la pancetta","price_cents":2700}]},{"category_type":"other","display_label":"Dolci","items":[{"name":"Tiramisu de la maison","price_cents":1000},{"name":"Cannolo sicilien, ricotta et granité pastèque","price_cents":1000},{"name":"Soupe de pêches plates, glace verveine","price_cents":1000},{"name":"Panna cotta au coulis de fruits de saison","price_cents":950}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/osteria-ferrara/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne. La précision est la de mise. Les pâtes sont al dente et baignent dans des justes parfaits, à l’image des Mezzi paccheri aux langoustines crues. Du brutal chic.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Derrière sa devanture boisée, l’Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.', '• Une institution discrète parfaite pour un très bon date avec l’Italie dans l’assiette.
INSERT INTO places_fts VALUES ('poi-osteria-ferrara', 'Osteria Ferrara', 'restaurant', 'italien', '7 Rue du Dahomey', '', 'Derrière sa devanture boisée, l’Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.');
