":0,"wine_glass":9,"coffee_price":0,"dish_price":35,"last_updated":"2026-03-07","menu_items":[{"category_type":"tasting_menu","display_label":"Formules & Menus","items":[{"name":"Menu Déjeuner (semaine)","price_cents":3000},{"name":"Brunch du Dimanche","price_cents":5400,"description":"Le fameux poulet rôti frites du dimanche."}]},{"category_type":"starter","display_label":"Spécialités de la maison (Entrées)","items":[{"name":"Pâté en croûte de Rodolphe Paquin","price_cents":1800,"description":"La légende de la maison."},{"name":"Terrine de boudin noir","price_cents":1600},{"name":"Terrine de lièvre (Saison)","price_cents":1700},{"name":"Pâté de campagne maison","price_cents":1200},{"name":"Salade d’oreilles de cochon","price_cents":1500},{"name":"Huîtres N°3 (les 6)","price_cents":1800}]},{"category_type":"main","display_label":"Gibiers & Viandes (Plats)","items":[{"name":"Lièvre à la Royale (en saison)","price_cents":4500},{"name":"Côte de veau de Normandie au cidre","price_cents":3500},{"name":"Parmentier de sanglier","price_cents":2800},{"name":"Gigot d’agneau rôti à l''ail en chemise","price_cents":3200},{"name":"Sole meunière poêlée au beurre","price_cents":4200}]},{"category_type":"dessert","display_label":"Fromages & Desserts","items":[{"name":"Assiette de fromages affinés","price_cents":1200},{"name":"Clafoutis aux pommes","price_cents":1000},{"name":"Mousse au chocolat noir et gingembre","price_cents":1100},{"name":"Tarte Tatin maison","price_cents":1100},{"name":"Eau micro-filtrée (75cl)","price_cents":450}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/repaire-cartouche/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. La trilogie hivernale absolue : terrine en entrée, lièvre à la royale au milieu, et plateau de fromages pour terminer.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Une institution viandarde et giboyeuse incontournable tenue par Rodolphe Paquin. Le Repaire de Cartouche est le temple du pâté en croûte à Paris et le QG des amateurs de classicisme français ultra-généreux. Un décor de bistrot de toujours, des terrines monumentales, et des sauces au vin rouge qui collent aux lèvres.', '• Ne venez pas ici si vous n’aimez pas la viande : c’est le paradis du gibier (lièvre à la royale, grouse, biche en saison d’hiver).
INSERT INTO places_fts VALUES ('poi-repaire-cartouche', 'Le Repaire de Cartouche', 'restaurant', 'français', '8 Boulevard des Filles du Calvaire', '', 'Une institution viandarde et giboyeuse incontournable tenue par Rodolphe Paquin. Le Repaire de Cartouche est le temple du pâté en croûte à Paris et le QG des amateurs de classicisme français ultra-généreux. Un décor de bistrot de toujours, des terrines monumentales, et des sauces au vin rouge qui collent aux lèvres.');
