ite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/acolyte-insolite/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Laissez-vous tenter par le grand écart : un Tartare de Bœuf parfaitement assaisonné suivi par des Takoyaki japonais !","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Une adresse curieuse et discrète (quasi introuvable sans la cercher) frôlant l’insaisissable, avec un rating stupéfiant de 4.8. La cuisine s’amuse d’une hybridité totale : des grands classiques bistrot de viandes croisant par surprise des Takoyaki ou des Udons japonais.', '• Les tarifs sont incroyablement doux pour le quartier (13€ la belle salade IGP, 9€ le sandwich ultra soigné).
INSERT INTO places_fts VALUES ('poi-acolyte-insolite', 'L’Acolyte de l’Insolite', 'restaurant', 'japonais', '49 Rue de la Folie Méricourt', '', 'Une adresse curieuse et discrète (quasi introuvable sans la cercher) frôlant l’insaisissable, avec un rating stupéfiant de 4.8. La cuisine s’amuse d’une hybridité totale : des grands classiques bistrot de viandes croisant par surprise des Takoyaki ou des Udons japonais.');
