ngembre","price_cents":1450},{"name":"Arancini au safran (x3)","price_cents":1200},{"name":"Focaccia maison, sel de Maldon","price_cents":550}]},{"category_type":"main","display_label":"Pizzas au Feu de Bois","items":[{"name":"Margherita (Tomate, Mozza, Basilic)","price_cents":1300},{"name":"Bambinita (Burrata, N’duja, Miel)","price_cents":1900},{"name":"Diavola (Salami piquant)","price_cents":1650},{"name":"Verdura (Légumes de saison)","price_cents":1550}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Tiramisu Signature","price_cents":900},{"name":"Mousse Chocolat & Huile d’Olive","price_cents":850}]},{"category_type":"drink","display_label":"Vins & Cocktails","items":[{"name":"Negroni","price_cents":1200},{"name":"Vin Naturel (Verre)","price_cents":750},{"name":"Bière Artisanale (Pinte)","price_cents":800}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bambino/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne. La pizza Bambinita avec sa burrata crémeuse.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Inspiré par les bars à vin de Tel Aviv et les jazz kissa japonais, Bambino est un lieu hybride unique. Entre mur de vinyles, système son audiophile et cuisine ouverte au feu de bois, l’ambiance y est électrique. On y déguste des pizzas d''une finesse folle et des petites assiettes aux influences levantines dans un nuage de funk et de jazz.', 'Ne manquez pas le brunch du dimanche, plus calme mais tout aussi savoureux. Pour le soir, arrivez à l’ouverture (19h) car l''endroit ne prend pas de réservations et se remplit en 15 minutes.', 'Saint-Ambroise', '[9]', '[]', 'ChIJl6yY_Vdt5kcR8O-N6V_X78g', NULL, 0);
INSERT INTO places_fts VALUES ('poi-bambino', 'Bambino', 'restaurant', 'italien', '25 Rue de la Folie Méricourt', '', 'Inspiré par les bars à vin de Tel Aviv et les jazz kissa japonais, Bambino est un lieu hybride unique. Entre mur de vinyles, système son audiophile et cuisine ouverte au feu de bois, l’ambiance y est électrique. On y déguste des pizzas d''une finesse folle et des petites assiettes aux influences levantines dans un nuage de funk et de jazz.');
