_exception":false,"happy_hour":null}', '{"avg_budget":35,"is_free":false,"pint_price":0,"wine_glass":6,"coffee_price":0,"dish_price":21,"last_updated":"2026-03-06","menu_items":[{"category_type":"other","display_label":"Tajines Maison","items":[{"name":"Tajine S’Ixudra (Végétarien)","price_cents":1800,"description":"Petits légumes de saison avec un œuf poché."},{"name":"Tajine S’Uyazid (Poulet, légumes, citron confit)","price_cents":2100},{"name":"Tajine Mtewem (Boulettes, poulet, pois chiches)","price_cents":2150},{"name":"Tajine S’Uxarfi (Agneau, légumes, citron confit)","price_cents":2150},{"name":"Tajine Lham Lahlou (Agneau, pruneaux, amandes)","price_cents":2200},{"name":"Tajine S’Ihut (Poissons sauvages du moment)","price_cents":2200}]},{"category_type":"other","display_label":"Couscous Maison (Seksu)","items":[{"name":"Seksu S’ixudra (Couscous Végétarien)","price_cents":1750},{"name":"Seksu Merguez","price_cents":1950},{"name":"Seksu S’uyazid (Poulet et merguez)","price_cents":2000},{"name":"Seksu S’iberdien n’izimer (Côtelettes d’agneau)","price_cents":2250},{"name":"Seksu Homme Bleu (Couscous Royal : brochette, boulette, côtelette, merguez)","price_cents":2300},{"name":"Seksu Tfaya (Agneau ou Poulet, raisins, miel)","price_cents":2400}]},{"category_type":"dessert","display_label":"Pâtisseries & Desserts","items":[{"name":"Thé à la menthe","price_cents":350},{"name":"Assortiment de pâtisseries marocaines","price_cents":900}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-homme-bleu/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine berbère. Le Couscous Royal rassemble tout ce qu’on aime, et les boulettes de viande sont fondantes à souhait.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'L’institution de la rue Jean-Pierre Timbaud. L''Homme Bleu réalise parmi les meilleurs couscous et tajines de tout Paris dans un décor pur jus oriental chaleureux. Des bouillons ultra-parfumés, des semoules fines comme du sable, des viandes parfaitement cuites. Le spot idéal pour un dîner réconfortant ou un repas dominical.', '• Le Couscous ’Homme Bleu’ (Royal à 23€) est la valeur sûre pour les très grosses faims.
INSERT INTO places_fts VALUES ('poi-l-homme-bleu', 'L’Homme Bleu', 'restaurant', 'marocain', '55 Bis Rue Jean-Pierre Timbaud', '', 'L’institution de la rue Jean-Pierre Timbaud. L''Homme Bleu réalise parmi les meilleurs couscous et tajines de tout Paris dans un décor pur jus oriental chaleureux. Des bouillons ultra-parfumés, des semoules fines comme du sable, des viandes parfaitement cuites. Le spot idéal pour un dîner réconfortant ou un repas dominical.');
