rnable du 11ème — venez tôt (dès 11h) pour avoir une table.
INSERT INTO places_fts VALUES ('poi-onze-a-table', 'Onze à Table', 'restaurant', 'français', '10 Rue de la Folie Méricourt', '', 'Onze à Table est le bistrot fait maison parfait de la Folie Méricourt : une carte généreuse qui va du tartare de bœuf au tataki de thon crispy, en passant par une entrecôte d’Argentine et un foie gras mi-cuit maison. Le dimanche, le brunch copieux à 34€ attire tout le quartier. Le cadre est chaleureux et moderne, avec une carte de vins de vignerons indépendants.');
