_price":26,"last_updated":"2026-03-06","menu_items":[{"category_type":"tasting_menu","display_label":"Formule Déjeuner (Lundi-Vendredi)","items":[{"name":"Entrée + Plat ou Plat + Dessert","price_cents":2800},{"name":"Entrée + Plat + Dessert","price_cents":2950}]},{"category_type":"starter","display_label":"Entrées","items":[{"name":"Terrine de campagne maison","price_cents":1000},{"name":"Huîtres de saison","price_cents":1200},{"name":"Carpaccio de poisson, agrumes","price_cents":1200},{"name":"Gnocchi aux artichauts et ricotta fumée","price_cents":1100},{"name":"Moules au gingembre et coriandre","price_cents":1000},{"name":"Salade de tomates, basilic, ricotta","price_cents":800}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Selle d’agneau farcie aux épinards","price_cents":2800},{"name":"Bar de ligne, légumes du moment","price_cents":2600},{"name":"Boeuf Wellington (en saison)","price_cents":2800},{"name":"Tête de porc grillée","price_cents":2400,"description":"Un classique audacieux du chef."},{"name":"Pigeon en pâté-croûte, foie gras","price_cents":2800},{"name":"Dorade, pommes de terre, fenouil grillé, salicorne","price_cents":2600},{"name":"Tagliatelles aux courgettes, basilic, tomates","price_cents":2400}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Brownie au chocolat","price_cents":800},{"name":"Sablé pistache, cerises, glace pistache","price_cents":900},{"name":"Dessert du jour","price_cents":800}]},{"category_type":"drink","display_label":"Cave (3000+ références, gérée par Marco Pelletier)","items":[{"name":"Verre de vin nature / bio","price_cents":700},{"name":"Bouteille (entrée de cave)","price_cents":2800},{"name":"Grands crus et raretés (jusqu’à)","price_cents":50000,"description":"Une cave légendaire de 3000 à 6000 bouteilles pour les amateurs."}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/vantre/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Les plats changent chaque semaine mais les regulars reviennent pour la selle d’agneau farcie aux épinards (28€), la tête de porc grillée (24€) pour les audacieux, ou le pigeon en pâté-croûte au foie gras (28€). Le midi, la formule E+P+D à 29.50€ est imbattable.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Vantre est le néo-bistrot du chef Marco Pelletier, sommelier de formation devenu cuisinier. Résultat : la cuisine est impeccable (touches japonaises subtiles, produits nobles) et la cave est tout simplement monumentale — entre 3000 et 6000 bouteilles référencées, dont des raretés introuvables. Le cadre est sobre et élégant dans un quartier qui concentre les meilleures tables de Paris.', '• La formule déjeuner à 28-29.50€ est l’un des meilleurs rapports qualité-prix du quartier pour cette catégorie de cuisine.
INSERT INTO places_fts VALUES ('poi-vantre', 'Vantre', 'restaurant', 'japonais', '19 Rue de la Fontaine au Roi', '', 'Vantre est le néo-bistrot du chef Marco Pelletier, sommelier de formation devenu cuisinier. Résultat : la cuisine est impeccable (touches japonaises subtiles, produits nobles) et la cave est tout simplement monumentale — entre 3000 et 6000 bouteilles référencées, dont des raretés introuvables. Le cadre est sobre et élégant dans un quartier qui concentre les meilleures tables de Paris.');
