izza Salsiccia","price_cents":2200,"description":"Saucisse italienne, fenouil, pecorino."},{"name":"Pizza Polpette","price_cents":2300,"description":"Boulettes de viande maison, tomate, parmesan."},{"name":"Pizza Blanche Asparagus","price_cents":2400,"description":"Asperges, agrumes, crème de ricotta."},{"name":"Pizza Carte Blanche (Chef Choice)","price_cents":2600,"description":"L’inspiration du moment de Dan Pearson."}]},{"category_type":"starter","display_label":"Sides & Entrées","items":[{"name":"Side Salad Oobatz","price_cents":800,"description":"Vinaigrette maison, herbes amères."},{"name":"Assiette de légumes rôtis","price_cents":1200}]},{"category_type":"dessert","display_label":"Desserts Signatures","items":[{"name":"Pizzookie (Warm Cookie & Pizza Dough)","price_cents":1000,"description":"Dough hybride, pépites de chocolat, servi chaud."},{"name":"Pana Cotta Saison","price_cents":800},{"name":"Glace Maison (Boule)","price_cents":600}]},{"category_type":"drink","display_label":"Vins Natures & Boissons","items":[{"name":"Verre de Vin Nature sélectionné","price_cents":700},{"name":"Bouteille de Vin (à partir de)","price_cents":3600},{"name":"Draft Beer (33cl)","price_cents":600},{"name":"Soft Artisanal","price_cents":1200,"description":"Limonades et kéfirs premium."}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/oobatz/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne (Pizzeria). Le Pizzookie chaud en fin de repas.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'La pizzeria culte de Dan Pearson, ex-chef du Rigmarole. Ici, la pizza est un art de la fermentation : pâte légère, croustillante et garnitures sourcées à l’extrême. Une expérience brute et vibrante.', 'Ne passez pas à côté du Pizzookie, le dessert signature hybride pizza-cookie servi chaud. Prévoyez de réserver pile 14 jours à l’avance à 10h, les places s''arrachent.', 'Ménilmontant', '[2]', '[]', 'ChIJr9u4KKtt5kcRNwiGaAm9JYw', NULL, 0);
INSERT INTO places_fts VALUES ('poi-oobatz', 'Oobatz', 'restaurant', 'italien', '4bis Av. Jean Aicard', '', 'La pizzeria culte de Dan Pearson, ex-chef du Rigmarole. Ici, la pizza est un art de la fermentation : pâte légère, croustillante et garnitures sourcées à l’extrême. Une expérience brute et vibrante.');
