ull}', '{"avg_budget":30,"is_free":false,"pint_price":0,"wine_glass":7,"coffee_price":0,"dish_price":24,"last_updated":"2026-03-06","menu_items":[{"category_type":"tasting_menu","display_label":"Formules Déjeuner (Semaine)","items":[{"name":"Menu Midi : Plat seul","price_cents":2300},{"name":"Menu Midi : Entrée + Plat ou Plat + Dessert","price_cents":2800}]},{"category_type":"starter","display_label":"Entrées / Petits Plats à Partager","items":[{"name":"Huîtres, pomme Granny Smith et aneth","price_cents":1200},{"name":"Brocoli croustillant, sweet chili","price_cents":800},{"name":"Croquettes de boeuf bourguignon","price_cents":1000},{"name":"Assiette de fromages affinés","price_cents":1200},{"name":"Terrine du moment","price_cents":1000}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Gnocchi, sauce aux champignons","price_cents":1800},{"name":"Poitrine de porc confite","price_cents":2200},{"name":"Bar de ligne poêlé, légumes de saison","price_cents":2400},{"name":"Entrecôte grillée, sauce maison","price_cents":2800},{"name":"Côte de boeuf à partager (pour 2)","price_cents":13000,"description":"La pièce star, à commander en avance."}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Crémeux au chocolat","price_cents":800},{"name":"Riz au lait","price_cents":700},{"name":"Crème brûlée","price_cents":800}]},{"category_type":"drink","display_label":"Vins Natures (250+ références en cave)","items":[{"name":"Verre de vin nature (sélection du jour)","price_cents":700},{"name":"Bouteille nature (à partir de)","price_cents":2500},{"name":"Dégustation dominicale (thématique, le dimanche)","price_cents":3000,"description":"Chaque dimanche, dégustation à thème avec rencontre vigneronne."}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-yard/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Les plats changent tous les jours au gré du marché. Misez sur le menu déjeuner Entrée + Plat à 28€ pour une valeur imbattable. Le soir, les assiettes à partager s’imposent : croquettes de bourguignon (10€), brocoli croustillant (8€) et un bon plat de poisson du jour.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le YARD, c’est avant tout une cave à vin naturel de 250+ références ET un restaurant bistronomique au cœur du 11ème. Le concept est malin : on choisit ses plats à la carte (viande, poisson, légumes grillés), on partage, et on se laisse guider par la sélection naturelle du jour au verre. L''ambiance est chaleureuse, sans chichi, idéale pour un dîner entre amis avec du bon vin en toile de fond.', '• Le menu midi entre 23€ et 28€ est un deal excellent pour cette qualité dans le quartier.
INSERT INTO places_fts VALUES ('poi-le-yard', 'YARD', 'restaurant', 'français', '6 Rue de Mont-Louis', '', 'Le YARD, c’est avant tout une cave à vin naturel de 250+ références ET un restaurant bistronomique au cœur du 11ème. Le concept est malin : on choisit ses plats à la carte (viande, poisson, légumes grillés), on partage, et on se laisse guider par la sélection naturelle du jour au verre. L''ambiance est chaleureuse, sans chichi, idéale pour un dîner entre amis avec du bon vin en toile de fond.');
