INSERT INTO places_fts VALUES ('poi-chez-justine', 'Chez Justine', 'restaurant', 'italien terrasse', '96 Rue Oberkampf', '', 'La pierre angulaire de la rue Oberkampf. À la fois néo-brasserie de quartier avec ses grandes tablées et ses viandes rôties au feu de bois, bar festif en fin de soirée, et surtout, redoutable pizzeria napolitaine à demeure.');
