asting Menus (Soir)","items":[{"name":"Menu Dégustation (6 temps)","price_cents":8000,"description":"L’essentiel de la vision de Ryuya Ono."},{"name":"Menu Dégustation (9 temps)","price_cents":12000,"description":"L’expérience Magma complète."},{"name":"Accords Mets & Vins (9 temps)","price_cents":9000},{"name":"Accords Mets & Sakés (9 temps)","price_cents":7000}]},{"category_type":"other","display_label":"Inspirations (Séquences Ryuya Ono)","items":[{"name":"Abalone & Oreille de cochon","price_cents":0,"description":"Fenouil, chanterelles, sauce thé vert (Signature)."},{"name":"Truite marinée & champignons de Paris","price_cents":0},{"name":"Lieu jaune de ligne au Bincho-tan","price_cents":0},{"name":"Omble chevalier fumé, bouillon dashi","price_cents":0},{"name":"Quasi de veau de lait, réglisse & blettes","price_cents":0},{"name":"Pigeon fermier rôti sur le coffre","price_cents":0},{"name":"Meringue aux tomates cerises & sorbet pêche","price_cents":0},{"name":"Chocolat Tonka, sablé noisette & glace sésame","price_cents":0},{"name":"Mont-Blanc crèmeux au goût de courge","price_cents":0},{"name":"Eau micro-filtrée","price_cents":0},{"name":"Mignardises de fin de repas","price_cents":0}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/magma/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Le menu 9 temps pour saisir toute la palette du chef.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le chef Ryuya Ono livre une partition d’une justesse rare. Magma est un laboratoire où la technique française s''efface devant la pureté japonaise du produit. Une cuisine anti-gaspi, agile et émouvante, servie dans un cadre intimiste.', 'L’ormeau (abalone) à l’oreille de cochon est le plat signature à ne pas manquer si disponible. L’accord saké est particulièrement bien pensé et apporte une dimension supplémentaire aux plats de mer.', 'Oberkampf', '[5,9]', '[]', 'ChIJnx3AVi1v5kcRegkMkjuBFa8', NULL, 0);
INSERT INTO places_fts VALUES ('poi-magma', 'Magma', 'restaurant', 'bistronomie français', '9 Rue Jean-Pierre Timbaud', '', 'Le chef Ryuya Ono livre une partition d’une justesse rare. Magma est un laboratoire où la technique française s''efface devant la pureté japonaise du produit. Une cuisine anti-gaspi, agile et émouvante, servie dans un cadre intimiste.');
