":5000,"description":"Le format signature, succession de brochettes au binchotan."},{"name":"Menu Dégustation (~13 plats, accord omakase)","price_cents":7500,"description":"Le grand menu complet du déjeuner."},{"name":"Menu Brochettes (9 brochettes chef’s choice)","price_cents":4500}]},{"category_type":"other","display_label":"Privatisation / Table d’Hôte (Soirée sur réservation)","items":[{"name":"Menu Privé 12 passages (8-16 couverts minimum)","price_cents":16000,"description":"Menu exhaustif sur mesure avec préférences et restrictions."}]},{"category_type":"other","display_label":"Brochettes Yakitori au Binchotan (à la carte)","items":[{"name":"Yakitori cuisse de poulet, zeste de clémentine","price_cents":700},{"name":"Blanc de volaille, basilic et citron confit","price_cents":700},{"name":"Poitrine de porc yakitori, bambou","price_cents":800},{"name":"Aorte et cœur grillés","price_cents":600},{"name":"Brochette de légumes de saison","price_cents":500},{"name":"Demi-pigeon grillé (en saison)","price_cents":1800}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Spaghetti à la poutargue (fait main)","price_cents":2400,"description":"Les pâtes maison sont la seconde spécialité du chef."},{"name":"Ravioli ricotta, bouillon dashi","price_cents":2200},{"name":"Pâtes fraîches au homard (en saison)","price_cents":3900},{"name":"Bar tartare","price_cents":1800},{"name":"Maquereau grillé au binchotan","price_cents":1600},{"name":"Seiche grillée, yaourt épicé","price_cents":1800},{"name":"Polpette de porc, purée d’épinards","price_cents":1400},{"name":"Beignets de butternut","price_cents":1200},{"name":"Poireaux grillés","price_cents":1000},{"name":"Courgettes rôties au binchotan","price_cents":1000}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Far aux dattes","price_cents":1000},{"name":"Fondant au chocolat, glace à l’orge grillé","price_cents":1200}]},{"category_type":"drink","display_label":"Vins Natures & Boissons","items":[{"name":"Sauvignon de Loire (verre)","price_cents":500},{"name":"Blanc des Côtes-du-Jura (verre)","price_cents":900},{"name":"Gamay de l’Ardèche (verre)","price_cents":700},{"name":"Rouge autrichien nature (verre)","price_cents":900},{"name":"Bouteille nature (à partir de)","price_cents":2800},{"name":"Bouteille premium","price_cents":7000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/rigmarole/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Commandez le Menu Surprise (50€) pour avoir la vision complète du chef : 7 brochettes yakitori cuites au binchotan (poulet, porc, légumes, abats), 2 petits plats, pickles maison et un dessert. Les spaghetti à la poutargue (24€) sont un impératif si vous êtes à la carte.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Rigmarole est la fusion miraculeuse entre le yakitori japonais et la pasta italienne en plein cœur d’Oberkampf. Le chef Robert Compagnon et la sommelière Jessica Yang (couple à la ville) y orchestrent un ballet hypnotisant au-dessus du charbon binchotan. Ancien étoilé Michelin, le restaurant a choisi de rendre son étoile pour se concentrer sur un service plus intime et familial, désormais uniquement au déjeuner du mercredi au vendredi.', '• Obtenir une place ici relève du miracle : les réservations ouvrent exactement 14 jours à l’avance pour ces 3 déjeuners seulement (Mer-Ven).
INSERT INTO places_fts VALUES ('poi-rigmarole', 'The Rigmarole', 'restaurant', 'japonais', '10 Rue du Grand Prieuré', '', 'Le Rigmarole est la fusion miraculeuse entre le yakitori japonais et la pasta italienne en plein cœur d’Oberkampf. Le chef Robert Compagnon et la sommelière Jessica Yang (couple à la ville) y orchestrent un ballet hypnotisant au-dessus du charbon binchotan. Ancien étoilé Michelin, le restaurant a choisi de rendre son étoile pour se concentrer sur un service plus intime et familial, désormais uniquement au déjeuner du mercredi au vendredi.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-soya', 'Soya Cantine Bio', 'soya', 'restaurant', 'bio', 'chill', 48.8687, 2.3695, 11, '20 Rue de la Pierre Levée', '#8ccaf7', 'pin', 1, 4.6, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/hero.jpg', NULL, 19.5, 0, '€', NULL, NULL, 7.5, 3, 19.5, 50, '{"chill":80,"festif":30,"culturel":40}', '{}', '["restaurant","bio","terrasse"]', '{"standard":"Lun-Sam: 12:00–15:00, 19:00–23:00; Dim: 11:30–16:00 (Brunch)","display":"Lun-Sam: 12:00–15:00, 19:00–23:00; Dim: 11:30–16:00 (Brunch)","detailed":"Lun-Sam: 12:00–15:00, 19:00–23:00; Dim: 11:30–16:00 (Brunch)"}', '{"opening_hours_raw":"Lun-Sam: 12:00–15:00, 19:00–23:00; Dim: 11:30–16:00 (Brunch)","reservation_policy":"resa_conseillee","terrace":true,"accessibility":true,"main_action":{"type":"site","url":"https://soya-cantine-bio.fr","label":"SITE WEB"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":30,"is_free":false,"pint_price":0,"wine_glass":7.5,"coffee_price":3,"dish_price":19.5,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category_type":"starter","display_label":"Entrées Véganes","items":[{"name":"Houmous au Dukkah & gomasio","price_cents":900},{"name":"Tartare d’algues fraîches","price_cents":1000},{"name":"Mozza’Cajou (mozzarella de cajou maison)","price_cents":1200},{"name":"Rouleaux de Printemps (x2)","price_cents":900}]},{"category_type":"main","display_label":"Les Plats","items":[{"name":"Grand Mezze de Soya","price_cents":2200,"description":"L’assiette signature : houmous, caviar de légumes, makis, falafels, crudités."},{"name":"Lasagne Végétale au pesto de cajou","price_cents":1900},{"name":"Bi Bim Bap 100% végétal","price_cents":1900},{"name":"Curry Masala au lait de coco","price_cents":1900},{"name":"Maxi Salade complète","price_cents":1800}]},{"category_type":"dessert","display_label":"Douceurs Bio","items":[{"name":"Moelleux chocolat noir & fleur de sel","price_cents":850},{"name":"Crumble aux fruits de saison","price_cents":850},{"name":"Brunch Buffet (Dimanche uniquement)","price_cents":3500}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/soya/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Gastronomie bio. Le Grand Mezze et leur Lasagne maison.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Soya est le pionnier de la cuisine bio et végane dans le 11ème. Installé dans un ancien atelier textile aux beaux volumes indus, ce restaurant prouve que la cuisine végétale peut être gourmande, généreuse et techniquement aboutie. Leur ’Grand Mezze’ est un festival de couleurs et de textures, devenu le chouchou des habitants du quartier en quête d’un repas sain sans compromis sur le plaisir.', 'Leur brunch du dimanche est une institution absolue à Paris : buffet pantagruélique bio et végan. Réservation obligatoire au moins une semaine à l’avance pour espérer avoir une table.', 'Oberkampf', '[5,9]', '[]', 'ChIJW0-v__tt5kcRrW0-v__tt5k', NULL, 1);
INSERT INTO places_fts VALUES ('poi-soya', 'Soya Cantine Bio', 'restaurant', 'bio terrasse', '20 Rue de la Pierre Levée', '', 'Soya est le pionnier de la cuisine bio et végane dans le 11ème. Installé dans un ancien atelier textile aux beaux volumes indus, ce restaurant prouve que la cuisine végétale peut être gourmande, généreuse et techniquement aboutie. Leur ’Grand Mezze’ est un festival de couleurs et de textures, devenu le chouchou des habitants du quartier en quête d’un repas sain sans compromis sur le plaisir.');
