e":3.5,"dish_price":52,"last_updated":"2026-03-06","menu_items":[{"category_type":"tasting_menu","display_label":"Formule Déjeuner","items":[{"name":"Menu Midi","price_cents":3500}]},{"category_type":"starter","display_label":"Entrées","items":[{"name":"Queue de bœuf au foie gras","price_cents":1800},{"name":"Tête de veau, sauce gribiche","price_cents":1600},{"name":"Ris de veau doré","price_cents":1800},{"name":"Saumon fumé maison, focaccia herbes","price_cents":2200},{"name":"Pâté en croûte (Ris de veau, Porc, Foie gras)","price_cents":2500},{"name":"Cervelle d’agneau et petits légumes","price_cents":1800}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Faux-filet de boeuf Blonde d’Aquitaine","price_cents":4200},{"name":"Fricassée de rognons à la truffe","price_cents":5200},{"name":"Épaule d’agneau de Lozère (pour 2)","price_cents":9500,"description":"Pièce de partage — exclue du dish_price."}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Baba au rhum, gingembre et clémentine","price_cents":1500},{"name":"Dessert du jour","price_cents":1500}]},{"category_type":"drink","display_label":"Cave (1000+ références, dominante Bourgogne)","items":[{"name":"Verre de vin (à partir de)","price_cents":1000},{"name":"Bouteille (à partir de)","price_cents":3500},{"name":"Grands Bourgognes (armoire vitrée)","price_cents":12000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-villaret/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. La fricassée de rognons à la truffe (52€) est iconique. Pour un budget plus doux, le faux-filet Blonde d’Aquitaine (42€) est irréprochable. Le menu midi à 35€ est un excellent deal.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Villaret est le bistrot gastronomique d’Olivier Gaslain, niché dans une ruequiète du 11ème. La carte est courte, ultra-saisonnière, et met en avant les produits nobles : rognons truffés, boeuf Blonde d’Aquitaine, agneau de Lozère. Mais le vrai trésor, c’est la cave : plus de 1000 références avec une dominante bourguignonne magistrale, présentées dans une armoire vitrée spectaculaire.', '• La cave de 1000+ références est LE trésor caché — demandez à voir l’armoire vitrée qui contient les Bourgognes rares.
INSERT INTO places_fts VALUES ('poi-le-villaret', 'Le Villaret', 'restaurant', 'français', '13 Rue Ternaux', '', 'Le Villaret est le bistrot gastronomique d’Olivier Gaslain, niché dans une ruequiète du 11ème. La carte est courte, ultra-saisonnière, et met en avant les produits nobles : rognons truffés, boeuf Blonde d’Aquitaine, agneau de Lozère. Mais le vrai trésor, c’est la cave : plus de 1000 références avec une dominante bourguignonne magistrale, présentées dans une armoire vitrée spectaculaire.');
