abel":"Entrées du Terroir (Entrées)","items":[{"name":"Terrine de Campagne Maison","price_cents":1000},{"name":"Poireaux Vinaigrette & Noisettes","price_cents":900,"is_highlight":true},{"name":"Oeuf Mayo à l’ail des ours","price_cents":1000},{"name":"Couteaux à la plancha, beurre persillé","price_cents":1400},{"name":"Foie Gras de Canard mi-cuit","price_cents":2500},{"name":"Hure de Cochon artisanale","price_cents":1000},{"name":"Salade de Museau de Boeuf","price_cents":1200},{"name":"Six Huîtres de pleine mer (N°3)","price_cents":1800}]},{"category_type":"main","display_label":"Plats de Tradition (Plats)","items":[{"name":"Filet de Boeuf au poivre de Sarawak & frites","price_cents":4400,"is_highlight":true},{"name":"Tartare de Boeuf au couteau & frites","price_cents":2800},{"name":"Aile de Raie à la Grenobloise","price_cents":3000,"is_highlight":true},{"name":"Sole Meunière du Guilvinec","price_cents":4800},{"name":"Andouillette AAAAA, sauce moutarde","price_cents":2600},{"name":"Tête de Veau sauce Gribiche","price_cents":2800},{"name":"Hachis Parmentier de canard","price_cents":2400},{"name":"Côte de Boeuf (pour deux), Béarnaise","price_cents":8500}]},{"category_type":"dessert","display_label":"Fromages & Desserts Cultes (Desserts)","items":[{"name":"Paris-Brest Signature (Le meilleur de Paris)","price_cents":1200,"is_highlight":true},{"name":"Soufflé au Grand Marnier","price_cents":1500,"is_highlight":true},{"name":"Soufflé au Chocolat amer","price_cents":1400},{"name":"Ile Flottante aux pralines roses","price_cents":1000},{"name":"Baba au Rhum Ambré","price_cents":1300},{"name":"Plateau de Fromages Jean-Yves Bordier","price_cents":1800}]},{"category_type":"drink","display_label":"Cave & Boissons (Boissons)","items":[{"name":"Verre de Vin Blanc (Sélection)","price_cents":700,"is_highlight":true},{"name":"Verre de Vin Rouge (Ardoise)","price_cents":800},{"name":"Pression Paul Bert (Lager)","price_cents":800},{"name":"Eau Minérale Evian/Badoit (75cl)","price_cents":650},{"name":"Café Espresso (Torréfié)","price_cents":300},{"name":"Infusion Herbes Fraîches","price_cents":500},{"name":"Digestif (Bas Armagnac)","price_cents":1200}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrot-paul-bert/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. Le filet de boeuf au poivre de Sarawak et l’inoxydable Paris-Brest.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Bistrot Paul Bert est l’archétype du bistrot parisien. Entre ses banquettes en cuir, ses miroirs piqués et ses ardoises où s’inscrivent les arrivages du jour, le temps semble s’être arrêté. Ici, on célèbre la grande cuisine de tradition française : viandes sourcées avec soin, sauces onctueuses et desserts généreux. Une institution bruyante, vivante et indispensable où le Paris-Brest et l''entrecôte au poivre règnent en maîtres.', 'Ne faites pas l’impasse sur le dessert. Leur Paris-Brest est une légende urbaine à lui seul. Arrivez à l''heure car la salle se remplit instantanément de fidèles et de gourmets du monde entier.', 'Faidherbe - Chaligny', '[8]', '[]', 'ChIJw7oP6G5z5kcRL6v_I4xR_q8', NULL, 0);
INSERT INTO places_fts VALUES ('poi-bistrot-paul-bert', 'Bistrot Paul Bert', 'restaurant', 'bistrot', '18 Rue Paul Bert', '', 'Le Bistrot Paul Bert est l’archétype du bistrot parisien. Entre ses banquettes en cuir, ses miroirs piqués et ses ardoises où s’inscrivent les arrivages du jour, le temps semble s’être arrêté. Ici, on célèbre la grande cuisine de tradition française : viandes sourcées avec soin, sauces onctueuses et desserts généreux. Une institution bruyante, vivante et indispensable où le Paris-Brest et l''entrecôte au poivre règnent en maîtres.');
