"is_free":false,"wine_glass":6,"coffee_price":2.4,"dish_price":17,"hh_pint":5.8,"hh_cocktail":7,"hh_time":"17h-00h","smart_tip":"HH 17h-00h : pinte 5,80€ et cocktails classiques 7€. Planche mixte gargantuesque à partager.","menu_items":[{"category_type":"main","display_label":"Plats","items":[{"name":"Terrine de campagne maison & pickles","price_cents":700},{"name":"Soupe à l’Oignon traditionnelle gratinée","price_cents":1200},{"name":"Fricassée de grenouilles ail & persil","price_cents":1600},{"name":"Escargots de Bourgogne (6 pcs)","price_cents":800},{"name":"Salade Amelot (légumes grillés & artichaut)","price_cents":1700}]},{"category_type":"main","display_label":"Plats Brasserie","items":[{"name":"Linguine All Arrabiata, Burrata & Parmesan","price_cents":1700},{"name":"Croque Monsieur à la truffe, frites & salade","price_cents":1800},{"name":"Fish & Chips maison, sauce tartare","price_cents":1800},{"name":"Entrecôte grillée (300g), frites maison","price_cents":2900},{"name":"Saucisse d’Auvergne au couteau & Aligot","price_cents":1900},{"name":"Confit de Canard, pommes Sarladaises","price_cents":2100},{"name":"Tartare de Bœuf Salers, frites maison","price_cents":1900},{"name":"L’Américain Cheeseburger Black Angus","price_cents":1700}]},{"category_type":"starter","display_label":"Grandes Salades","items":[{"name":"La César (Poulet croustillant, Parmesan, Œuf mollet)","price_cents":1900},{"name":"L’Italienne (Burrata, Légumes grillés, Pesto)","price_cents":2100},{"name":"L’Auvergnate (Jambon cru, St Nectaire, Noix)","price_cents":1900}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Crème brûlée à la vanille bourbon","price_cents":800},{"name":"Brownie chocolat & noix","price_cents":800},{"name":"Salade d’agrumes à la menthe fraîche","price_cents":800},{"name":"Café gourmand (sélection du jour)","price_cents":1200}]},{"category_type":"other","display_label":"Bières (HH)","items":[{"name":"Pinte blonde (HH)","price_cents":580},{"name":"Pinte blonde","price_cents":840}]},{"category_type":"drink","display_label":"Cocktails","items":[{"name":"Cocktail classique (HH)","price_cents":700},{"name":"Cocktail classique","price_cents":900},{"name":"Cocktail signature","price_cents":1400}]}],"last_updated":"2026-02-28"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-centenaire/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Bistrot. Le Centenaire.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Bistrot de quartier généreux et chaleureux, Le Centenaire est une institution de la rue Amelot à deux pas d’Oberkampf. Avec ses 1000+ avis Google et sa note de 4.3, c’est le genre d’adresse où tout le monde se sent chez soi. La cuisine française maison y est servie sans chichi : entrecôte sauce poivre, fish and chips avec frites maison (avec leur peau), et une planche mixte gargantuesque qui fait le bonheur des tablées d''amis. Le Happy Hour de 17h à minuit en fait un des meilleurs deals du 11e pour les after-work prolongés.', 'La planche mixte est légendaire — les habitués la décrivent comme ’la plus longue qu’ils aient jamais vue’. Le café gourmand à 12€ est un excellent rapport qualité-prix selon les avis récents. Demandez les vins bio sur conseil du staff. Pour les végétariens : la salade César est disponible avec du Halloumi grillé à la place du poulet.', 'Oberkampf', '["5","9"]', '[]', 'ChIJ0VTQYgdu5kcRAOymof359kA', NULL, 1);
INSERT INTO places_fts VALUES ('poi-le-centenaire', 'Le Centenaire', 'restaurant', 'bistrot bar-brasserie cuisine-française happy-hour terrasse', '104 Rue Amelot', '', 'Bistrot de quartier généreux et chaleureux, Le Centenaire est une institution de la rue Amelot à deux pas d’Oberkampf. Avec ses 1000+ avis Google et sa note de 4.3, c’est le genre d’adresse où tout le monde se sent chez soi. La cuisine française maison y est servie sans chichi : entrecôte sauce poivre, fish and chips avec frites maison (avec leur peau), et une planche mixte gargantuesque qui fait le bonheur des tablées d''amis. Le Happy Hour de 17h à minuit en fait un des meilleurs deals du 11e pour les after-work prolongés.');
