ocktail_price":10,"wine_glass":6,"coffee_price":2.5,"dish_price":10,"smart_tip":"Formule déjeuner 100% bio imbattable dès 10€. Coworking gratuit l’après-midi. Ambiance cantine bio le midi et bar à tapas le soir.","menu_items":[{"category_type":"tasting_menu","display_label":"Formules Midi (100% Bio)","items":[{"name":"Entrée + Plat bio","price_cents":1000},{"name":"Plat + Dessert bio","price_cents":1000},{"name":"Formule complète bio (entrée+plat+dessert)","price_cents":1700}]},{"category_type":"main","display_label":"Plats à la carte (Cantine)","items":[{"name":"Bol 1 bio végé du jour","price_cents":1000},{"name":"Bol protéiné bio","price_cents":1100},{"name":"Duo de crudités bio","price_cents":300},{"name":"Plat chaud bio signature","price_cents":1000}]},{"category_type":"drink","display_label":"Boissons Sans Alcool (Bio)","items":[{"name":"Citronnade maison bio","price_cents":400},{"name":"Jus Pomme-Carotte bio","price_cents":400},{"name":"ChariTea Mate","price_cents":450},{"name":"ChariTea Black","price_cents":450},{"name":"Café artisanal bio","price_cents":250}]},{"category_type":"drink","display_label":"Alcools & Cocktails (Bio)","items":[{"name":"Pinte de bière bio (pression)","price_cents":700},{"name":"Breguet Mule (Vodka/Ginger Beer)","price_cents":1000},{"name":"Vodka infusée au basilic","price_cents":900},{"name":"Verre de vin nature bio","price_cents":600},{"name":"Bière bio bouteille","price_cents":600}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Succulent au chocolat","price_cents":300},{"name":"Gâteau végan bio","price_cents":400}]},{"category_type":"other","display_label":"Brunch (Samedi)","items":[{"name":"Formule Bréguet Brunch (Buffet + Œufs)","price_cents":3200}]}],"last_updated":"2026-02-28"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-grand-breguet/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cantine-bio. Le Grand Bréguet.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Grand Bréguet est une ’cantine vivante’ nichée au cœur du 11e, à deux pas de la Place de la Bastille. Véritable tiers-lieu 100% bio, l’espace alterne entre café studieux le matin (coworking gratuit), cantine saine le midi (formules dès 10€) et bar à tapas/vins nature le soir. On y trouve de grandes tables en bois, une terrasse spacieuse, un piano et même un baby-foot. L’engagement est total : 90% des produits sont issus de l’agriculture française et l''intégralité de la carte est biologique, y compris les spiritueux.', 'C’est un établissement en self-service : on prend son plateau à la cantine et on débarrasse sa table (règle d’or du lieu). Pour le coworking, c’est gratuit de 08:30 à 12:00 et de 14:30 à 17:45 en semaine, avec prises et WiFi. Le soir, l''ambiance devient plus festive avec des bières bio et des cocktails signature comme le Breguet Mule.', 'Bréguet-Sabin', '["5"]', '[]', 'ChIJX2Ot2vht5kcRlPPv7W_48LA', NULL, 1);
INSERT INTO places_fts VALUES ('poi-le-grand-breguet', 'Le Grand Bréguet', 'restaurant', 'cantine-bio café bar coworking brunch terrasse', '17 Rue Bréguet', '', 'Le Grand Bréguet est une ’cantine vivante’ nichée au cœur du 11e, à deux pas de la Place de la Bastille. Véritable tiers-lieu 100% bio, l’espace alterne entre café studieux le matin (coworking gratuit), cantine saine le midi (formules dès 10€) et bar à tapas/vins nature le soir. On y trouve de grandes tables en bois, une terrasse spacieuse, un piano et même un baby-foot. L’engagement est total : 90% des produits sont issus de l’agriculture française et l''intégralité de la carte est biologique, y compris les spiritueux.');
