:[{"category_type":"tasting_menu","display_label":"Formules & Menus","items":[{"name":"Menu Déjeuner","price_cents":2700,"description":"La carte blanche du déjeuner (change chaque semaine)"},{"name":"MENU PICOTTE (E+P+D, Soir)","price_cents":4900,"description":"Menu 3 temps le soir."}]},{"category_type":"starter","display_label":"Entrées (Tour de France)","items":[{"name":"Carpaccio de Saint Jacques, chou fleur, vinaigrette capucine","price_cents":1500},{"name":"Œuf Bio Parfait, hollandaise pistache, oca du Pérou","price_cents":1400},{"name":"Endive braisée, jambon blanc maison, béchamel pain d’épice","price_cents":1300},{"name":"Toast de Morbier, beurre sapin, condiment ail noir","price_cents":1400},{"name":"Tartiflette revisitée (disque de pomme de terre, siphon reblochon)","price_cents":1400}]},{"category_type":"main","display_label":"Plats (Tour de France)","items":[{"name":"Longe de Porc Duroc grillée, toffailles, mousseline patate douce","price_cents":2800},{"name":"Pêche du jour rôtie (sauce vin rouge, anguille fumée, épinards)","price_cents":2900},{"name":"Cannelloni de Poireau farci aux lentilles et noix","price_cents":2500,"description":"Plat végétarien."},{"name":"La Bouillabaisse de Picotte (poissons rôtis, rouille, pommes de terre)","price_cents":3300}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Flan Antillais, crème coco et goyave","price_cents":1100},{"name":"Chichi frégi, ganache chocolat noir, espuma banane","price_cents":1200},{"name":"Nonnettes de Reims","price_cents":1100}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/picotte/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Laissez-vous surprendre par leurs revisites de plats ultra-classiques (comme l’œuf parfait ou le toast au Morbier) : c","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Un fantastique Tour de France culinaire à l’esprit bistronomique. Picotte ressuscite les grandes recettes régionales (tartiflette, bouillabaisse, pimentade antillaise, nonnettes) en leur appliquant les codes et le raffinement de la gastronomie moderne. La cheffe Marta Biagianti réussit le pari de faire de la cuisine de terroir un art subtil et contemporain.', '• La carte change très régulièrement (le midi chaque semaine, le soir 4 fois par an) selon les vraies saisons.
INSERT INTO places_fts VALUES ('poi-picotte', 'Picotte', 'restaurant', 'français', '42 Rue de Malte', '', 'Un fantastique Tour de France culinaire à l’esprit bistronomique. Picotte ressuscite les grandes recettes régionales (tartiflette, bouillabaisse, pimentade antillaise, nonnettes) en leur appliquant les codes et le raffinement de la gastronomie moderne. La cheffe Marta Biagianti réussit le pari de faire de la cuisine de terroir un art subtil et contemporain.');
