offee_price":5,"dish_price":75,"force_manual_dish_price":true,"menu_type":"fixed","last_updated":"2026-03-07","menu_items":[{"category_type":"tasting_menu","display_label":"Menu Découverte (Dîner & Week-end)","items":[{"name":"Menu en 5 étapes","price_cents":11000,"description":"Le voyage gastronomique structuré par Nobuyuki Akishige."},{"name":"Menu en 7 étapes","price_cents":14500,"description":"L’expérience complète du chef avec des produits nobles."},{"name":"Accord Mets & Vins (5 verres)","price_cents":4500},{"name":"Accord Mets & Vins (7 verres)","price_cents":6500}]},{"category_type":"tasting_menu","display_label":"Menu Déjeuner (Mercredi au Vendredi)","items":[{"name":"Menu complet","price_cents":7500,"description":"Amuse bouche, entrée, plat au choix, dessert et mignardises."}]},{"category_type":"other","display_label":"Inspirations (Séquences Automne)","items":[{"name":"Saint-Jacques de Dieppe & légumes de saison","price_cents":0},{"name":"Asperges blanches, oseille & amandes fraîches","price_cents":0},{"name":"Maigre de ligne, courgettes & couteaux de plongée","price_cents":0},{"name":"Jardinière de légumes, émulsion barigoule","price_cents":0},{"name":"Tartelette de foie gras au pain d’épice & muscat","price_cents":0},{"name":"Ris de veau croustillant & champignons pied bleu","price_cents":0},{"name":"Selle de chevreuil rôtie (en saison de chasse)","price_cents":0},{"name":"Blanc manger à l’estragon & sorbet huile d''olive","price_cents":0},{"name":"Gelée de thé jasmin, crème chocolat blanc & mangue","price_cents":0}]},{"category_type":"drink","display_label":"Boissons & Extras","items":[{"name":"Eau minérale (75cl)","price_cents":600},{"name":"Café de spécialité","price_cents":500},{"name":"Mignardises de fin de repas","price_cents":0}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/automne/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie. Laissez-vous guider par le Menu en 7 temps (145€). L’assiette star reste son ris de veau croustillant au printemps, ou ses formidables cuissons de gibier racé en hiver.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Couronné d’une étoile Michelin, Automne est l’écrin du chef japonais Nobuyuki Akishige. Il y déploie une gastronomie française d’une technicité redoutable, magnifiée par la délicatesse et la précision de sa culture natale. Le cadre est feutré et sobre, concentrant toute l’attention sur des assiettes bluffantes, sublimées par une cave nature d’exception dirigée par le sommelier Ulysse Hivroz.', '• C’est l’adresse parfaite pour un dîner d’affaires haut de gamme ou un repas romantique où le calme et le service impeccable priment.
INSERT INTO places_fts VALUES ('poi-automne', 'Automne', 'restaurant', 'français japonais', '11 Rue Richard Lenoir', '', 'Couronné d’une étoile Michelin, Automne est l’écrin du chef japonais Nobuyuki Akishige. Il y déploie une gastronomie française d’une technicité redoutable, magnifiée par la délicatesse et la précision de sa culture natale. Le cadre est feutré et sobre, concentrant toute l’attention sur des assiettes bluffantes, sublimées par une cave nature d’exception dirigée par le sommelier Ulysse Hivroz.');
