ay_label":"Plats Traditionnels","items":[{"name":"Andouillette de Bretagne, moutarde à l’ancienne","price_cents":1900},{"name":"Spaghetti bicolores aux coques","price_cents":1700},{"name":"Entrecôte de Normandie (300g), Béarnaise","price_cents":2800},{"name":"Faut-filet au poivre, frites maison","price_cents":2400},{"name":"Poisson du marché selon arrivage","price_cents":2200}]},{"category_type":"dessert","display_label":"Desserts Classiques","items":[{"name":"Mi-cuit au chocolat, crème anglaise","price_cents":800},{"name":"Tarte Tatin maison","price_cents":800},{"name":"Crème brûlée à la vanille bourbon","price_cents":800},{"name":"Assiette de fromages","price_cents":950}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-ami-pierre/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. L’Andouillette de Bretagne ou l","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'L’Ami Pierre est l’exemple même du petit bistrot de quartier que l’on voudrait garder pour soi. Situé dans la calme rue de la Main d’Or, ce lieu respire l’authenticité avec son comptoir en zinc et ses nappes à carreaux. On y vient pour une cuisine française sincère, sans chichi, où les produits (notamment les viandes de Normandie) sont rois. Un accueil d''une gentillesse rare qui fait de chaque repas un moment suspendu.', 'Leurs frites maison sont une pure merveille, n’hésitez pas à demander un supplément. Le midi, la formule à 14€ est imbattable dans le quartier.', 'Ledru-Rollin', '[8]', '[]', '0x47e67208a3bec699:0x4be330db6d7710a3', NULL, 0);
INSERT INTO places_fts VALUES ('poi-l-ami-pierre', 'A l’ami Pierre', 'restaurant', 'bistrot', '5 Rue de la Main d’Or', '', 'L’Ami Pierre est l’exemple même du petit bistrot de quartier que l’on voudrait garder pour soi. Situé dans la calme rue de la Main d’Or, ce lieu respire l’authenticité avec son comptoir en zinc et ses nappes à carreaux. On y vient pour une cuisine française sincère, sans chichi, où les produits (notamment les viandes de Normandie) sont rois. Un accueil d''une gentillesse rare qui fait de chaque repas un moment suspendu.');
