category_type":"other","display_label":"Softs & Mocktails","items":[{"name":"Mocktail Curry & Amande","price_cents":1000},{"name":"Mocktail Cardamome & Café","price_cents":1000},{"name":"Limonade artisanale (citron-gingembre)","price_cents":600},{"name":"Thé Glacé Maison (pêche-verveine)","price_cents":600},{"name":"Cola Baladin (Artisanal)","price_cents":550}]},{"category_type":"other","display_label":"Beers & Natural Wines","items":[{"name":"Pression : Guinness (33cl)","price_cents":800},{"name":"Pression : NEIPA Cloudy Job (33cl)","price_cents":800},{"name":"Can : Fauve Craft Beer (33cl)","price_cents":900},{"name":"Vin Naturel Rouge (Verre)","price_cents":850},{"name":"Vin Naturel Orange (Verre)","price_cents":950},{"name":"Bouteille Vin Naturel (à partir de)","price_cents":3800}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/superfine/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne (Sandwichs). La Puff Pizza Pepperoni, incroyable de légèreté, suivie d’un Superdog bien gratiné.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Nouveau bastion de la nuit roquette, Superfine a investi l’ancien Motel pour créer un ’dive bar’ ultra-léché. Ici, le street food se veut ’sexy’ (pizze soufflées, superdogs) et les cocktails s’aventurent dans des territoires audacieux (dashi, absinthe, sapin). DJ sets, acoustique soignée et ambiance électrique : l’adresse est déjà le nouveau QG de l''Est parisien branché.', '• Ne passez pas à côté de la ’Puff Pizza’ à la harissa et au miel, une tuerie absolue.
INSERT INTO places_fts VALUES ('poi-superfine', 'Superfine', 'restaurant', 'italien terrasse', '86 Rue de la Roquette', '', 'Nouveau bastion de la nuit roquette, Superfine a investi l’ancien Motel pour créer un ’dive bar’ ultra-léché. Ici, le street food se veut ’sexy’ (pizze soufflées, superdogs) et les cocktails s’aventurent dans des territoires audacieux (dashi, absinthe, sapin). DJ sets, acoustique soignée et ambiance électrique : l’adresse est déjà le nouveau QG de l''Est parisien branché.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-le-tagine', 'Le Tagine', 'le-tagine', 'restaurant', 'marocain', 'chill', 48.863119, 2.366224, 11, '13 Rue Crussol', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/hero.jpg', NULL, 26, 0, '€', NULL, NULL, 8, 3, 26, 50, '{"chill":70,"festif":40,"culturel":60}', '{}', '["restaurant","marocain"]', '{"standard":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","display":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","detailed":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun"}', '{"opening_hours_raw":"Mer-Dim: 12:00–13:30, 19:00–22:30; Mar: 19:00–22:30; Fermé Lun","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"main_action":{"type":"site","url":"http://www.letagine-restaurant.com","label":"RÉSERVER"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":42,"is_free":false,"pint_price":0,"wine_glass":8,"coffee_price":3,"dish_price":26,"menu_type":"standard","force_manual_dish_price":true,"last_updated":"2026-03-08","menu_items":[{"category_type":"starter","display_label":"Entrées Traditionnelles","items":[{"name":"Pastilla au Pigeonneau","price_cents":2600,"description":"Le grand classique sucré-salé, d’une finesse rare."},{"name":"Méchouïa (Salade de tomates et poivrons grillés)","price_cents":1500},{"name":"Merguez grillées & salade marocaine","price_cents":1500},{"name":"Brick à l’œuf de poule de Marans","price_cents":1200}]},{"category_type":"other","display_label":"Les Tagines (Cuisinés en poterie)","items":[{"name":"Tagine d’Agneau aux olives et citrons confits","price_cents":2700},{"name":"Tagine de Poulet fermier aux poires & miel","price_cents":2500},{"name":"Tagine de Saumon aux légumes frais","price_cents":3400},{"name":"Tagine d’Agneau aux raisins secs & amandes","price_cents":2700}]},{"category_type":"other","display_label":"Les Couscous (Graines roulées main)","items":[{"name":"Couscous Méchoui (Gigot d’agneau de lait)","price_cents":3400},{"name":"Couscous Royal (3 viandes : Poulet, Agneau, Merguez)","price_cents":3400},{"name":"Couscous Merguez (x3)","price_cents":2400},{"name":"Couscous Légumes frais","price_cents":2200}]},{"category_type":"dessert","display_label":"Desserts & Thé","items":[{"name":"Pâtisseries marocaines maison (l’assiette)","price_cents":1200},{"name":"Salade d’oranges à la cannelle","price_cents":900},{"name":"Thé à la menthe traditionnel (verre)","price_cents":450}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-tagine/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine marocaine. Le Couscous Méchoui (agneau de lait) et la Pastilla au Pigeonneau.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Tagine est bien plus qu’un restaurant, c’est une institution marocaine à Paris depuis plus de 30 ans. Ici, la gastronomie du Maghreb est traitée avec un respect immense : les graines de couscous sont roulées à la main, les épices sont sourcées avec soin et les cuissons en tagine de terre cuite sont d’une tendreté absolue. Le décor, parsemé de zelliges et de lanternes, invite au voyage dans une atmosphère élégante et chaleureuse.', 'Demandez leur pastilla au pigeonneau en entrée, c’est sans doute l’une des meilleures de la capitale. Et n’oubliez pas de goûter aux vins du Maroc, souvent méconnus mais excellents avec leurs plats épicés.', 'Oberkampf', '[5,9]', '[]', 'ChIJW0-v__tt5kcRrW0-v__tt5k', NULL, 0);
INSERT INTO places_fts VALUES ('poi-le-tagine', 'Le Tagine', 'restaurant', 'marocain', '13 Rue Crussol', '', 'Le Tagine est bien plus qu’un restaurant, c’est une institution marocaine à Paris depuis plus de 30 ans. Ici, la gastronomie du Maghreb est traitée avec un respect immense : les graines de couscous sont roulées à la main, les épices sont sourcées avec soin et les cuissons en tagine de terre cuite sont d’une tendreté absolue. Le décor, parsemé de zelliges et de lanternes, invite au voyage dans une atmosphère élégante et chaleureuse.');
