e_cents":1100}]},{"category_type":"main","display_label":"Platos Fuertes (Plats à partager)","items":[{"name":"Demi-poulet rôti au beurre de piment japone","price_cents":2800},{"name":"Entrecôte (500g) sauce Café de Paris Mexicana","price_cents":5200,"description":"Idéal pour deux."},{"name":"Tacos Cantinero (boeuf braisé lentement)","price_cents":2400},{"name":"Lieu jaune, salsa verde & herbes fraîches","price_cents":2600}]},{"category_type":"dessert","display_label":"Postres (Desserts)","items":[{"name":"Flan au caramel, huile d’olive & romarin frit","price_cents":1000,"description":"Le dessert signature incontournable."},{"name":"Gâteau de maïs, crème de Mezcal","price_cents":950}]},{"category_type":"other","display_label":"Bebidas","items":[{"name":"Margarita Maison","price_cents":1300},{"name":"Verre de Mezcal sélection","price_cents":900},{"name":"Soda UMÀ Green Tea / Lemonade","price_cents":700}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tarantula/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine créative. Les Tacos de champignons sauvages et le Flan huile d’olive/romarin.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c’est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.', 'Leur flan à l’huile d''olive et au romarin frit est devenu culte en quelques mois : ne terminez pas sans lui. Pour les amateurs de sensations fortes, demandez leur sélection de mezcals artisanaux.', 'Voltaire', '[9]', '[]', 'ChIJN4EGozVz5kcRcL9OSHhiPWE', NULL, 0);
INSERT INTO places_fts VALUES ('poi-tarantula', 'Tarántula', 'restaurant', 'fusion', '13 bis Rue Keller', '', 'Tarántula est la nouvelle sensation mexicaine de la rue Keller. Sous la houlette du chef Emmanuel Peña Treviño, cette cantina moderne délaisse les clichés pour proposer une cuisine du nord du Mexique (Norestense) hautement créative. Ambiance tamisée à la bougie, playlist pointue et sélection de vins natures : c’est le lieu parfait pour une soirée vibrante où les saveurs de piments fumés rencontrent des produits de terroir français sourcés avec soin.');
