2026-03-07","menu_items":[{"category_type":"tasting_menu","display_label":"Formules Déjeuner","items":[{"name":"Menu Déjeuner (E+P ou P+D)","price_cents":2300},{"name":"Menu Déjeuner Complet (E+P+D)","price_cents":2900}]},{"category_type":"starter","display_label":"Entrées (Soir)","items":[{"name":"Asperges blanches au barbecue","price_cents":1500},{"name":"Ravioles de Pélardon","price_cents":1400},{"name":"Millefeuille de champignon, mousseline miso","price_cents":1500},{"name":"Maigre, tarama de sardines, ponzu","price_cents":1500}]},{"category_type":"main","display_label":"Plats (Soir)","items":[{"name":"Barbue meunière, sabayon ail des ours","price_cents":3500},{"name":"Carré de veau, gnocchis de patate douce","price_cents":3500},{"name":"Épaule d’agneau braisée, mousseline chou-rave","price_cents":2800},{"name":"Daurade royale, fumet fumé, sabayon herbacé","price_cents":2800},{"name":"Pithiviers, palet butternut, betterave fumée","price_cents":2800,"description":"Végétarien"}]},{"category_type":"dessert","display_label":"Desserts & Fromages","items":[{"name":"Gianduja, pomme crue-gingembre","price_cents":1100},{"name":"Génoise chocolat, glace piment d’Espelette","price_cents":1200},{"name":"Sélection de fromages (Taka & Vermot)","price_cents":1400}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/erso/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Suivez aveuglément leurs propositions sur les poissons nobles (barbue, daurade, maigre) traités avec une main de maître sur les fumets et sabayons.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Élu meilleur bistrot de Paris 2025 par le Lebey. Erso (la ’déferlante’ en basque) a tout emporté sur son passage. En cuisine, le jeune chef Yann Placet dégaine une bistronomie incisive d’une précision diabolique sur les cuissons et les condiments. En salle, Marine Bert orchestre un service tout en velours pour accompagner de pures assiettes de terroir moderne.', '• Le déjeuner est un hold-up gastronomique spectaculaire : 29€ les 3 services pour un tel niveau de cuisine, on trouve difficilement mieux à Paris.
INSERT INTO places_fts VALUES ('poi-erso', 'Erso', 'restaurant', 'français terrasse', '18 Rue Saint-Ambroise', '', 'Élu meilleur bistrot de Paris 2025 par le Lebey. Erso (la ’déferlante’ en basque) a tout emporté sur son passage. En cuisine, le jeune chef Yann Placet dégaine une bistronomie incisive d’une précision diabolique sur les cuissons et les condiments. En salle, Marine Bert orchestre un service tout en velours pour accompagner de pures assiettes de terroir moderne.');
