INSERT INTO places_fts VALUES ('poi-le-servan', 'Le Servan', 'restaurant', 'français bistronomie', '32 Rue Saint-Maur', '', 'Le bistrot fulgurant des sœurs Tatiana et Katia Levha. Sous ses airs de bistrot titi-parisien (moulures, plafond peint), la carte balance de formidables uppercuts aux influences asiatiques, et particulièrement philippines (piment, herbes fraîches, agrumes).');
