INSERT INTO places_fts VALUES ('poi-reyna', 'Reyna', 'restaurant', 'français bistronomie', '41 Rue de Montreuil', '', 'La ’Reine'' de la fusion philippine par Erica Paredes. Une cuisine de tripes et de cœur qui bouscule les codes : ingrédients saisonniers français rencontrant les punchy saveurs de Manille.');
