"items":[{"name":"Menu Dégustation 4 Temps","price_cents":6800,"description":"2 Entrées, 1 Plat, 1 Dessert"},{"name":"Menu Dégustation 5 Temps","price_cents":7500,"description":"Carte blanche au chef Taka"},{"name":"Menu Dégustation 7 Temps","price_cents":8500,"description":"L’expérience complète Machizo"},{"name":"Accord Mets & Vins","price_cents":4500,"description":"4 verres sélectionnés pour le menu 4 ou 5 temps"},{"name":"Accord Mets & Vins Premium","price_cents":6000,"description":"5 verres sélectionnés pour le menu 7 temps"}]},{"category_type":"other","display_label":"Exemples de Créations du Moment (Omakase)","items":[{"name":"Flan de foie gras","price_cents":2400,"description":"Prix Lebey 2024 du meilleur foie gras : Flan onctueux, bouillon dashi et champignons"},{"name":"Saint-Jacques snackées","price_cents":2200,"description":"Purée de topinambour, yuzu kosho et émulsion au beurre noisette"},{"name":"Sashimi de sériole","price_cents":1900,"description":"Sauce ponzu maison, radis daikon et huile de sésame grillé"},{"name":"Pigeon de Racan rôti","price_cents":3800,"description":"Cuisson sur le coffre, jus corsé au miso rouge et légumes racines"},{"name":"Lieu jaune de ligne","price_cents":3400,"description":"Asperges blanches, émulsion au saké et algues nori"},{"name":"Tartelette au matcha","price_cents":1200,"description":"Pâte sablée, ganache matcha et glace au sésame noir"},{"name":"Mousse au chocolat guanaja","price_cents":1100,"description":"Tuile croustillante et confit de yuzu"}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/machizo/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Le flan de foie gras infusé au dashi. Une texture irréelle qui a secoué la critique gastronomique.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Un joyau d’intimité caché dans le 11ème arrondissement (26 couverts seulement). Le chef Taka fusionne l’hyper-précision technique japonaise avec le répertoire gastronomique français. Une cuisine instinctive et évolutive servie sous forme de menus dégustation à l’aveugle, avec un service chaleureux assuré par son épouse Kornelia en salle.', '• Pensez à réserver très en avance (salle minuscule ouverte que le soir).
INSERT INTO places_fts VALUES ('poi-machizo', 'Machizo', 'restaurant', 'japonais', '35 Rue Saint-Sébastien', '', 'Un joyau d’intimité caché dans le 11ème arrondissement (26 couverts seulement). Le chef Taka fusionne l’hyper-précision technique japonaise avec le répertoire gastronomique français. Une cuisine instinctive et évolutive servie sous forme de menus dégustation à l’aveugle, avec un service chaleureux assuré par son épouse Kornelia en salle.');
