ted":"2026-03-07","menu_items":[{"category_type":"tasting_menu","display_label":"Menus Dégustation Gourmands","items":[{"name":"Menu Maison (Dîner 6 étapes)","price_cents":14000},{"name":"Menu Maison (Dîner 7 étapes - Mer-Sam)","price_cents":16500},{"name":"Menu Déjeuner (4 étapes)","price_cents":6500},{"name":"Menu Déjeuner (5 étapes - Jeu-Sam)","price_cents":8500},{"name":"Menu Dimanche (7 étapes)","price_cents":16500},{"name":"Accord Mets & Vins - Dîner","price_cents":11000}]},{"category_type":"other","display_label":"Signature Sota Atsumi (Extraits)","items":[{"name":"Makis de veau, huîtres & condiment algues","price_cents":0},{"name":"Asperges blanches cuites au bois, beurre d’agrumes","price_cents":0},{"name":"Saint-Jacques de plongée, mousseline de céleri","price_cents":0},{"name":"Pigeon de Vendée, betteraves au feu de bois","price_cents":0},{"name":"Poire rôtie, glace au foin & caramel beurre salé","price_cents":0},{"name":"Tartelette au yuzu & meringue italienne","price_cents":0},{"name":"Homard bleu de casier au Bincho-tan","price_cents":0},{"name":"Oursin & sabayon au Vin Jaune","price_cents":0},{"name":"Turbot sauvage, émulsion d’arêtes perlé","price_cents":0},{"name":"Pain maison au feu de bois & Beurre fermier","price_cents":0},{"name":"Mignardises de la Maison Sota","price_cents":0},{"name":"Eau micro-filtrée","price_cents":600},{"name":"Sélection de Cafés par Sota","price_cents":500}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-sota/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Laissez-vous totalement guider par le Menu Maison (165€). Le pigeon et les pièces maîtresses rôtissent lentement au feu de bois devant vos yeux, tandis que le homard et l’oursin font des apparitions remarquables au rythme des saisons.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Installé dans un loft sublimement réhabilité avec ses hauts plafonds et ses briques apparentes, Maison est le temple parisien du chef Sota Atsumi (ancien du Clown Bar). L’expérience s’articule autour d’un imposant four à bois spectaculaire placé au centre de la cuisine ouverte. La brigade y exécute une partition millimétrée, mêlant la rigueur japonaise aux plus beaux produits des terroirs français.', '• C’est la table pour célébrer un anniversaire où le budget n’est pas un problème. Le cadre est incroyablement esthétique et romantique.
INSERT INTO places_fts VALUES ('poi-maison-sota', 'Maison Sota Atsumi', 'restaurant', 'japonais', '3 Rue Saint-Hubert', '', 'Installé dans un loft sublimement réhabilité avec ses hauts plafonds et ses briques apparentes, Maison est le temple parisien du chef Sota Atsumi (ancien du Clown Bar). L’expérience s’articule autour d’un imposant four à bois spectaculaire placé au centre de la cuisine ouverte. La brigade y exécute une partition millimétrée, mêlant la rigueur japonaise aux plus beaux produits des terroirs français.');
