1/object/public/place-media/virtus/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/virtus/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine argentine. Saint-Jacques de plongée & Ris de Veau doré","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Virtus est une table étoilée discrète et élégante située à deux pas du marché d’Aligre. Porté par le duo de chefs Chiho Kanzaki et Marcelo di Giacomo, le restaurant propose une partition culinaire d’une grande finesse, mêlant technicité japonaise et générosité argentine. Le décor épuré aux tons pastel et le service attentif créent une atmosphère sereine, idéale pour découvrir une cuisine centrée sur la pureté du produit et l’harmonie des saveurs.', '• **Le Déjeuner Imbattable** : Le menu déjeuner à 45€ est sans doute l''un des meilleurs rapports qualité-prix étoilés de la capitale.
INSERT INTO places_fts VALUES ('poi-restaurant-virtus', 'Restaurant Virtus', 'restaurant', 'argentin', '29 Rue de Cotte, 75012 Paris, France', '', 'Virtus est une table étoilée discrète et élégante située à deux pas du marché d’Aligre. Porté par le duo de chefs Chiho Kanzaki et Marcelo di Giacomo, le restaurant propose une partition culinaire d’une grande finesse, mêlant technicité japonaise et générosité argentine. Le décor épuré aux tons pastel et le service attentif créent une atmosphère sereine, idéale pour découvrir une cuisine centrée sur la pureté du produit et l’harmonie des saveurs.');
