e":"main","display_label":"Plats","items":[{"name":"American Burger pur bœuf, frites maison","price_cents":1500},{"name":"Filet de cabillaud rôti à la poêle, petits légumes, pistou","price_cents":1500},{"name":"Côte de bœuf, sauce béarnaise, pommes salardaises","price_cents":1950},{"name":"Assiette de tapas","price_cents":1000}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Mi-cuit au chocolat tendre à cœur","price_cents":650},{"name":"Tarte Tatin, pomme Golden & quenelle de crème","price_cents":650},{"name":"Brioche façon pain perdu, caramel laitier & parfum glacé","price_cents":650}]},{"category_type":"other","display_label":"Bières","items":[{"name":"Pinte","price_cents":700},{"name":"Pinte Happy Hour (15h-00h)","price_cents":500}]},{"category_type":"drink","display_label":"Happy Hour (15h-00h)","items":[{"name":"Pinte","price_cents":500},{"name":"Vin blanc / rosé (verre)","price_cents":300}]}],"smart_tip":"Happy Hour XXL de 15h à minuit : pinte 5€, vin 3€. Côte de bœuf à 19,50€ pour les gros appétits.","last_updated":"2026-02-28"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-associes/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Brasserie. Les Associés.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Grande brasserie posée sur le boulevard de la Bastille, Les Associés joue la carte de la brasserie parisienne classique avec un twist afterwork. Deux terrasses (dont une couverte toute l’année), un intérieur spacieux, une cuisine française maison et un Happy Hour XXL qui s’étire de 15h jusqu’à minuit — le genre d''endroit où tu poses ton sac à la sortie du bureau et tu ne bouges plus de la soirée. La carte mélange burgers, tapas, plats de brasserie et un beau choix de desserts maison.', 'Le Happy Hour va jusqu’à MINUIT — c’est l’un des plus longs du quartier Bastille. Pinte à 5€ et verre de vin à 3€ pendant 9 heures d’affilée. La terrasse couverte est un game-changer quand il pleut. Attention : un avis MisterGoodBeer signale que les prix HH ne seraient pas toujours appliqués — vérifie à l’arrivée.', 'Bastille', '[1,5,8]', '[]', 'TODO', NULL, 1);
INSERT INTO places_fts VALUES ('poi-309', 'Les Associés', 'restaurant', 'brasserie bar afterwork terrasse', '50 Boulevard de la Bastille', '', 'Grande brasserie posée sur le boulevard de la Bastille, Les Associés joue la carte de la brasserie parisienne classique avec un twist afterwork. Deux terrasses (dont une couverte toute l’année), un intérieur spacieux, une cuisine française maison et un Happy Hour XXL qui s’étire de 15h jusqu’à minuit — le genre d''endroit où tu poses ton sac à la sortie du bureau et tu ne bouges plus de la soirée. La carte mélange burgers, tapas, plats de brasserie et un beau choix de desserts maison.');
