 minute.
INSERT INTO places_fts VALUES ('poi-au-petit-marguery', 'Au Petit Marguery', 'restaurant', 'bistrot terrasse', '9 Bd de Port-Royal, 75013 Paris, France', '', 'Au Petit Marguery est une institution de la cuisine bourgeoise située sur le boulevard de Port-Royal. Dans un décor de bistrot Belle Époque, le restaurant célèbre les traditions françaises avec une rigueur exemplaire. Célèbre pour ses gibiers en saison et son soufflé au Grand-Marnier, c’est l''adresse idéale pour un repas hors du temps.');
