/v1/object/public/place-media/il-etait-un-square-burger-paris/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/il-etait-un-square-burger-paris/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Burgers de terroir. Le Burger Montagnard & Mayonnaise Maison","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Réputé comme l’un des meilleurs spots de burgers de la rive gauche, Il Était Un Square mise sur la qualité brute : viande d’exception, frites maison et mayonnaises travaillées. L’ambiance y est conviviale, presque villageoise malgré la proximité de la Place d''Italie. Une adresse de quartier qui ne déçoit jamais les amateurs de produits sourcés.', '• **Frites Légendaires** : Elles sont coupées et cuites sur place, trempez-les absolument dans leur mayonnaise maison.
INSERT INTO places_fts VALUES ('poi-il-etait-un-square-burger-paris', 'Il Était Un Square', 'restaurant', 'burger terrasse', '54 Rue Corvisart, 75013 Paris, France', '', 'Réputé comme l’un des meilleurs spots de burgers de la rive gauche, Il Était Un Square mise sur la qualité brute : viande d’exception, frites maison et mayonnaises travaillées. L’ambiance y est conviviale, presque villageoise malgré la proximité de la Place d''Italie. Une adresse de quartier qui ne déçoit jamais les amateurs de produits sourcés.');
