INSERT INTO places_fts VALUES ('poi-l-ourcine', 'L’Ourcine', 'restaurant', 'bar à vin terrasse', '92 Rue Broca, 75013 Paris, France', '', 'L’Ourcine est une adresse bistronomique d’exception au cœur du 13ème arrondissement. Derrière une façade discrète de la rue Broca se cache une cuisine de marché créative, généreuse et techniquement irréprochable. L’ambiance y est conviviale, typique des grands bistrots parisiens qui privilégient le produit et le goût.');
