INSERT INTO places_fts VALUES ('poi-la-felicita', 'La Felicità', 'restaurant', 'italien terrasse ferme tard', '5 Parv. Alan Turing, 75013 Paris, France', '', 'La Felicità est le vaisseau amiral du groupe Big Mamma à Station F. Ce food-market italien de 4500m² est un lieu hybride unique à Paris, mêlant plusieurs stands gourmands (Pizza, Pasta, Burger, Cocktails) dans un décor spectaculaire et végétalisé. C’est l''endroit parfait pour une sortie festive et décontractée en groupe.');
