r/","label":"VOIR LE SITE"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"certification":"silver","avg_budget":18,"dish_price":14.5,"is_free":false,"last_updated":"2026-03-25","verified_at":"2026-03-25","menu_items":[{"category_type":"starter","display_label":"Entrées (Khmères)","items":[{"name":"Salade d’Ananas aux Crevettes","price_cents":950,"is_highlight":true},{"name":"Raviolis à la vapeur (Knom Krok)","price_cents":850},{"name":"Rouleaux de Printemps Maison","price_cents":700},{"name":"Satay de Bœuf Grillé (x3)","price_cents":900},{"name":"Salade de Papaye Verte (Épicée)","price_cents":850},{"name":"Ailes de Poulet Farcies","price_cents":1000}]},{"category_type":"main","display_label":"Spécialités de la Maison (Plats)","items":[{"name":"Amok de Poisson (Traditionnel)","price_cents":1450,"is_highlight":true},{"name":"Curry Rouge au Canard & Litchis","price_cents":1500},{"name":"Lok Lak (Bœuf sauté au poivre)","price_cents":1400},{"name":"Mekong Prawns (Sauce Coco)","price_cents":1650},{"name":"Poulet au Curry Jaune & Bambou","price_cents":1350},{"name":"Saumon Grillé à la Khmère","price_cents":1550},{"name":"Tofu sauté aux Légumes Croquants","price_cents":1250}]},{"category_type":"tasting_menu","display_label":"Formules & Menus Découverte","items":[{"name":"Menu Découverte (2 pers.)","price_cents":4200,"is_highlight":true},{"name":"Formule Midi (E+P)","price_cents":1400},{"name":"Formule Midi (E+P+D)","price_cents":1750}]},{"category_type":"dessert","display_label":"Douceurs (Desserts)","items":[{"name":"Flan au Lait de Coco & Taro","price_cents":650},{"name":"Mangue Fraîche & Riz Gluant","price_cents":850},{"name":"Banane au Lait de Coco","price_cents":600},{"name":"Gingembre Confis Maison","price_cents":450},{"name":"Perles du Japon aux fruits","price_cents":650}]},{"category_type":"drink","display_label":"La Cave / Boissons","items":[{"name":"Bière Angkor (Cambodge)","price_cents":650,"is_highlight":true},{"name":"Thé Vert Jasmin Artisanal","price_cents":450},{"name":"Jus de Coco Frais (Entier)","price_cents":700},{"name":"Café à la mode de Phnom Penh","price_cents":350},{"name":"Infusion Gingembre Frais","price_cents":450},{"name":"Verre de Vin Blanc (Viognier)","price_cents":600}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mondol-kiri/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française traditionnelle. Amok de Poisson & Salade d’Ananas","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Mondol Kiri est l’ambassadeur de la gastronomie cambodgienne dans le 13e arrondissement depuis 2010. Situé sur l’avenue de Choisy, ce restaurant cultive un art de vivre khmer tout en finesse, loin de l’agitation des grands bouillons. La spécialité, l’Amok de poisson cuit à la vapeur dans une feuille de bananier, est un chef-d’œuvre de douceur et d’équilibre. L’accueil y est d’une politesse rare, offrant une parenthèse apaisante et authentique aux amateurs de saveurs d’Asie du Sud-Est.', '• **Le Trésor National** : Ne passez pas à côté de l’Amok, c''est le plat national cambodgien et il est ici exécuté selon une recette familiale ancestrale.
INSERT INTO places_fts VALUES ('poi-mondol-kiri', 'Mondol Kiri', 'restaurant', 'bouillon terrasse', '159 Av. de Choisy, 75013 Paris, France', '', 'Mondol Kiri est l’ambassadeur de la gastronomie cambodgienne dans le 13e arrondissement depuis 2010. Situé sur l’avenue de Choisy, ce restaurant cultive un art de vivre khmer tout en finesse, loin de l’agitation des grands bouillons. La spécialité, l’Amok de poisson cuit à la vapeur dans une feuille de bananier, est un chef-d’œuvre de douceur et d’équilibre. L’accueil y est d’une politesse rare, offrant une parenthèse apaisante et authentique aux amateurs de saveurs d’Asie du Sud-Est.');
