mgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/restaurant-lao-lane-xang/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine vietnamienne. Salade de riz croustillant & Steak Lao","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Lao Lane Xang 2 est l’une des tables les plus respectées du 13ème arrondissement. Proposant un voyage culinaire entre le Laos, la Thaïlande et le Vietnam, le lieu est célèbre pour son équilibre parfait entre épices et fraîcheur. Un cadre plus soigné que les cantines voisines, idéal pour découvrir des spécialités comme le riz croustillant ou le canard au curry.', '• **Combo Moelle** : La salade de riz croustillant (Nam Khao) est un incontournable absolu pour commencer le repas.
INSERT INTO places_fts VALUES ('poi-restaurant-lao-lane-xang', 'Restaurant Lao Lane Xang', 'restaurant', 'vietnamien terrasse', '102 Av. d’Ivry, 75013 Paris, France', '', 'Lao Lane Xang 2 est l’une des tables les plus respectées du 13ème arrondissement. Proposant un voyage culinaire entre le Laos, la Thaïlande et le Vietnam, le lieu est célèbre pour son équilibre parfait entre épices et fraîcheur. Un cadre plus soigné que les cantines voisines, idéal pour découvrir des spécialités comme le riz croustillant ou le canard au curry.');
