INSERT INTO places_fts VALUES ('poi-tempero-epicerie', 'TEMPERO EPICERIE', 'restaurant', 'bar à vin terrasse', '24 Prom. Claude Lévi-Strauss, 75013 Paris, France', '', 'Tempero Épicerie est la ’petite sœur’ du restaurant Nosso d’Alessandra Montagne. Cette épicerie-cantine propose une cuisine vive, locale et aux accents brésiliens dans un cadre moderne et lumineux. On y vient pour les cocottes réconfortantes, les vins natures et l''atmosphère décontractée du quartier de la BNF.');
