s":0,"coffee_price":0,"dish_price":15.5,"last_updated":"2026-03-05","menu_items":[{"category_type":"other","display_label":"Antipasti","items":[{"name":"Mozzarella bufala, pesto di basilico","price_cents":900},{"name":"Antipasto verduro","price_cents":900},{"name":"Piatti di parma (Assiette jambon de Parme)","price_cents":950},{"name":"Burratina","price_cents":1100},{"name":"Trio di bruschetta casareccia","price_cents":1350},{"name":"Involtini di melanzane","price_cents":1350},{"name":"Fiori di zucchina in pastella","price_cents":1400}]},{"category_type":"main","display_label":"Pizzas (Feu de bois)","items":[{"name":"Margherita","price_cents":1250},{"name":"4 Formaggi","price_cents":1550}]},{"category_type":"other","display_label":"Pâtes & Gnocchis","items":[{"name":"Penne puttanesca","price_cents":1500},{"name":"Linguine al limone (Pignons, citron, crème)","price_cents":1500},{"name":"Tagliatelle verdure","price_cents":1550},{"name":"Gnocchi ai formaggi","price_cents":1550},{"name":"Penne modica (Pesto de noix, gorgonzola)","price_cents":1600},{"name":"Gnocchi Veloci (Speck, champignon, crème)","price_cents":1600},{"name":"Fusilli calabrese","price_cents":1700},{"name":"Penne salmone","price_cents":1750},{"name":"Fusilli dello chef (Veau haché, champignons)","price_cents":1750},{"name":"Linguine alle vongole","price_cents":1850},{"name":"Tagliatelle di bronte (Gambas, pesto pistache)","price_cents":1850},{"name":"Tagliatelle tartufate (Crème de truffe, Parme)","price_cents":1900},{"name":"Linguine frutti di mare","price_cents":1950}]},{"category_type":"main","display_label":"Viandes (Secondi Piatti)","items":[{"name":"Scaloppina alla crema di tartufo","price_cents":2350}]},{"category_type":"dessert","display_label":"Dolci (Desserts)","items":[{"name":"Cannoli siciliani","price_cents":900}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lancetta/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne. L’art de la pasta. Ne passez pas à côté des beignets de fleurs de courgettes (14€) en entrée. Le plat phare : les incroyables Tagliatelle tartufate (19€) ou de puissantes Linguine frutti di mare.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Installé en plein cœur du 13ème arrondissement historique près de la Place d’Italie, Lancetta est une véritable pépite italienne qui cultive le secret d’une trattoria authentique. Avec son ambiance chaleureuse, son rez-de-chaussée vibrant et sa salle à l’étage un peu plus intime, on y vient pour déguster une cuisine sincère et extrêmement soignée : pêle-mêle de pâtes minutieusement sourcées, d''antipasti généreux et de pizzas au feu de bois.', '• Une salle à manger se trouve à l’étage, n’hésitez pas à la demander lors de votre réservation si vous souhaitez un cadre plus intimiste.
INSERT INTO places_fts VALUES ('poi-lancetta', 'Lancetta', 'restaurant', 'italien', '26 Rue Bobillot', '', 'Installé en plein cœur du 13ème arrondissement historique près de la Place d’Italie, Lancetta est une véritable pépite italienne qui cultive le secret d’une trattoria authentique. Avec son ambiance chaleureuse, son rez-de-chaussée vibrant et sa salle à l’étage un peu plus intime, on y vient pour déguster une cuisine sincère et extrêmement soignée : pêle-mêle de pâtes minutieusement sourcées, d''antipasti généreux et de pizzas au feu de bois.');
