,"main_action":{"type":"book","url":"https://www.restaurant-empreinte.paris/","label":"RÉSERVER UNE TABLE"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":48,"is_free":false,"dish_price":24,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"L’Empreinte (Plats)","items":[{"name":"Ris de Veau Croustillant Sauce Foie Gras","price_cents":3900,"description":"Écrasé de PDT et pleurotes de saison."},{"name":"Tartare de Boeuf au couteau du Chef","price_cents":2400},{"name":"Magret de Canard Miel & Romarin","price_cents":2400},{"name":"Filet de Bar, Sauce Hollandaise","price_cents":2400},{"name":"Noix de St-Jacques Poêlées, Passion","price_cents":2900},{"name":"Filet de Boeuf Poêlé, Jus de Viande","price_cents":2900},{"name":"Assiette Végétarienne du Marché","price_cents":2400}]},{"category_type":"starter","display_label":"Entrées de Saison","items":[{"name":"Brick de Saint-Marcellin au Miel","price_cents":1200},{"name":"Foie Gras de Canard Maison","price_cents":1900},{"name":"Nage de Couteaux à la Crème Persillée","price_cents":1500},{"name":"Terrine de Râbles de Lapin au Foie Gras","price_cents":1500},{"name":"Salade d’Écrevisses au Curry & Avocat","price_cents":1500},{"name":"Tartare de Veau à la Pistache","price_cents":1700},{"name":"Saumon Gravlax, Mousse Citron Vert","price_cents":1500},{"name":"Feuilleté d’Escargots de Bourgogne","price_cents":1700}]},{"category_type":"dessert","display_label":"Douceurs Finales","items":[{"name":"Tarte Tatin revisitée par le Chef","price_cents":1000},{"name":"Pavlova aux Fruits Frais","price_cents":1000},{"name":"Tarte au Citron de l’Empreinte","price_cents":1000},{"name":"Crème Brûlée à la Fève de Tonka","price_cents":1000},{"name":"Fondant au Chocolat, vanille","price_cents":1000},{"name":"Camembert aux Noix et Calvados","price_cents":1100}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-empreinte-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Le Ris de Veau Croustillant sauce Foie Gras.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'L’Empreinte est une pépite bistronomique discrète nichée rue Mouton-Duvernet. Le chef Noël Druais y déploie une cuisine de marché inventive et d’une grande justesse technique, privilégiant les circuits courts et les produits d’exception. Le cadre, aux tons chauds et à l’éclairage soigné, offre une atmosphère intimiste idéale pour une dégustation attentive. Chaque assiette est une composition équilibrée où les saveurs franches des produits de saison sont sublimées par des jus et des émulsions de caractère. C’est l’adresse parfaite pour ceux qui cherchent la discrétion et l’excellence culinaire sans le formalisme des grandes tables.', 'Le ris de veau croustillant est la signature absolue du lieu, d’une tendreté et d''un goût incomparables. Pensez également à explorer leur carte des vins, riche en références de vignerons indépendants très bien sourcées.', 'Mouton-Duvernet', '["4"]', '[]', 'ChIJEcUSM7dx5kcRo3kHqPKmfao', NULL, 0);
INSERT INTO places_fts VALUES ('poi-empreinte-75014', 'L’Empreinte', 'restaurant', 'bistronomie français', '5 Rue Mouton-Duvernet, 75014 Paris, France', '', 'L’Empreinte est une pépite bistronomique discrète nichée rue Mouton-Duvernet. Le chef Noël Druais y déploie une cuisine de marché inventive et d’une grande justesse technique, privilégiant les circuits courts et les produits d’exception. Le cadre, aux tons chauds et à l’éclairage soigné, offre une atmosphère intimiste idéale pour une dégustation attentive. Chaque assiette est une composition équilibrée où les saveurs franches des produits de saison sont sublimées par des jus et des émulsions de caractère. C’est l’adresse parfaite pour ceux qui cherchent la discrétion et l’excellence culinaire sans le formalisme des grandes tables.');
