main_action":{"type":"book","url":"https://Origins-14.com/","label":"RÉSERVER UNE TABLE"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":55,"is_free":false,"dish_price":15,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Les Créations du Moment","items":[{"name":"Poitrine de Cochon Fermier Moelleuse de chez Ospital","price_cents":2600,"description":"Couenne croustillante, haricots de Paimpol et chorizo."},{"name":"Risotto Crémeux à l’Encre de Seiche","price_cents":2400},{"name":"Cabillaud Rôti sur la peau, Gnocchis à l’encre","price_cents":2700},{"name":"Suprême de Volaille Jaune des Landes","price_cents":2700},{"name":"Paleron de Boeuf braisé au Vin Noir","price_cents":2700},{"name":"Tartare de Boeuf au Couteau & Frites","price_cents":2400},{"name":"Carbonara de Céleri façon Risotto","price_cents":2250}]},{"category_type":"starter","display_label":"L’Héritage Régalade (Entrées)","items":[{"name":"Terrine de Campagne offerte à l’arrivée","price_cents":0,"description":"Le geste emblématique de la maison."},{"name":"Royale de Foie Gras de Canard, Bouillon Champignons","price_cents":1800},{"name":"Poêlée d’Escargots et Champignons au Chorizo","price_cents":1500},{"name":"Vitello Tonnato de La Régalade","price_cents":1400},{"name":"Soupe Crémeuse de Choux-Fleurs au Parmesan","price_cents":1500},{"name":"Rôtis d’Escargots à l''Oeuf Poché","price_cents":1450}]},{"category_type":"dessert","display_label":"Signatures Sucrées","items":[{"name":"Le Fameux Riz au Lait de Grand-Mère","price_cents":1200,"description":"Servi dans son grand saladier avec caramel laitier."},{"name":"Soufflé Chaud au Grand Marnier","price_cents":1200},{"name":"Guimauve Maison, Chocolat Noir & Coco","price_cents":1100},{"name":"Tarte Fine aux Pommes et Vanille","price_cents":1200},{"name":"Cheesecake Maison à la Mangue & Passion","price_cents":1200}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-regalade-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. La Poitrine de Cochon Ospital et le Riz au Lait.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'La Régalade est le berceau de la bistronomie parisienne. Fondée par Yves Camdeborde et aujourd’hui perpétuée sous le nom d’Origins 14, cette institution n’a rien perdu de sa superbe. Le concept reste inchangé : une généreuse terrine de campagne déposée sur table à l’arrivée, suivie d’une cuisine de marché inventive et sincère. C’est ici que s’est inventé un luxe démocratisé, où l''excellence culinaire se savoure dans une ambiance de bistrot vibrant et décontracté. Le riz au lait final, servi à discrétion dans son saladier familial, est devenu le symbole de cette générosité jamais démentie.', 'Ne mangez pas trop de pain avec la terrine d’accueil, les plats sont riches ! Le menu-carte en trois services est le meilleur moyen de découvrir toute l''étendue du talent de la brigade. Le riz au lait est une obligation morale.', 'Alésia', '["4"]', '[]', 'ChIJq2raO61x5kcRjYZM61f-eT4', NULL, 1);
INSERT INTO places_fts VALUES ('poi-la-regalade-75014', 'La Régalade (Origins 14)', 'restaurant', 'bistronomie français terrasse', '49 Avenue Jean Moulin, 75014 Paris, France', '', 'La Régalade est le berceau de la bistronomie parisienne. Fondée par Yves Camdeborde et aujourd’hui perpétuée sous le nom d’Origins 14, cette institution n’a rien perdu de sa superbe. Le concept reste inchangé : une généreuse terrine de campagne déposée sur table à l’arrivée, suivie d’une cuisine de marché inventive et sincère. C’est ici que s’est inventé un luxe démocratisé, où l''excellence culinaire se savoure dans une ambiance de bistrot vibrant et décontracté. Le riz au lait final, servi à discrétion dans son saladier familial, est devenu le symbole de cette générosité jamais démentie.');
