get":30,"is_free":false,"dish_price":12.85,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Brasserie Maison","items":[{"name":"Tartare de Boeuf Charolais ’Rendez-Vous''","price_cents":1750},{"name":"Hamburger Maison au Cantal","price_cents":1800},{"name":"Poulet Fermier Rôti, Frites Maison","price_cents":1850},{"name":"Saucisse au couteau de l’Aveyron","price_cents":1650},{"name":"Tartare de Saumon Frais aux Herbes","price_cents":1900},{"name":"Entrecôte Grillée (300g), Sauce Poivre","price_cents":2200},{"name":"Linguine à la Tomate et Basilic Frais","price_cents":1550},{"name":"Plat du Semainier (du jour)","price_cents":1500}]},{"category_type":"sharing","display_label":"Salades & Planches (Happy Hour)","items":[{"name":"Salade César au Poulet Croustillant","price_cents":1420},{"name":"Salade Niçoise au Thon Frais","price_cents":1450},{"name":"Oeuf Cocotte à la Tomate Confite","price_cents":1150},{"name":"Asperges Rôties au Parmesan","price_cents":750},{"name":"Grande Planche Mixte Rendez-Vous","price_cents":2400},{"name":"Tapas du moment (l’unité)","price_cents":600}]},{"category_type":"dessert","display_label":"Desserts & Glaces","items":[{"name":"Nougat Glacé Maison aux Fruits Secs","price_cents":680},{"name":"Coulant au Chocolat Coeur Fondant","price_cents":800},{"name":"Tarte du Jour","price_cents":750},{"name":"Glaces Artisanales (2 boules)","price_cents":700}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-du-rendez-vous/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. L’Hamburger maison au Cantal et les Oeufs Cocotte.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Posté à l’angle stratégique de la place Denfert-Rochereau, le Café du Rendez-Vous est le point de ralliement incontournable du quartier. Ce grand bistrot parisien, avec sa terrasse chauffée qui s’étire généreusement sur le trottoir, offre une animation constante du petit-déjeuner au dernier verre nocturne. L’ambiance y est cosmopolite, vibrante et décontractée, attirant aussi bien les voyageurs en transit que les habitués du 14ème. C''est le lieu idéal pour une pause rapide, un déjeuner de travail efficace ou un Happy Hour prolongé entre amis, le tout dans un décor de brasserie moderne et chaleureuse.', 'Leur Happy Hour est l’un des plus généreux du quartier, incluant des cocktails créatifs et des planches de produits sourcés. C’est aussi l’endroit parfait pour observer le tumulte parisien depuis la terrasse sans être pressé par le service.', 'Denfert-Rochereau', '["4","6","RER B"]', '[]', 'ChIJEYElfrdx5kcR8NJ6jn7CDG8', NULL, 1);
INSERT INTO places_fts VALUES ('poi-cafe-du-rendez-vous', 'Café du Rendez-Vous', 'café', 'français terrasse terrasse', '2 Avenue du Général Leclerc, 75014 Paris, France', '', 'Posté à l’angle stratégique de la place Denfert-Rochereau, le Café du Rendez-Vous est le point de ralliement incontournable du quartier. Ce grand bistrot parisien, avec sa terrasse chauffée qui s’étire généreusement sur le trottoir, offre une animation constante du petit-déjeuner au dernier verre nocturne. L’ambiance y est cosmopolite, vibrante et décontractée, attirant aussi bien les voyageurs en transit que les habitués du 14ème. C''est le lieu idéal pour une pause rapide, un déjeuner de travail efficace ou un Happy Hour prolongé entre amis, le tout dans un décor de brasserie moderne et chaleureuse.');
