rice_cents":1750}]},{"category_type":"starter","display_label":"Entrées & Tapas","items":[{"name":"Oeuf cocotte à la tomate confite","price_cents":1150},{"name":"Asperges rôties au parmesan","price_cents":750},{"name":"Planche de tapas à partager","price_cents":1800},{"name":"Soupe à l’oignon gratinée","price_cents":950}]},{"category_type":"dessert","display_label":"Douceurs Maison","items":[{"name":"French Toast au caramel beurre salé","price_cents":900},{"name":"Tiramisu du Rendez-Vous","price_cents":850},{"name":"Île flottante généreuse","price_cents":750}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/cafe-rendez-vous/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. L’œuf cocotte maison et le French Toast au caramel.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Café du Rendez-Vous est l’âme battante de la Place Denfert-Rochereau. Depuis plus de 30 ans, cette brasserie tenue par la famille Porte incarne le trait d’union parfait entre le bistrot parisien traditionnel et l’élégance contemporaine. Sa terrasse chauffée et vitrée, véritable poste d''observation sur le mouvement de la ville, ne désemplit jamais, du petit-déjeuner matinal au dernier cocktail de la nuit.', 'Profitez du Happy Hour de 17h à 21h pour découvrir leurs planches de tapas à prix doux. La terrasse est chauffée en hiver, ce qui en fait l’un des rares spots confortables dehors toute l''année à Denfert.', 'Denfert-Rochereau', '[4,6,"B"]', '[]', 'ChIJEYElfrdx5kcR8NJ6jn7CDG8', NULL, 1);
INSERT INTO places_fts VALUES ('poi-cafe-rendez-vous', 'Café du Rendez-Vous', 'restaurant', 'français bistronomie terrasse terrasse', '2 Av. du Général Leclerc', '', 'Le Café du Rendez-Vous est l’âme battante de la Place Denfert-Rochereau. Depuis plus de 30 ans, cette brasserie tenue par la famille Porte incarne le trait d’union parfait entre le bistrot parisien traditionnel et l’élégance contemporaine. Sa terrasse chauffée et vitrée, véritable poste d''observation sur le mouvement de la ville, ne désemplit jamais, du petit-déjeuner matinal au dernier cocktail de la nuit.');
