:8,"wine_glass":7,"coffee_price":2.5,"dish_price":19.25,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Antipasti (Le partage à l’italienne)","items":[{"name":"Burrata des Pouilles & Tomates cerises","price_cents":1350},{"name":"Vitello Tonnato traditionnel","price_cents":1600},{"name":"Beignets de Mozzarella (Fritters)","price_cents":1150},{"name":"Planche de charcuterie transalpine","price_cents":1900},{"name":"Focaccia romarin & fleur de sel","price_cents":600}]},{"category_type":"other","display_label":"Pizze au feu de bois","items":[{"name":"Pizze Grappoli (Parme, Roquette, Tomate, Mozza)","price_cents":1850},{"name":"Margherita di Buffala Classica","price_cents":1450},{"name":"Diavola (Salami piquant, N’duja)","price_cents":1650},{"name":"Tartufo (Crème de truffe, Champignons)","price_cents":1950}]},{"category_type":"main","display_label":"Pasta Fresca & Secondi","items":[{"name":"Linguine à la Vongole (Palourdes)","price_cents":2100},{"name":"Spaghetti alla Carbonara (Guanciale)","price_cents":1750},{"name":"Penne alla Norma (Aubergines, Ricotta)","price_cents":1600},{"name":"Escalope de Veau Milanaise","price_cents":2250}]},{"category_type":"other","display_label":"Dolci","items":[{"name":"Tiramisu della Nonna","price_cents":850},{"name":"Panna Cotta aux fruits rouges","price_cents":750},{"name":"Profiterole Géante au chocolat chaud","price_cents":1000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/i-grappoli/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine italienne. La pizza Tripletta (homonyme piquant) ou les linguine alla Vongole.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'I Grappoli est l’adresse transalpine qui réchauffe la Place Denfert-Rochereau. Cette véritable trattoria de quartier brille par sa simplicité authentique et sa générosité. Avec sa grande terrasse ensoleillée, c’est le lieu idéal pour une immersion italienne, entre pizzas cuites au feu de bois et pâtes fraîches maison. L’ambiance y est vibrante, rappelant les déjeuners dominicaux en famille sous le soleil de Toscane.', 'Leur terrasse est un véritable aimant à soleil, arrivez tôt aux beaux jours. Ne manquez pas les beignets de mozzarella en entrée, un plaisir régressif parfait avec un Spritz.', 'Denfert-Rochereau', '[4,6,"B"]', '[]', 'ChIJu3t9ZLVx5kcRxSvcyGOmQm0', NULL, 1);
INSERT INTO places_fts VALUES ('poi-grappoli', 'I Grappoli', 'restaurant', 'italien terrasse', '22 Pl. Denfert-Rochereau', '', 'I Grappoli est l’adresse transalpine qui réchauffe la Place Denfert-Rochereau. Cette véritable trattoria de quartier brille par sa simplicité authentique et sa générosité. Avec sa grande terrasse ensoleillée, c’est le lieu idéal pour une immersion italienne, entre pizzas cuites au feu de bois et pâtes fraîches maison. L’ambiance y est vibrante, rappelant les déjeuners dominicaux en famille sous le soleil de Toscane.');
