5,"is_free":false,"dish_price":18.5,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"starter","display_label":"Starters & Shared Plates","items":[{"name":"Planche Mixte (Charcuteries & Fromages)","price_cents":2600},{"name":"Foie Gras de Canard, Chutney de Saison","price_cents":2100},{"name":"Crème de Saint-Jacques au St Marcellin","price_cents":800},{"name":"Gaspacho Andalou & Quenelle Guacamole","price_cents":700},{"name":"Gratinée à l’Oignon Traditionnelle","price_cents":700},{"name":"Carpaccio de Boeuf au Miel","price_cents":1200},{"name":"Tentacules de Poulpe Caramélisés","price_cents":1400}]},{"category_type":"main","display_label":"Les Plats de la Scène","items":[{"name":"Belle Entrecôte (300g) Sauce Béarnaise","price_cents":2200},{"name":"Filets de Bar, Sauce Vierge, Ecrasé de PDT","price_cents":1800},{"name":"Suprême de Poulet aux Cèpes & Truffe","price_cents":1400},{"name":"Timbale de Légumes de Saison","price_cents":1600},{"name":"Bar de Ligne, Emulsion Bergamote","price_cents":2000},{"name":"Veau Fondant au Serrano","price_cents":2200},{"name":"Risotto crémeux aux champignons","price_cents":1800},{"name":"Burger Jazz au Comté","price_cents":1900}]},{"category_type":"dessert","display_label":"Desserts Final","items":[{"name":"Café Gourmand (4 mignardises)","price_cents":700},{"name":"Cheesecake Maison aux Fruits Rouges","price_cents":700},{"name":"Crème Brûlée à l’Anis Étoilée","price_cents":700},{"name":"Dôme Vanille-Amande & Hibiscus","price_cents":900},{"name":"Pavé Chocolat Guanaja 70%","price_cents":900}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/jazz-cafe-montparnasse/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. L’Entrecôte sauce Béarnaise et le Pavé Chocolat Guanaja.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le temple de la note bleue à Montparnasse. Le Jazz Café Montparnasse perpétue l’esprit légendaire des jazz clubs parisiens dans un cadre moderne, confortable et acoustiquement irréprochable. Ici, la musique ne se savoure pas seulement avec les oreilles, mais aussi avec une cuisine de bistrot généreuse et soignée. La scène accueille chaque soir des pointures internationales et des talents émergents, créant une atmosphère électrique où les verres s’entrechoquent au rythme du swing. C’est le lieu parfait pour une soirée hors du temps, entre improvisation culinaire et virtuosité musicale.', 'Les concerts débutent généralement à 21h, mais arrivez dès 18h30 pour l’apéritif dans la véranda, l''ambiance y est déjà magique. Pensez à réserver les tables en bord de scène pour une immersion totale.', 'Gaîté', '["13"]', '[]', 'ChIJVVVVzspx5kcR-5LwER4FSEE', NULL, 1);
INSERT INTO places_fts VALUES ('poi-jazz-cafe-montparnasse', 'Jazz Café Montparnasse', 'restaurant', 'bistrot terrasse', '13 Rue du Commandant René Mouchotte, 75014 Paris, France', '', 'Le temple de la note bleue à Montparnasse. Le Jazz Café Montparnasse perpétue l’esprit légendaire des jazz clubs parisiens dans un cadre moderne, confortable et acoustiquement irréprochable. Ici, la musique ne se savoure pas seulement avec les oreilles, mais aussi avec une cuisine de bistrot généreuse et soignée. La scène accueille chaque soir des pointures internationales et des talents émergents, créant une atmosphère électrique où les verres s’entrechoquent au rythme du swing. C’est le lieu parfait pour une soirée hors du temps, entre improvisation culinaire et virtuosité musicale.');
