/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mosugo-mory-sacko-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Street-food (Afro-fusion). Le Mosugo Chicken Burger et les Alocco.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Avec Mosugo, le chef étoilé Mory Sacko démocratise son univers afro-fusion à travers la street-food. Concentré sur le poulet frit (incroyablement croustillant et épicé), ce spot du 14ème propose des burgers au pain bretzel et des accompagnements qui font voyager, comme les l’alocco (bananes plantains). C’est une immersion rapide et savoureuse dans la signature culinaire de l’un des chefs les plus créatifs de sa génération.', 'Prenez absolument les Alocco (bananes plantains) en accompagnement, elles sont parfaitement caramélisées. Si vous avez une grosse faim, le Menu Burger and Fried est une expérience totale du concept.', 'Gaîté', '[13]', '[]', 'ChIJ3YTrLT1x5kcRTTzu1sGsJq8', NULL, 0);
INSERT INTO places_fts VALUES ('poi-mosugo', 'MOSUGO', 'restaurant', 'street-food', '22 Rue Raymond Losserand, 75014 Paris', '', 'Avec Mosugo, le chef étoilé Mory Sacko démocratise son univers afro-fusion à travers la street-food. Concentré sur le poulet frit (incroyablement croustillant et épicé), ce spot du 14ème propose des burgers au pain bretzel et des accompagnements qui font voyager, comme les l’alocco (bananes plantains). C’est une immersion rapide et savoureuse dans la signature culinaire de l’un des chefs les plus créatifs de sa génération.');
