false,"happy_hour":null}', '{"avg_budget":35,"is_free":false,"dish_price":12.75,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Spécialités de l’Aubrac","items":[{"name":"Aligot Traditionnel Monté en direct","price_cents":1850,"description":"La spécialité maison, servie avec saucisse fraîche."},{"name":"Truffade Dorée à la Tome","price_cents":1950},{"name":"Saucisse fraîche d’Auvergne & Aligot","price_cents":2000},{"name":"Chou Farci à l’Aveyronnaise","price_cents":1900},{"name":"Tripoux d’Auvergne (les 3)","price_cents":2100},{"name":"Pavé de Boeuf de l’Aubrac (250g)","price_cents":2450},{"name":"Entrecôte Nature (330g)","price_cents":2600},{"name":"Côte de Boeuf (500g) pour amateurs","price_cents":3400},{"name":"Magret de Canard Entier (380g)","price_cents":2800}]},{"category_type":"starter","display_label":"Entrées & Fromages","items":[{"name":"Planche de Charcuterie d’Auvergne","price_cents":1700},{"name":"Salade de Canard Fumé","price_cents":1450},{"name":"Jambon Cru de Montagne","price_cents":1200},{"name":"Assiette de 5 Fromages AOP","price_cents":1350},{"name":"Cabécou AOP (les 2)","price_cents":850},{"name":"Terrine de Campagne Maison","price_cents":900}]},{"category_type":"dessert","display_label":"Desserts Traditionnels","items":[{"name":"Tarte aux Myrtilles Sauvages","price_cents":850},{"name":"Coupe de Glace (3 boules)","price_cents":900},{"name":"Mousse au Chocolat","price_cents":750},{"name":"Crème Brûlée Vanille","price_cents":800},{"name":"Baba au Rhum","price_cents":950}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-plomb-du-cantal-gaite/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de terroir. L’Aligot Saucisse, évidemment.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Plomb du Cantal est l’ambassade la plus authentique (et la plus généreuse) de l’Auvergne à Paris. Situé dans la bouillonnante rue de la Gaîté, ce restaurant est célèbre pour son aligot et sa truffade, étirés avec virtuosité sous les yeux des clients. Le décor est rustique, les assiettes débordent et l’ambiance est celle d’une fête de village à Laguiole. C’est l''endroit idéal pour les très grosses faims et les amateurs de gastronomie de terroir sans concession, servis dans une atmosphère bon enfant qui ne désemplit jamais.', 'Visez le service continu si vous voulez éviter la file d’attente monumentale aux heures de pointe. Les portions frolent le gargantuesque, donc ménagez vos efforts sur l’entrée si vous voulez voir la fin de votre plateau d’aligot.', 'Gaîté', '["13"]', '[]', 'ChIJQ4R4kctx5kcR-FcGt54DySs', NULL, 1);
INSERT INTO places_fts VALUES ('poi-plomb-du-cantal-gaite', 'Le Plomb du Cantal', 'restaurant', 'français terrasse terrasse', '3 Rue de la Gaîté, 75014 Paris, France', '', 'Le Plomb du Cantal est l’ambassade la plus authentique (et la plus généreuse) de l’Auvergne à Paris. Situé dans la bouillonnante rue de la Gaîté, ce restaurant est célèbre pour son aligot et sa truffade, étirés avec virtuosité sous les yeux des clients. Le décor est rustique, les assiettes débordent et l’ambiance est celle d’une fête de village à Laguiole. C’est l''endroit idéal pour les très grosses faims et les amateurs de gastronomie de terroir sans concession, servis dans une atmosphère bon enfant qui ne désemplit jamais.');
