0 – 2:15 PM, 7:00 – 10:30 PM | Sunday: 12:00 – 2:15 PM, 7:00 – 10:30 PM","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"main_action":{"type":"site","url":"http://www.restaurant-ledome.com/","label":"SITE OFFICIEL"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":65,"is_free":false,"dish_price":35,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"L’Art des Poissons","items":[{"name":"Sole Meunière Façon Dôme (selon poids)","price_cents":4800},{"name":"Pavé de Turbot à la Plancha, Purée de Céleri","price_cents":3800},{"name":"Bouillabaisse ’Petit Bateau'' Individuelle","price_cents":4200},{"name":"Filet de Bar Bio au Sel de Guérande","price_cents":3200},{"name":"Noix de Saint-Jacques Snackées, Risotto","price_cents":3500},{"name":"Brandade de Morue Fraîche à l’Huile d''Olive","price_cents":2800},{"name":"Thon Rouge en Tataki aux Sésames","price_cents":3000}]},{"category_type":"starter","display_label":"Préludes Marins (Entrées)","items":[{"name":"Soupe de Poissons de Roche et sa Rouille","price_cents":1800},{"name":"Huîtres Fines de Claire n°3 (les 6)","price_cents":1950},{"name":"Calamars à la Romaine, Sauce Tartare","price_cents":1600},{"name":"Saumon Fumé d’Écosse ’Maison’","price_cents":2200},{"name":"Carpaccio de Saint-Jacques au Citron Vert","price_cents":2400}]},{"category_type":"dessert","display_label":"Douceurs Classiques","items":[{"name":"Millefeuille à la Vanille de Tahiti","price_cents":1400},{"name":"Soufflé au Grand Marnier (Signé)","price_cents":1600},{"name":"Baba au Rhum Ambré et sa Crème Fouettée","price_cents":1200},{"name":"Sorbets Maison Fraîcheur du Jour","price_cents":1000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-bistrot-du-dome-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. La Sole Meunière et la Soupe de Poissons.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Bistrot du Dôme est le digne héritier du mythique restaurant Le Dôme, voisin et frère d’armes. Moins guindé mais tout aussi exigeant sur la qualité maritime, il offre un cadre élégant à la décoration nautique raffinée. La spécialité ici est sans conteste le poisson : arrivages quotidiens directs, cuissons millimétrées et saveurs iodées préservées. C’est l’endroit parfait pour déguster des huîtres d''exception ou une sole meunière légendaire dans une atmosphère de brasserie parisienne chic et feutrée.', 'La bouillabaisse est l’une des meilleures de la capitale, servie dans les règles de l’art. Pour le dessert, le millefeuille est une institution qu’il faut absolument avoir goûté une fois dans sa vie.', 'Vavin', '["4"]', '[]', 'ChIJQ0M91s5x5kcRIxMlRQkwoqU', NULL, 0);
INSERT INTO places_fts VALUES ('poi-bistrot-du-dome-75014', 'Le Bistrot du Dôme', 'restaurant', 'bistrot', '1 Rue Delambre, 75014 Paris, France', '', 'Le Bistrot du Dôme est le digne héritier du mythique restaurant Le Dôme, voisin et frère d’armes. Moins guindé mais tout aussi exigeant sur la qualité maritime, il offre un cadre élégant à la décoration nautique raffinée. La spécialité ici est sans conteste le poisson : arrivages quotidiens directs, cuissons millimétrées et saveurs iodées préservées. C’est l’endroit parfait pour déguster des huîtres d''exception ou une sole meunière légendaire dans une atmosphère de brasserie parisienne chic et feutrée.');
