CIEL"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":45,"is_free":false,"pint_price":0,"wine_glass":9,"coffee_price":3,"dish_price":27.5,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"Les Plats de Terroir","items":[{"name":"Bife de Lomo (Filet de bœuf, 250g)","price_cents":3800,"description":"Le summum de la tendreté argentine."},{"name":"Ojo de Bife (Noix d’entrecôte, 300g)","price_cents":3200},{"name":"Bife de Cuadril (Cœur de rumsteck)","price_cents":2600},{"name":"Bife de Chorizo (Faux-filet, 300g)","price_cents":2900},{"name":"Asado de Tira (Plat de côtes)","price_cents":2400},{"name":"Entraña (Hampe savoureuse)","price_cents":2500}]},{"category_type":"other","display_label":"Entradas (Tradition)","items":[{"name":"Empanadas de carne (les 2)","price_cents":1200,"description":"Faites maison selon la recette familiale."},{"name":"Mollejas de Ternera (Ris de veau grillés)","price_cents":1800},{"name":"Chorizo Argentino","price_cents":1000},{"name":"Morcilla (Boudin noir)","price_cents":950},{"name":"Provoleta au grill","price_cents":1100}]},{"category_type":"other","display_label":"Guarniciones & Postres","items":[{"name":"Papas Fritas a la provenzal (ail & persil)","price_cents":600},{"name":"Ensalada mixta","price_cents":700},{"name":"Panqueque con Dulce de Leche","price_cents":950},{"name":"Don Pedro (Glace vanille, whisky, noix)","price_cents":1100}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/les-grillades-de-buenos-aires/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine argentine. L’Asado de Tira et les Papas Fritas a la provenzal.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Une véritable ’estancia’ argentine au cœur de Montparnasse. Depuis plus de 20 ans, cet établissement fait figure de référence pour les amoureux de viande d’exception, exclusivement importée de la Pampa argentine. Dans un décor rustique et chaleureux peuplé de guitares et de souvenirs, les parrilladas sont orchestrées avec une précision chirurgicale, portées par les notes de tango qui flottent dans l''air.', 'Le ’Bife de Lomo’ est d’une tendreté légendaire, mais ne passez pas à côté des empanadas maison en entrée et demandez leur chimichurri spécial.', 'Montparnasse-Bienvenüe', '[4,6,12,13]', '[]', 'ChIJIVDDEcxx5kcRNdC36XGfaBA', NULL, 0);
INSERT INTO places_fts VALUES ('poi-grillades-buenos-aires', 'Les Grillades de Buenos Aires', 'restaurant', 'argentin', '54 Rue du Montparnasse', '', 'Une véritable ’estancia’ argentine au cœur de Montparnasse. Depuis plus de 20 ans, cet établissement fait figure de référence pour les amoureux de viande d’exception, exclusivement importée de la Pampa argentine. Dans un décor rustique et chaleureux peuplé de guitares et de souvenirs, les parrilladas sont orchestrées avec une précision chirurgicale, portées par les notes de tango qui flottent dans l''air.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-hanoi-quan', 'Hanoi Quan', 'hanoi-quan-montparnasse', 'restaurant', 'vietnamien', 'chill', 48.8348427, 2.319709, 14, '2 Place de Catalogne, 75014 Paris, France', '#8ccaf7', 'pin', 1, 4.7, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/hero.jpg', NULL, 13.9, 0, '€', NULL, NULL, NULL, NULL, 13.9, 50, '{"chill":70,"festif":30,"culturel":50}', '{}', '["restaurant","vietnamien","terrasse","ferme tard"]', '{"standard":"lundi: 11:00 – 00:00\nmardi: 11:00 – 00:00\nmercredi: 11:00 – 00:00\njeudi: 11:00 – 00:00\nvendredi: 11:00 – 00:00\nsamedi: 11:00 – 00:00\ndimanche: 11:00 – 00:00","display":"lundi: 11:00 – 00:00","detailed":"lundi: 11:00 – 00:00\nmardi: 11:00 – 00:00\nmercredi: 11:00 – 00:00\njeudi: 11:00 – 00:00\nvendredi: 11:00 – 00:00\nsamedi: 11:00 – 00:00\ndimanche: 11:00 – 00:00"}', '{"opening_hours_raw":"lundi: 11:00 – 00:00 | mardi: 11:00 – 00:00 | mercredi: 11:00 – 00:00 | jeudi: 11:00 – 00:00 | vendredi: 11:00 – 00:00 | samedi: 11:00 – 00:00 | dimanche: 11:00 – 00:00","reservation_policy":"sans_resa","terrace":true,"ferme_tard":true,"accessibility":true,"main_action":{"type":"site","url":"http://hanoiquan.fr/","label":"VOIR LA CARTE"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":18,"is_free":false,"last_updated":"2026-03-22","menu_items":[{"category_type":"starter","display_label":"Entrées & Snacks (Khai Vị)","items":[{"name":"Nems au Porc (x4)","price_cents":650,"description":"Croustillants et faits maison"},{"name":"Nems au Poulet (x4)","price_cents":650},{"name":"Rouleaux de Printemps (x2)","price_cents":600,"description":"Crevettes, porc, herbes fraîches"},{"name":"Salade de Mangue fraîche","price_cents":750,"description":"Épicée et acidulée"}]},{"category_type":"main","display_label":"Les Plats (Món Chính)","items":[{"name":"Phở Bœuf Ha Noi","price_cents":1350,"description":"Bouillon mijoté 12h, herbes"},{"name":"Phở Poulet","price_cents":1280},{"name":"Bo Bun Nem Porc & Bœuf","price_cents":1450,"description":"Le classique complet"},{"name":"Bo Bun Nem Poulet","price_cents":1450},{"name":"Bo Bun Nem Crevettes","price_cents":1550},{"name":"Bo Bun Végétarien","price_cents":1350},{"name":"Riz Bœuf à la citronnelle","price_cents":1450,"description":"Accompagné de salade mangue"},{"name":"Riz Poulet grillé","price_cents":1380},{"name":"Poké Bowl Saumon frais","price_cents":1400},{"name":"Poké Bowl Poulet Teriyaki","price_cents":1350}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Litchis au sirop","price_cents":550},{"name":"Boules Coco (x2)","price_cents":500,"description":"Cœur haricot mungo"},{"name":"Perles du Japon au lait de coco","price_cents":600}]}],"dish_price":13.9}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/hanoi-quan-montparnasse/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine vietnamienne. Phở Bœuf & Bo Bun Nem","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Trônant sur la Place de Catalogne, Hanoi Quan est une escale vietnamienne authentique qui réchauffe le quartier Montparnasse. Son bouillon Phở, mijoté pendant des heures, et ses Bo Bun généreux en font une adresse incontournable pour les amateurs de saveurs du Mékong. L’ambiance y est décontractée, idéale pour un shoot de fraîcheur avant de prendre un train.', '• Les Phở sont servis ici dans leur version la plus traditionnelle : n’hésitez pas à demander du piment frais supplémentaire pour un kick authentique.
INSERT INTO places_fts VALUES ('poi-hanoi-quan', 'Hanoi Quan', 'restaurant', 'vietnamien terrasse ferme tard', '2 Place de Catalogne, 75014 Paris, France', '', 'Trônant sur la Place de Catalogne, Hanoi Quan est une escale vietnamienne authentique qui réchauffe le quartier Montparnasse. Son bouillon Phở, mijoté pendant des heures, et ses Bo Bun généreux en font une adresse incontournable pour les amateurs de saveurs du Mékong. L’ambiance y est décontractée, idéale pour un shoot de fraîcheur avant de prendre un train.');
