"terrace":false,"accessibility":true,"main_action":{"type":"site","url":"http://www.restaurantleduc.com/","label":"SITE OFFICIEL"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":110,"is_free":false,"dish_price":55,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"L’Art des Poissons","items":[{"name":"Carpaccio de Bar au Citron Vert et Huile d’Olive","price_cents":4800},{"name":"Tartare de Bar ’Le Duc'' (Signé Minchelli)","price_cents":5200},{"name":"Sashimi de Thon Rouge d’Exception","price_cents":5500},{"name":"Dorade Royale Crue à la Fleur de Sel","price_cents":4600},{"name":"Sole Meunière Façon Le Duc (entière)","price_cents":8500},{"name":"Turbot Grillé aux Herbes (pour 2)","price_cents":18000},{"name":"Pâtes au Homard de Bretagne","price_cents":7500}]},{"category_type":"starter","display_label":"Entrées de la Mer","items":[{"name":"Huîtres Belon n°00 (les 6)","price_cents":3600},{"name":"Palourdes Farcies à la façon du chef","price_cents":2800},{"name":"Soupe de Poissons de Roche","price_cents":2400},{"name":"Salade de Homard Tiède","price_cents":6200},{"name":"Friture de Petits Poissons","price_cents":2200}]},{"category_type":"dessert","display_label":"Douceurs Classiques","items":[{"name":"Soufflé au Grand Marnier (Signé)","price_cents":2200},{"name":"Sorbet Citron Arrosé de Vodka","price_cents":1800},{"name":"Mille-Feuille à la Vanille de Tahiti","price_cents":2000},{"name":"Ardoise de Fromages de chez Cantin","price_cents":2400}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-duc-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine japonaise. Le Carpaccio de Bar et la Sole Meunière.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Duc est plus qu’un restaurant, c’est le lieu où a été inventé l’art de manger le poisson cru à Paris dans les années 60, bien avant la mode des sushis. Fondé par Jean Minchelli, ce temple de la mer conserve un décor intramontable de yacht luxueux des années 70, avec ses boiseries vernies et ses hublots. Ici, le produit est sacré : le poisson n’est jamais dénaturé, simplement sublimé par une découpe parfaite ou une cuisson à la seconde près. C’est l’adresse favorite du Paris littéraire et artistique qui cherche l’épure et l''exceptionnel.', 'Commencez impérativement par le carpaccio de bar, le plat qui a fait la légende du lieu. La carte des vins propose des Chablis et des Meursaults de collection qui sont les parfaits compagnons de ces assiettes iodées. Ambiance feutrée et très select.', 'Raspail', '["4","6"]', '[]', 'ChIJqXbHfMhx5kcRT_MHosKnfWw', NULL, 0);
INSERT INTO places_fts VALUES ('poi-le-duc-75014', 'Le Duc', 'restaurant', 'japonais', '243 Boulevard Raspail, 75014 Paris, France', '', 'Le Duc est plus qu’un restaurant, c’est le lieu où a été inventé l’art de manger le poisson cru à Paris dans les années 60, bien avant la mode des sushis. Fondé par Jean Minchelli, ce temple de la mer conserve un décor intramontable de yacht luxueux des années 70, avec ses boiseries vernies et ses hublots. Ici, le produit est sacré : le poisson n’est jamais dénaturé, simplement sublimé par une découpe parfaite ou une cuisson à la seconde près. C’est l’adresse favorite du Paris littéraire et artistique qui cherche l’épure et l''exceptionnel.');
