ccessibility":true,"main_action":{"type":"site","url":"https://www.lacantinedutroquet.com/#pernety","label":"SITE OFFICIEL"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":45,"is_free":false,"dish_price":24.5,"last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"Plats du Sud-Ouest","items":[{"name":"Couteaux à la Plancha, Ail et Persil","price_cents":1800},{"name":"Cochon de Lait Croustillant de chez Ospital","price_cents":2800},{"name":"Pavé de Thon Snacké, Pimientos de Padron","price_cents":2700},{"name":"Boudin Noir de Christian Parra, Purée","price_cents":2400},{"name":"Entrecôte Maturée, Frites Maison","price_cents":3400},{"name":"Tartare de Boeuf au Piment d’Espelette","price_cents":2500},{"name":"Épaule d’Agneau Confite (pour 2)","price_cents":7200},{"name":"Merlu de Ligne à l’Espagnole","price_cents":2600},{"name":"Poitrine de Veau rôtie au Romarin","price_cents":2900}]},{"category_type":"starter","display_label":"Entrées Canailles","items":[{"name":"Oeuf Cocotte au Jambon Ibaïama","price_cents":1400},{"name":"Terrine de Campagne Maison","price_cents":1100},{"name":"Os à Moelle à la Fleur de Sel","price_cents":1300},{"name":"Salade de Lentilles et Gésiers","price_cents":1250},{"name":"Croquettes de Cochon Maison","price_cents":1500},{"name":"Encornets sautés au Chorizo","price_cents":1700},{"name":"Asperges des Landes (en saison)","price_cents":1600}]},{"category_type":"main","display_label":"Plats de Fromages & Douceurs","items":[{"name":"Ossau-Iraty et sa Confiture de Cerises noires","price_cents":1200},{"name":"Gâteau Basque à la Crème de Christian","price_cents":1000},{"name":"Riz au Lait Onctueux au Caramel","price_cents":950},{"name":"Mousse au Chocolat pour les Gourmands","price_cents":1100},{"name":"Baba au Rhum Artisanal","price_cents":1200}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cantine-du-troquet-pernety-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. Le Cochon de Lait croustillant.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'La Cantine du Troquet Pernety est le navire amiral de Christian Etchebest dans le 14ème. C’est un lieu vibrant, bruyant, vivant, où l’on cultive l’art du bien-manger sans manières. La cuisine est celle du Sud-Ouest : franche, généreuse et techniquement impeccable. Les produits sont sourcés chez les meilleurs artisans (Ospital, Parra). On s’y installe sur de grandes tablées dans une ambiance de bistrot moderne très dynamique. C’est l''endroit rêvé pour une soirée conviviale où le partage et la bonne humeur sont les maîtres-mots.', 'Ici, on ne réserve pas, donc venez tôt ou profitez de l’ambiance au bar en attendant votre table. Les couteaux à la plancha sont absolument divins, une commande obligatoire dès votre arrivée.', 'Pernety', '["13"]', '[]', 'ChIJzYpmNUpw5kcR9shuTwHBx-4', NULL, 1);
INSERT INTO places_fts VALUES ('poi-cantine-troquet-pernety-75014', 'La Cantine du Troquet Pernety', 'restaurant', 'bistrot terrasse', '101 Rue de l’Ouest, 75014 Paris, France', '', 'La Cantine du Troquet Pernety est le navire amiral de Christian Etchebest dans le 14ème. C’est un lieu vibrant, bruyant, vivant, où l’on cultive l’art du bien-manger sans manières. La cuisine est celle du Sud-Ouest : franche, généreuse et techniquement impeccable. Les produits sont sourcés chez les meilleurs artisans (Ospital, Parra). On s’y installe sur de grandes tablées dans une ambiance de bistrot moderne très dynamique. C’est l''endroit rêvé pour une soirée conviviale où le partage et la bonne humeur sont les maîtres-mots.');
