te","url":"https://www.lesrestos.com/restaurant/paris/75014/la-cerisaie","label":"DÉCOUVRIR"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":42,"is_free":false,"dish_price":24,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Spécialités du Sud-Ouest Signées Cyril Lalanne","items":[{"name":"Cassoulet aux Haricots Tarbais (Le Vrai)","price_cents":2800,"description":"Mijoté longuement, la signature incontestée de la maison."},{"name":"Cochon Noir de Bigorre et Fèves de Printemps","price_cents":2600},{"name":"Pot au Feu de Canard et Cochon Noir (pour 2)","price_cents":5600},{"name":"Magret d’Oie des Landes, Polenta Crémeuse","price_cents":2450},{"name":"Cuisse de Canard Confite et Piperade Basque","price_cents":2200},{"name":"Manchon de Canard & Chorizo Confits","price_cents":2100},{"name":"Piquillos farcis à la morue, Bisque","price_cents":1800},{"name":"Chipirons Poêlés au Riz","price_cents":2400}]},{"category_type":"dessert","display_label":"Premières Saveurs & Fromages","items":[{"name":"Terrine de Foie Gras de Canard Maison","price_cents":1950},{"name":"Terrine de Porc Noir de Bigorre","price_cents":1200},{"name":"Bouillon de Canard aux Truffes Noires","price_cents":700},{"name":"Asperges des Landes au Citron Confit","price_cents":1450},{"name":"Fromage de Bethmale servi à la gelée de coing","price_cents":950},{"name":"Laguiole Affiné","price_cents":900}]},{"category_type":"dessert","display_label":"Douceurs des Pyrénées","items":[{"name":"Sablé Doré Fraise-Rhubarbe (Crumble)","price_cents":950},{"name":"Baba à l’Armagnac, Crème Fouettée Vanille","price_cents":1100},{"name":"Tarte Fondante au Chocolat Noir","price_cents":900},{"name":"Petit Pot de Crème Chocolat & Noisette","price_cents":850},{"name":"Glace au Roquefort (Pour audacieux)","price_cents":900}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-cerisaie-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Le Cassoulet aux Haricots Tarbais.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'La Cerisaie est l’un des secrets les mieux gardés (et les plus petits) de Montparnasse. Cyril Lalanne y officie avec une passion rare pour les produits de son Sud-Ouest natal. Dans une salle minuscule de 26 couverts où la proximité crée une convivialité immédiate, on déguste un cassoulet d’anthologie et des charcuteries de Porc Noir de Bigorre d’une qualité exceptionnelle. C’est une table de terroir pure, sans artifices, où chaque plat raconte une histoire de vignes et de montagnes. La réservation n’est pas une option, c''est une nécessité absolue pour goûter à cette cuisine de coeur.', 'Appelez au moins une semaine à l’avance pour le soir. Le menu ardoise change selon les arrivages du pays, mais le cassoulet est pratiquement toujours là. Ne partez pas sans avoir goûté au fromage de Bethmale.', 'Edgar Quinet', '["6"]', '[]', 'ChIJLRjIfsxx5kcRTKRS3UUvWVY', NULL, 0);
INSERT INTO places_fts VALUES ('poi-cerisaie-75014', 'La Cerisaie', 'restaurant', 'français', '70 Boulevard Edgar Quinet, 75014 Paris, France', '', 'La Cerisaie est l’un des secrets les mieux gardés (et les plus petits) de Montparnasse. Cyril Lalanne y officie avec une passion rare pour les produits de son Sud-Ouest natal. Dans une salle minuscule de 26 couverts où la proximité crée une convivialité immédiate, on déguste un cassoulet d’anthologie et des charcuteries de Porc Noir de Bigorre d’une qualité exceptionnelle. C’est une table de terroir pure, sans artifices, où chaque plat raconte une histoire de vignes et de montagnes. La réservation n’est pas une option, c''est une nécessité absolue pour goûter à cette cuisine de coeur.');
