happy_hour":null}', '{"avg_budget":35,"is_free":false,"pint_price":7.5,"wine_glass":6.5,"coffee_price":2.5,"dish_price":21.25,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"main","display_label":"Les Plats de Saison","items":[{"name":"Pavé de saumon rôti, purée de panais","price_cents":2400},{"name":"Risotto aux champignons & truffe","price_cents":2000},{"name":"Suprême de volaille fermière","price_cents":2250},{"name":"Burger de L’Entrepôt","price_cents":1950},{"name":"Tataki de bœuf au sésame","price_cents":2300},{"name":"Pennes à l’arrabbiata & burrata","price_cents":1850}]},{"category_type":"starter","display_label":"Entrées & Tapas","items":[{"name":"Os à moelle au sel de Guérande","price_cents":1200},{"name":"Salade d’écrevisses au pesto","price_cents":1450},{"name":"Burrata crémeuse","price_cents":1400},{"name":"Accras de morue (les 6 pièces)","price_cents":1000},{"name":"Planche de charcuterie ibérique","price_cents":1800}]},{"category_type":"dessert","display_label":"Desserts & Brunch","items":[{"name":"Tiramisu Nutella-Spéculoos","price_cents":950},{"name":"Mousse au chocolat noir 70%","price_cents":900},{"name":"Brunch Complet (Dimanche)","price_cents":3200}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-entrepot/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. L’os à moelle au sel de Guérande et le Tiramisu Nutella-Spéculoos.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Fondé en 1975 par Frédéric Mitterrand dans une ancienne imprimerie, L’Entrepôt est une véritable ’biosphère’ culturelle. Ce lieu hybride unique à Paris réunit trois salles de cinéma Art et Essai, une galerie d’exposition, une salle de concert jazz et un restaurant niché sous une vaste verrière. Un havre de paix artistique où l’on vient aussi bien pour un film indépendant que pour une cuisine de saison dégustée dans son jardin secret, loin du tumulte urbain.', 'Ne manquez pas les séances ’Ciné-Bébé’ pour les parents ou les concerts Lindy-Hop. La terrasse chauffée, sous serres en hiver, est un pur moment de magie toute l’année.', 'Pernety', '[13]', '[]', 'ChIJIwFfsktw5kcR7QCCSLLlDwY', NULL, 1);
INSERT INTO places_fts VALUES ('poi-entrepot', 'L’Entrepôt', 'restaurant', 'français terrasse', '7 Rue Francis de Pressensé', '', 'Fondé en 1975 par Frédéric Mitterrand dans une ancienne imprimerie, L’Entrepôt est une véritable ’biosphère’ culturelle. Ce lieu hybride unique à Paris réunit trois salles de cinéma Art et Essai, une galerie d’exposition, une salle de concert jazz et un restaurant niché sous une vaste verrière. Un havre de paix artistique où l’on vient aussi bien pour un film indépendant que pour une cuisine de saison dégustée dans son jardin secret, loin du tumulte urbain.');
