tion":{"type":"book","url":"https://www.papyauxfourneaux.fr/","label":"RÉSERVER UNE TABLE"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":35,"is_free":false,"dish_price":10,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"sharing","display_label":"Cocottes à Partager","items":[{"name":"Sauté de Veau à la Corse, Olives & Ail","price_cents":2190,"description":"Servi en cocotte de fonte au centre de la table."},{"name":"Paleron de 15h, Charolais du Bourbonnais","price_cents":2600},{"name":"Poisson du jour, Bisque de Crabe & Pastis","price_cents":2090},{"name":"Croustillants de Pont L’Evêque AOP & Miel","price_cents":1000},{"name":"Volaille de Vendée aux Pleurotes","price_cents":1950},{"name":"Potée de Jarret de Cochon Bio aux Lentilles","price_cents":2100},{"name":"Tartiflette de Légumes au Reblochon Fermier","price_cents":1950}]},{"category_type":"starter","display_label":"Entrées de Papy","items":[{"name":"Oeufs Bio ’Jolie Cocotte'' au Comté","price_cents":650},{"name":"Velouté de Carottes au Cumin & Raclette","price_cents":1000},{"name":"Assiette de Couteaux en Persillade","price_cents":850},{"name":"Velouté de Potimarron & Chips de Lard","price_cents":750},{"name":"Tranché de Galabar & Pomme Rôtie","price_cents":700},{"name":"Assiette de Fromages AOP (Comté 18 mois)","price_cents":800}]},{"category_type":"dessert","display_label":"Douceurs de Famille","items":[{"name":"Brioche Perdue au Caramel Beurre Salé","price_cents":950},{"name":"Tarte Bourdaloue à la Pistache","price_cents":990},{"name":"Crème Brûlée à la Fève de Tonka","price_cents":800},{"name":"Flan Pâtissier à la Vanille de Madagascar","price_cents":990},{"name":"Poires Pochées au Vin Rouge & Amandes","price_cents":700}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/papy-aux-fourneaux-paris/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. La Cocotte de Sauté de Veau et la Brioche Perdue.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Papy aux Fourneaux réinvente le concept de la table d’hôtes avec une modernité et une chaleur désarmantes. Ici, pas d’assiettes individuelles dressées au millimètre, mais de grandes cocottes en fonte posées au centre de la table, invitant au partage et à la gourmandise. La cuisine est une déclaration d’amour aux produits français, sourcés directement auprès de petits producteurs. Le décor, mêlant vintage et industriel, crée une atmosphère de salon familial où l’on prend le temps de vivre. C’est l’adresse ultime pour un repas entre amis ou en famille qui finit toujours par se prolonger autour d’un bon dessert maison.', 'Le restaurant fonctionne sur le principe de la cocotte unique par table, idéal à partir de deux personnes. Ne faites pas l’impasse sur la brioche perdue, c''est le doudou culinaire de la maison.', 'Pernety', '["13"]', '[]', 'ChIJFfkFjkpw5kcRVy2kmvlINzs', NULL, 0);
INSERT INTO places_fts VALUES ('poi-papy-aux-fourneaux-75014', 'Papy aux Fourneaux', 'restaurant', 'français', '70 Rue de l’Ouest, 75014 Paris, France', '', 'Papy aux Fourneaux réinvente le concept de la table d’hôtes avec une modernité et une chaleur désarmantes. Ici, pas d’assiettes individuelles dressées au millimètre, mais de grandes cocottes en fonte posées au centre de la table, invitant au partage et à la gourmandise. La cuisine est une déclaration d’amour aux produits français, sourcés directement auprès de petits producteurs. Le décor, mêlant vintage et industriel, crée une atmosphère de salon familial où l’on prend le temps de vivre. C’est l’adresse ultime pour un repas entre amis ou en famille qui finit toujours par se prolonger autour d’un bon dessert maison.');
