 PM | Sunday: 12:00 – 2:00 PM, 7:00 – 10:00 PM","reservation_policy":"resa_conseillee","terrace":false,"accessibility":true,"main_action":{"type":"site","url":"http://www.bistrotters.com/","label":"SITE OFFICIEL"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":40,"is_free":false,"dish_price":11.5,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"L’ardoise des Bistrotters","items":[{"name":"Cuisse de Canard Confite Maison","price_cents":2250},{"name":"Filet de Boeuf Aubrac, sauce poivre","price_cents":2800},{"name":"Dos de Cabillaud en croûte d’herbes","price_cents":2400},{"name":"Saucisse de Toulouse grillée et Aligot","price_cents":1950},{"name":"Poitrine de Veau rôtie aux petits oignons","price_cents":2400},{"name":"Tartare de Boeuf au couteau préparé","price_cents":2100},{"name":"Risso de Légumes de l’Ardoise","price_cents":1850}]},{"category_type":"starter","display_label":"Entrées Gourmandes","items":[{"name":"Os à Moelle Gratiné au Sel de Guérande","price_cents":1000},{"name":"Oeuf Cocotte au Maroilles (Pépite !)","price_cents":1150},{"name":"Ardoise de Charcuteries de pays","price_cents":1400},{"name":"Entrée du Marché (à l’ardoise)","price_cents":950},{"name":"Salade de Crottin de Chavignol chaud","price_cents":1200}]},{"category_type":"dessert","display_label":"Desserts de Tradition","items":[{"name":"Le fameux Riz au Lait de Bistrotters","price_cents":900},{"name":"Tatin Maison et Crème Fraîche","price_cents":1000},{"name":"Mousse au Chocolat Noir intense","price_cents":850},{"name":"Baba au Rhum du Chef","price_cents":1100},{"name":"Fromages de nos Provinces","price_cents":1200}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bistrotters-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de bistrot. Le Confit de Canard et le Riz au Lait.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Bistrotters est l’une de ces pépites parisiennes que l’on voudrait garder pour soi. Situé dans la tranquille rue Decrès, ce restaurant incarne le bistrot moderne dans ce qu’il a de plus noble : une cuisine de terroir généreuse, un accueil d’une gentillesse rare et une atmosphère chaleureuse faite de bois et de sourires. Tout ici est fait maison, de la terrine au dessert, avec un respect sacré du produit. C’est l’adresse idéale pour redécouvrir le plaisir simple d’un plat parfaitement mijoté dans un cadre authentique.', 'Goutez absolument à leur riz au lait, une légende locale qui vaut le détour à elle seule. L’ambiance le samedi soir est particulièrement conviviale, pensez à réserver car le lieu est petit.', 'Pernety', '["13"]', '[]', 'ChIJUWpN50tw5kcRxFHi8fOzbi4', NULL, 0);
INSERT INTO places_fts VALUES ('poi-bistrotters-75014', 'Bistrotters', 'restaurant', 'bistrot', '9 Rue Decrès, 75014 Paris, France', '', 'Bistrotters est l’une de ces pépites parisiennes que l’on voudrait garder pour soi. Situé dans la tranquille rue Decrès, ce restaurant incarne le bistrot moderne dans ce qu’il a de plus noble : une cuisine de terroir généreuse, un accueil d’une gentillesse rare et une atmosphère chaleureuse faite de bois et de sourires. Tout ici est fait maison, de la terrine au dessert, avec un respect sacré du produit. C’est l’adresse idéale pour redécouvrir le plaisir simple d’un plat parfaitement mijoté dans un cadre authentique.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-chez-alphonse-75014', 'Chez Alphonse', 'chez-alphonse-paris-14', 'restaurant', 'bistro, traditionnel, terrasse, fait-maison, ardoise, convivial', 'chill', 48.826872, 2.327089, 14, '16 Rue Alphonse Daudet', '#8ccaf7', 'pin', 1, 4.6, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/hero.jpg', 'restaurantchezalphonse', 23, 0, '€', NULL, NULL, NULL, NULL, 23, 50, '{"chill":70,"festif":35,"culturel":20}', '{}', '["restaurant","bistro","traditionnel","terrasse","fait-maison","ardoise","convivial","terrasse"]', '{"standard":"Lundi au Vendredi: 08:00–00:00\nSamedi et Dimanche: 09:00–00:00","display":"Lundi au Vendredi: 08:00–00:00","detailed":"Lundi au Vendredi: 08:00–00:00\nSamedi et Dimanche: 09:00–00:00"}', '{"reservation_policy":"resa_conseillee","accessibility":true,"terrace":true,"opening_hours_raw":"Lundi au Vendredi: 08:00–00:00\nSamedi et Dimanche: 09:00–00:00","main_action":{"type":"book","url":"https://www.thefork.fr/restaurant/chez-alphonse-r482015","label":"RÉSERVER SUR THEFORK"},"menu_url":"https://www.chez-alphonse.fr/","terrasse":true,"viande_exception":false,"happy_hour":null}', '{"avg_budget":31,"is_free":false,"dish_price":23,"smart_tip":"Menu Ardoise imbattable (31€). Les portions sont généreuses, idéal pour un gros appétit de quartier.","menu_items":[{"category_type":"starter","display_label":"Entrées (Saison)","items":[{"name":"Oeuf poché bio aux poireaux vinaigrette","price_cents":900},{"name":"Ravioles deux fromages, crème truffée","price_cents":900},{"name":"Beignets de crevettes maison","price_cents":1400},{"name":"Velouté de potimarron & châtaignes","price_cents":900}]},{"category_type":"main","display_label":"Les Plats","items":[{"name":"Cuisse de canard confite, écrasé de PDT","price_cents":1900,"description":"La spécialité maison, fondante à souhait."},{"name":"Araignée de boeuf, sauce poivre vert","price_cents":2600},{"name":"Lieu jaune poêlé, jus Arqua Pazza","price_cents":1800},{"name":"Noix de quasi de veau, jus corsé","price_cents":2300},{"name":"Cabillaud rôti, petits légumes du moment","price_cents":2300}]},{"category_type":"dessert","display_label":"Desserts & Fromages","items":[{"name":"Cheesecake léger, glace yaourt","price_cents":900},{"name":"Tiramisu traditionnel au café","price_cents":900},{"name":"Mi-cuit chocolat noir pur origine","price_cents":900},{"name":"Assiette de fromages affinés du 14e","price_cents":900}]}],"last_updated":"2026-03-03"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/chez-alphonse-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Bistro. Chez Alphonse.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Niché rue Alphonse Daudet, Chez Alphonse est l’archétype du néo-bistrot de quartier réussi. Le lieu marie avec élégance des cloisons modernes, de confortables banquettes et de grandes tablées boisées sous une belle hauteur de plafond. Ici, la cuisine française traditionnelle est exécutée avec la précision d’un restaurant gastronomique mais servie avec la générosité d’une brasserie. Le sourcing est au cœur de l’assiette, privilégiant les circuits courts et les produits d’artisans. C’est une valeur sûre, aussi bien pour un déjeuner rapide que pour un dîner épicurien, portée par une équipe d’une efficacité redoutable.', '• La formule Ardoise à 31€ est l’une des meilleures affaires du quartier Alésia.
INSERT INTO places_fts VALUES ('poi-chez-alphonse-75014', 'Chez Alphonse', 'restaurant', 'bistro traditionnel terrasse fait-maison ardoise convivial terrasse', '16 Rue Alphonse Daudet', '', 'Niché rue Alphonse Daudet, Chez Alphonse est l’archétype du néo-bistrot de quartier réussi. Le lieu marie avec élégance des cloisons modernes, de confortables banquettes et de grandes tablées boisées sous une belle hauteur de plafond. Ici, la cuisine française traditionnelle est exécutée avec la précision d’un restaurant gastronomique mais servie avec la générosité d’une brasserie. Le sourcing est au cœur de l’assiette, privilégiant les circuits courts et les produits d’artisans. C’est une valeur sûre, aussi bien pour un déjeuner rapide que pour un dîner épicurien, portée par une équipe d’une efficacité redoutable.');
