","url":"https://restaurant-lassiette.paris/","label":"SITE OFFICIEL"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":65,"is_free":false,"dish_price":21.5,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"Les Incontournables de David Rathgeber","items":[{"name":"Cassoulet Artisanal de L’Assiette","price_cents":3800,"description":"Confit de canard, saucisse de Toulouse, couenne et haricots lingots."},{"name":"Ris de Veau Doré au Sutoir","price_cents":5200},{"name":"Andouillette AAAAA de chez Duval","price_cents":3200},{"name":"Parmentier de Queue de Boeuf","price_cents":3400},{"name":"Poitrine de Cochon Fondante","price_cents":2900},{"name":"Dos de Cabillaud Cuisson Basse Température","price_cents":3600},{"name":"Épaule d’Agneau de Lait (pour 2)","price_cents":9500}]},{"category_type":"starter","display_label":"Entrées de Saison","items":[{"name":"Bouillon de Poule à la Truffe","price_cents":1800},{"name":"Calamars à la Plancha, Chorizo","price_cents":2200},{"name":"Foie Gras Chantilly de David","price_cents":2400},{"name":"Asperges Vertes de Provence (en saison)","price_cents":2100},{"name":"Escargots de Bourgogne en Coquille (les 6)","price_cents":1800},{"name":"Pâté en Croûte Maison","price_cents":2600}]},{"category_type":"dessert","display_label":"Desserts & Gourmandises","items":[{"name":"Crème Caramel à la Vanille de Tahiti","price_cents":1200},{"name":"Tarte Tatin Géante","price_cents":1450},{"name":"Paris-Brest Signature","price_cents":1500},{"name":"Mousse au Chocolat Noir intense","price_cents":1300},{"name":"Assiette de Fromages de chez Sanders","price_cents":1800}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-assiette-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Le Cassoulet Maison et le Ris de Veau.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'L’Assiette est une institution mythique de la rue du Château, où David Rathgeber (ancien d’Alain Ducasse) perpétue l’excellence d’une cuisine de terroir haute couture. Le décor est celui d’une ancienne charcuterie fine, avec ses plafonds peints et ses miroirs piqués, offrant une atmosphère d’un chic absolu et d’un confort bourgeois. On y vient pour le meilleur Cassoulet de Paris, mais aussi pour des plats canailles élevés au rang d’oeuvres d’art. C’est le rendez-vous des gourmets qui cherchent la vérité du produit et la générosité d’un chef passionné.', 'Le cassoulet est la signature qu’il faut avoir goûtée au moins une fois dans sa vie, mais gardez une place pour le Paris-Brest, l''un des plus fins de la capitale. La carte des vins, axée sur les vignerons indépendants, est une merveille.', 'Mouton-Duvernet', '["4"]', '[]', 'ChIJkc5OT7Rx5kcRJx30EIJaxvM', NULL, 0);
INSERT INTO places_fts VALUES ('poi-lassiette-75014', 'L’Assiette', 'restaurant', 'français bistronomie', '181 Rue du Château, 75014 Paris, France', '', 'L’Assiette est une institution mythique de la rue du Château, où David Rathgeber (ancien d’Alain Ducasse) perpétue l’excellence d’une cuisine de terroir haute couture. Le décor est celui d’une ancienne charcuterie fine, avec ses plafonds peints et ses miroirs piqués, offrant une atmosphère d’un chic absolu et d’un confort bourgeois. On y vient pour le meilleur Cassoulet de Paris, mais aussi pour des plats canailles élevés au rang d’oeuvres d’art. C’est le rendez-vous des gourmets qui cherchent la vérité du produit et la générosité d’un chef passionné.');
