ice":0,"wine_glass":8,"coffee_price":2.5,"dish_price":10,"menu_type":"fixed","last_updated":"2026-03-10","menu_items":[{"category_type":"tasting_menu","display_label":"Menus du Moment (Standard Industriel)","items":[{"name":"Menu MIDI (Entrée + Plat + Dessert)","price_cents":3500},{"name":"Menu MIDI (Entrée + Plat)","price_cents":3400,"description":"L’option déjeuner standard."},{"name":"Menu SOIR (Entrée + Plat + Dessert)","price_cents":4200},{"name":"Menu SOIR (Entrée + Plat)","price_cents":4100}]},{"category_type":"main","display_label":"Exemples de Plats (Selon Arrivage)","items":[{"name":"Épaule de porc de 12h, purée de panais","price_cents":0},{"name":"Cabillaud nacré, émulsion de coquillages","price_cents":0},{"name":"Poitrine de cochon croustillante","price_cents":0},{"name":"Velouté de potiron & châtaignes","price_cents":0},{"name":"Carpaccio de Saint-Jacques","price_cents":0},{"name":"Chou craquelin vanille Bourbon","price_cents":0}]},{"category_type":"sharing","display_label":"À Partager (Apéritif)","items":[{"name":"Petites sardines à l’huile d''olive artisanales","price_cents":1000},{"name":"Socca minute croustillante à la fleur de sel","price_cents":700},{"name":"½ Fuet Catalan artisanal","price_cents":1000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-cornichon-paris-14/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. L’épaule de porc fondante et le chou croustillant vanille bourbon.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le Cornichon est l’un des néo-bistrots les plus accomplis du 14ème, régulièrement salué par le guide Michelin d’un Bib Gourmand. La cuisine y est franche, technique et d’une grande finesse, privilégiant les circuits ultra-courts et le respect des saisons. Le cadre est sobre et moderne, mettant toute la lumière sur l’assiette. C’est l’archétype du restaurant où l’on revient pour la justesse des cuissons et l''originalité des sauces.', 'Les formules déjeuner sont d’un rapport qualité-prix exceptionnel pour ce niveau de technicité. La socca croustillante en apéritif est un petit bonheur simple à ne pas négliger.', 'Denfert-Rochereau', '[4,6]', '[]', 'ChIJi994frZx5kcRKNYXb8J4sEg', NULL, 0);
INSERT INTO places_fts VALUES ('poi-le-cornichon', 'Le Cornichon', 'restaurant', 'français', '34 Rue Gassendi, 75014 Paris', '', 'Le Cornichon est l’un des néo-bistrots les plus accomplis du 14ème, régulièrement salué par le guide Michelin d’un Bib Gourmand. La cuisine y est franche, technique et d’une grande finesse, privilégiant les circuits ultra-courts et le respect des saisons. Le cadre est sobre et moderne, mettant toute la lumière sur l’assiette. C’est l’archétype du restaurant où l’on revient pour la justesse des cuissons et l''originalité des sauces.');
