false,"happy_hour":null}', '{"avg_budget":65,"is_free":false,"dish_price":32,"menu_type":"standard","last_updated":"2026-03-10","menu_items":[{"category_type":"other","display_label":"L’Écailler de la Rotonde","items":[{"name":"Plateau La Rotonde (pour 2 personnes)","price_cents":9800},{"name":"Assiette du Mareyeur","price_cents":4200},{"name":"Huîtres Marennes d’Oléron N°3 (les 6)","price_cents":2400},{"name":"Tourteau frais entier","price_cents":3200},{"name":"Langoustines de casier (les 5)","price_cents":3600},{"name":"Bulots et Crevettes roses","price_cents":2100}]},{"category_type":"other","display_label":"Les Grands Classiques","items":[{"name":"Foie Gras de Canard Maison","price_cents":2600},{"name":"Soupe à l’Oignon Gratinée","price_cents":1450},{"name":"Sole de Petit Bateau Meunière","price_cents":5400},{"name":"Côte de Boeuf (env. 1kg pour 2)","price_cents":11500},{"name":"Confit de Canard et Pommes Sarladaises","price_cents":2800},{"name":"Tartare de Boeuf Charolais au couteau","price_cents":2650},{"name":"Magret de Canard au Miel et Epices","price_cents":3400},{"name":"Blanquette de Veau à l’ancienne","price_cents":3200},{"name":"Filet de Bar grillé, légumes de saison","price_cents":3800},{"name":"Ravioles de Royans crème de parmesan","price_cents":2400}]},{"category_type":"dessert","display_label":"Douceurs de la Rive Gauche","items":[{"name":"Profiteroles Classiques de La Rotonde","price_cents":1450},{"name":"Ile Flottante aux Pralines Roses","price_cents":1200},{"name":"Tarte Tatin et Crème Fraîche","price_cents":1350},{"name":"Baba au Rhum Géant","price_cents":1500},{"name":"Mousse au Chocolat à discrétion","price_cents":1250}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-rotonde-montparnasse/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de brasserie. Le Plateau Royal de l’Écailler.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Avec son auvent rouge flamboyant et ses éclairages d’or, La Rotonde est le phare de Montparnasse. Temple de l’art de vivre parisien depuis 1911, elle fut le quartier général de Picasso, Modigliani et Apollinaire. Aujourd’hui, elle incarne la brasserie d’exception où le service en tablier blanc et la nappe immaculée sont de rigueur. On y vient aussi bien pour ses plateaux de fruits de mer vertigineux que pour ses classiques de la gastronomie bourgeoise, servis dans un décor resté fidèle à sa légende. C’est le lieu idéal pour observer le ballet parisien depuis sa terrasse mythique ou pour un dîner feutré dans les salons chargés d''histoire.', 'Bien que très courue, La Rotonde garde toujours quelques tables pour les habitués au bar. Pour un moment plus calme, préférez le salon à l’étage. N''oubliez pas de goûter aux fruits de mer froids, leur arrivage est quotidien.', 'Vavin', '["4"]', '[]', 'ChIJUUTr285x5kcR-hIAm6NjUHY', NULL, 1);
INSERT INTO places_fts VALUES ('poi-rotonde-montparnasse', 'La Rotonde Montparnasse', 'restaurant', 'français terrasse terrasse', '105 Boulevard du Montparnasse, 75006 Paris, France', '', 'Avec son auvent rouge flamboyant et ses éclairages d’or, La Rotonde est le phare de Montparnasse. Temple de l’art de vivre parisien depuis 1911, elle fut le quartier général de Picasso, Modigliani et Apollinaire. Aujourd’hui, elle incarne la brasserie d’exception où le service en tablier blanc et la nappe immaculée sont de rigueur. On y vient aussi bien pour ses plateaux de fruits de mer vertigineux que pour ses classiques de la gastronomie bourgeoise, servis dans un décor resté fidèle à sa légende. C’est le lieu idéal pour observer le ballet parisien depuis sa terrasse mythique ou pour un dîner feutré dans les salons chargés d''histoire.');
