a résa.
INSERT INTO places_fts VALUES ('poi-l-accolade', 'L’Accolade', 'restaurant', 'bistronomie français terrasse', '208 Rue de la Croix Nivert, 75015 Paris, France', '', 'À un jet de pierre de la rue du Commerce se cache L’Accolade, une pépite bistronomique de quartier pilotée par le chef Nicolas Tardivel (ancien prof de sport reconverti). Dans une salle minimaliste et chaleureuse, le ton est donné : menu resserré, produits ultra-frais sourcés à Rungis et carte qui valse au rythme des saisons. Sans frou-frou mais avec une précision chirurgicale, les assiettes racontent l’amour du terroir français bousculé par de discrètes fulgurances (ail noir, yuzu, miso). Une adresse intimiste que les habitants du 15ème se murmurent à l''oreille.');
