ande_exception":false,"happy_hour":null}', '{"certification":"silver","avg_budget":45,"is_free":false,"last_updated":"2026-03-29","verified_at":"2026-03-29","menu_items":[{"category_type":"starter","display_label":"Nos Entrées","items":[{"name":"Le fameux Os à Moelle","price_cents":1200,"description":"Rôti à la fleur de sel de Guérande, pain grillé","is_highlight":true},{"name":"Terrine de Campagne Maison","price_cents":900,"description":"Cornichons et confiture d’oignons"},{"name":"Poireaux Vinaigrette Revisités","price_cents":800,"description":"Œuf mollet, croûtons dorés"},{"name":"Foie Gras de Canard Mi-Cuit","price_cents":1600,"description":"Chutney de saison, brioche toastée","is_highlight":true},{"name":"Gaspacho Andalou","price_cents":800,"description":"Légumes d’été frais et croquants"}]},{"category_type":"main","display_label":"Les Plats de Résistance","items":[{"name":"Caille Rôtie","price_cents":2400,"description":"Jus corsé, purée de pommes de terre","is_highlight":true},{"name":"Pièce de Bœuf (selon arrivage)","price_cents":2800,"description":"Frites maison et sauce au poivre"},{"name":"Ris de Veau Croustillants","price_cents":3200,"description":"Poêlée de champignons de saison","is_highlight":true},{"name":"Cabillaud Nacré","price_cents":2500,"description":"Légumes primeurs, beurre blanc"},{"name":"Tartare de Bœuf Tradition","price_cents":1900,"description":"Préparé au couteau, frites"}]},{"category_type":"dessert","display_label":"Les Desserts Douceur","items":[{"name":"Gros Baba au Rhum","price_cents":1000,"description":"Crème montée à la vanille, rhum arrangé","is_highlight":true},{"name":"Mousse au Chocolat Noir","price_cents":800,"description":"Éclats de noisettes torréfiées"},{"name":"Crème Brûlée","price_cents":800,"description":"Vanille de Madagascar"},{"name":"Trio de Fromages Affinés","price_cents":1100,"description":"Sélection du fromager, pain aux noix"}]},{"category_type":"tasting_menu","display_label":"Les Formules","items":[{"name":"Le Menu Dégustation","price_cents":4500,"description":"Le grand voyage en 6 services selon l’humeur du Chef","is_highlight":true},{"name":"Formule Midi (Semaine)","price_cents":2400,"description":"Entrée + Plat ou Plat + Dessert"}]},{"category_type":"drink","display_label":"Pour la Soif","items":[{"name":"Verre de Vin Blanc (Chardonnay)","price_cents":600},{"name":"Verre de Vin Rouge (Brouilly)","price_cents":650},{"name":"Bières Pression","price_cents":450},{"name":"Café Espresso","price_cents":250}]}],"dish_price":25}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-os-a-moelle/gallery_4.jpg"]', NULL, '{"text":"Un monument pour les viandards et les amateurs de la bistronomie de Thierry Faucher. Convivialité XXL garantie avec des plats aussi généreux d’esprit que d’assiette.","must_eat":"Cuisine de bistrot. Leur légendaire Os à Moelle au sel de Guérande, immanquable.","le_secret":"La formule déjeuner en semaine donne un super aperçu de cette maîtrise classique.","le_son":"Le brouhaha joyeux typique des bons bistrots vitaux.","le_must":"Prendre le menu en 6 temps, s''asseoir et se laisser dicter le repas par le patron."}', 'Institution incontournable du 15ème arrondissement, L’Os à Moelle est le fleuron de la bistronomie de quartier imaginé par le chef Thierry Faucher. L’ambiance y est chaleureuse au milieu des grandes tablées et des murs patinés. On y célèbre le véritable terroir français, sans chichi mais avec une justesse technique irréprochable, avec en vedette des plats mythiques de viande et d''abats mijotés.', '• **L’Anexe d’en face** : S’il n’y a plus de place, traversez la rue pour découvrir "La Cave de l’Os à Moelle", qui propose une formule buffet exceptionnelle et sans fioritures dans les mêmes cuisines.
INSERT INTO places_fts VALUES ('poi-l-os-a-moelle', 'L’Os à moelle', 'restaurant', 'français terrasse', '3 Rue Vasco de Gama, 75015 Paris, France', '', 'Institution incontournable du 15ème arrondissement, L’Os à Moelle est le fleuron de la bistronomie de quartier imaginé par le chef Thierry Faucher. L’ambiance y est chaleureuse au milieu des grandes tablées et des murs patinés. On y célèbre le véritable terroir français, sans chichi mais avec une justesse technique irréprochable, avec en vedette des plats mythiques de viande et d''abats mijotés.');
