rkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-troquet/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Français. Le Troquet.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Une authentique pépite du 15ème arrondissement où l’âme bistrotier croise le Sud-Ouest avec panache. Avec ses nappes à carreaux vichy rouge et son zinc patiné, le Troquet de Marc Lèze respecte un dogme absolu : la glorification du gras, du bonbon de viande et du jus corsé. La côte de bœuf pour deux y est majestueuse, et le ris de veau fait pleurer les puristes. Le bruit des fourchettes résonne, les verres trinquent, c’est l''anti-fast-food par excellence.', '• **Dîner Canaille** : Ne manquez surtout pas le menu complet à 48€, dont le rapport qualité-prix-satiété est quasi imbattable à Paris.
INSERT INTO places_fts VALUES ('poi-le-troquet', 'Le Troquet', 'restaurant', 'français terrasse', '21 Rue François Bonvin, 75015 Paris, France', '', 'Une authentique pépite du 15ème arrondissement où l’âme bistrotier croise le Sud-Ouest avec panache. Avec ses nappes à carreaux vichy rouge et son zinc patiné, le Troquet de Marc Lèze respecte un dogme absolu : la glorification du gras, du bonbon de viande et du jus corsé. La côte de bœuf pour deux y est majestueuse, et le ris de veau fait pleurer les puristes. Le bruit des fourchettes résonne, les verres trinquent, c’est l''anti-fast-food par excellence.');
