INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-alkaram-75015', 'AlKaram', 'alkaram-paris-15', 'restaurant', 'libanais, moyen-orient, mezzes, grillades, fait-maison, traiteur', 'chill', 48.8384506, 2.2971176, 15, '15 Rue Ferdinand Fabre, 75015 Paris', '#8ccaf7', 'pin', 1, 4.8, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/hero.jpg', NULL, 18, 0, '€', 6, 9, 8, 2.6, 18, 50, '{"chill":80,"festif":20,"culturel":40}', '{}', '["restaurant","libanais","moyen-orient","mezzes","grillades","fait-maison","traiteur"]', '{"standard":"Mardi-Samedi: 12:00-14:30, 19:00-23:00\nDimanche-Lundi: Fermé","display":"Mardi-Samedi: 12:00-14:30, 19:00-23:00","detailed":"Mardi-Samedi: 12:00-14:30, 19:00-23:00\nDimanche-Lundi: Fermé"}', '{"reservation_policy":"resa_conseillee","accessibility":true,"terrace":false,"opening_hours_raw":"Mardi-Samedi: 12:00-14:30, 19:00-23:00\nDimanche-Lundi: Fermé","main_action":{"type":"site","url":"http://www.restaurant-alkaram.fr/","label":"SITE OFFICIEL"},"menu_url":"http://www.restaurant-alkaram.fr/la-carte/","terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"dish_price":18,"force_manual_dish_price":true,"pint_price":6,"cocktail_price":9,"wine_glass":8,"coffee_price":2.6,"soft_price":5,"smart_tip":"L’option sandwich/emporter (Chawarma à 7,50€) est imbattable pour le déjeuner. Sur place, la moyenne par personne avec mezzés tourne autour de 25€.","menu_items":[{"category_type":"other","display_label":"Mezzés Froids","items":[{"name":"Hommos Classique","price_cents":800,"description":"Purée de pois chiches à la crème de sésame."},{"name":"Hommos Beyrouti","price_cents":900,"description":"Version relevée avec ail et persil."},{"name":"Hommos Viande","price_cents":1050,"description":"Relevé avec des émincés de viande poêlés."},{"name":"Moutabal (Caviar d’aubergine)","price_cents":800,"description":"Aubergine grillée, crème de sésame."},{"name":"Taboulé Libanais","price_cents":800,"description":"Persil, blé concassé, tomate, menthe, oignon, citron."}]},{"category_type":"other","display_label":"Mezzés Chauds","items":[{"name":"Falafels (4 pièces)","price_cents":840,"description":"Boulettes frites de fèves et pois chiches."},{"name":"Kebbé Boulettes (4 pièces)","price_cents":840,"description":"Viande farcie au bourghoul et pignons de pin."}]},{"category_type":"other","display_label":"Grillades & Assiettes","items":[{"name":"Chawarma (Bœuf mariné)","price_cents":2500,"description":"Sur place. Viande de bœuf mariné, émincé et grillé."},{"name":"Chiche Taouk (Poulet mariné)","price_cents":2350},{"name":"Sandwich Chawarma (Emporter)","price_cents":750}]},{"category_type":"drink","display_label":"Boissons & Vins","items":[{"name":"Verre de Vin Ksara Libanais","price_cents":800},{"name":"Arak (Boisson libanaise anisée 8cl)","price_cents":700},{"name":"Bière Libanaise (33cl)","price_cents":600},{"name":"Laban Ayran (Yaourt liquide salé)","price_cents":600},{"name":"Café Expresso","price_cents":260},{"name":"Café Blanc (Eau de fleur d’oranger)","price_cents":380}]}],"last_updated":"2026-03-04"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/alkaram-paris-15/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Libanais. AlKaram.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Situé rue Ferdinand Fabre, AlKaram s’impose discrètement comme l’une des tables libanaises les plus fiables du 15ème arrondissement. Oubliez les concepts standardisés : l’endroit mise sur une véritable authenticité culinaire où tout est fait maison, de l’onctuosité de l’houmous aux viandes marinées avec précision. Le cadre est pensé pour être chaleureux et immersif, soutenu par un fond musical toujours juste – assez présent pour donner la texture d’un voyage au Levant, mais parfaitement dosé pour préserver l’intimité des tables.', '• Garez vos a priori sur les portions : les mezzés sont très copieux, laissez le service vous guider sur les quantités, ils sont de très bon conseil pour éviter le suremballage.
INSERT INTO places_fts VALUES ('poi-alkaram-75015', 'AlKaram', 'restaurant', 'libanais moyen-orient mezzes grillades fait-maison traiteur', '15 Rue Ferdinand Fabre, 75015 Paris', '', 'Situé rue Ferdinand Fabre, AlKaram s’impose discrètement comme l’une des tables libanaises les plus fiables du 15ème arrondissement. Oubliez les concepts standardisés : l’endroit mise sur une véritable authenticité culinaire où tout est fait maison, de l’onctuosité de l’houmous aux viandes marinées avec précision. Le cadre est pensé pour être chaleureux et immersif, soutenu par un fond musical toujours juste – assez présent pour donner la texture d’un voyage au Levant, mais parfaitement dosé pour préserver l’intimité des tables.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-lintrigue-75015', 'L’Intrigue', 'lintrigue-paris-15', 'restaurant', 'bar, brasserie, bar-a-cocktails, brunch, terrasse, fait-maison, happy-hour', 'festif', 48.8428398, 2.291778, 15, '24 Pl. Etienne Pernet, 75015 Paris', '#ffab60', 'pin', 1, 4.6, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/hero.jpg', 'lintrigueparis15', 19.45, 0, '€', 7.5, 12, 5, 2.6, 19.45, 50, '{"chill":65,"festif":75,"culturel":10}', '{}', '["restaurant","bar","brasserie","bar-a-cocktails","brunch","terrasse","fait-maison","happy-hour","terrasse"]', '{"standard":"Lundi-Dimanche: 07:00-00:00","display":"Lundi-Dimanche: 07:00-00:00","detailed":"Lundi-Dimanche: 07:00-00:00"}', '{"reservation_policy":"resa_conseillee","accessibility":true,"terrace":true,"opening_hours_raw":"Lundi-Dimanche: 07:00-00:00","main_action":{"type":"site","url":"http://www.lintrigueparis.fr/","label":"SITE OFFICIEL"},"menu_url":"http://www.lintrigueparis.fr/la-carte/","terrasse":true,"viande_exception":false,"happy_hour":"16h-20h"}', '{"is_free":false,"avg_budget":2,"dish_price":19.45,"cocktail_price":12,"pint_price":9,"hh_pint":7.5,"hh_time":"16h-20h","wine_glass":5,"coffee_price":2.6,"planche_price":20,"smart_tip":"Le ’Happy Hour’ (16h-20h) fait chuter la pinte d’IPA à 7,50€. Pour les familles, le brunch dominical à 32€ (15€ pour les enfants) est un excellent calcul sur la Place Étienne Pernet.","menu_items":[{"category_type":"other","display_label":"La Partie Bar & Mixologie","items":[{"name":"Cocktail Mimosa","price_cents":1200,"description":"Champagne et jus d’orange frais."},{"name":"Bissapolitain Maison","price_cents":1200,"description":"Création signature à base de fleurs d’hibiscus."},{"name":"Bellini Passion","price_cents":1200},{"name":"Verre de Chardonnay / Pinot Noir","price_cents":500,"description":"Sélection 12cl."},{"name":"Tequila Volcan De Mi Tierra","price_cents":1200},{"name":"Pinte IPA (Happy Hour)","price_cents":750}]},{"category_type":"main","display_label":"La Partie Brasserie & Plats","items":[{"name":"Burger de L’Intrigue","price_cents":1790,"description":"Classic simple. Double à 22,90€."},{"name":"Confit de Canard","price_cents":1970,"description":"Servi avec pommes de terre grenailles."},{"name":"Filet de Bar à la plancha","price_cents":2170},{"name":"Pavé de Veau","price_cents":2190},{"name":"Poke Bowl","price_cents":1920},{"name":"Planche Mixte (Charcuterie/Fromage)","price_cents":2000},{"name":"Tataki de Thon","price_cents":1200,"description":"Entrée signature."},{"name":"Oeuf Cocotte truffé","price_cents":950}]},{"category_type":"dessert","display_label":"Desserts Artisans","items":[{"name":"Paris-Brest de L’Intrigue","price_cents":1080},{"name":"Nems au Chocolat","price_cents":950},{"name":"Tiramisu Maison","price_cents":950}]}],"last_updated":"2026-03-04"}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/lintrigue-paris-15/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Bar. L’Intrigue.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'L’Intrigue est le pivot social de la Place Étienne Pernet. Cette brasserie moderne a réussi le pari de l’hybridation : café de quartier dès 7h du matin, table bistronomique pour le déjeuner, et bar de nuit chaleureux aux cocktails précis. Le décor, feutré et boisé, tranche avec les établissements plus froids du quartier Félix Faure. Le ’Fait Maison’ y est une règle stricte, appliquée aussi bien aux pâtisseries qu’aux jus de fruits du bar, faisant de l''endroit une valeur refuge constante, particulièrement pour ses brunchs saisonniers très prisés.', '• Ne vous laissez pas surprendre par l’efficacité du service : la cuisine envoie très vite, demandez explicitement de temporiser si vous voulez profiter de votre apéritif en terrasse.
INSERT INTO places_fts VALUES ('poi-lintrigue-75015', 'L’Intrigue', 'restaurant', 'bar brasserie bar-a-cocktails brunch terrasse fait-maison happy-hour terrasse', '24 Pl. Etienne Pernet, 75015 Paris', '', 'L’Intrigue est le pivot social de la Place Étienne Pernet. Cette brasserie moderne a réussi le pari de l’hybridation : café de quartier dès 7h du matin, table bistronomique pour le déjeuner, et bar de nuit chaleureux aux cocktails précis. Le décor, feutré et boisé, tranche avec les établissements plus froids du quartier Félix Faure. Le ’Fait Maison’ y est une règle stricte, appliquée aussi bien aux pâtisseries qu’aux jus de fruits du bar, faisant de l''endroit une valeur refuge constante, particulièrement pour ses brunchs saisonniers très prisés.');
