enu","display_label":"Les Menus Dégustation","items":[{"name":"Menu en 6 Étapes","price_cents":25000,"description":"Le voyage complet dans l’univers de Grégory Garimbay"},{"name":"Menu en 4 Étapes","price_cents":20000},{"name":"Menu en 3 Étapes","price_cents":17000},{"name":"Menu Diamant Noir (Saison Truffe)","price_cents":32000,"description":"5 services dédiés à la truffe noire"}]},{"category_type":"other","display_label":"La Nature & Le Jardin","items":[{"name":"Araignée de Mer de casier","price_cents":6500,"description":"Au caviar, bouillon de carcasse infusé","is_highlight":true},{"name":"Courge du Potager","price_cents":5500,"description":"Au riz noir de Camargue, condiment fumé"},{"name":"Langoustine de Bretagne","price_cents":7500,"description":"Juste saisie, beurre de corail"},{"name":"Légumes de Saison","price_cents":4800,"description":"Cuisinés en différentes textures, fleurs du jardin"},{"name":"Turbot de Ligne","price_cents":8500,"description":"À la nacre, émulsion au pin"},{"name":"Veau de Lait","price_cents":8000,"description":"Quasi rôti, jus perlé, racines de saison"},{"name":"Canette de Challans","price_cents":7800,"description":"Poitrine fondante, cerise et hibiscus"}]},{"category_type":"dessert","display_label":"Les Douceurs Botaniques","items":[{"name":"Chocolat & Aiguilles de Pin","price_cents":3200,"description":"Une signature végétale et intense"},{"name":"Miel du Saint James","price_cents":2800,"description":"Glacé, pollen frais et agrumes"},{"name":"Soufflé Passion","price_cents":3000,"description":"Cœur coulant, sorbet gingembre"},{"name":"Sélection de Fromages de Maître","price_cents":3400}]},{"category_type":"drink","display_label":"La Cave & Boissons","items":[{"name":"Verre de Sancerre (Domaine Vacheron)","price_cents":2200},{"name":"Cocktail Signature ’Bellefeuille''","price_cents":2800},{"name":"Thé Rare (Sélection)","price_cents":1400},{"name":"Expresso Bio","price_cents":900}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bellefeuille/gallery_4.jpg"]', NULL, '{"text":"Bellefeuille est une bulle. On oublie qu’on est à Paris. La cuisine de Garimbay est d''une légèreté incroyable, avec un focus rare sur le végétal sans jamais être ennuyeux.","must_eat":"Cuisine française. Araignée de Mer au Caviar","le_secret":"La piscine de l’hôtel est accessible aux résidents, mais l''ambiance du jardin est ouverte à tous pour le dîner.","le_son":"L’élégance du silence, feutré par les tapis et la végétation.","le_must":"Pour un dîner romantique ou confidentiel où l’on veut vraiment impressionner par le calme et la beauté du lieu."}', 'Table étoilée du mythique hôtel Saint James Paris, Bellefeuille est un écrin de verdure et de sérénité. Le chef Grégory Garimbay y déploie une cuisine inspirée par la nature, les produits de la mer et le potager de l’hôtel. La salle, entre bibliothèque et jardin d’hiver, offre une atmosphère confidentielle et luxueuse, loin du tumulte parisien.', '• **Le Jardin Caché** : En été, demandez une table en terrasse sous la pergola pour vivre l’expérience ''garden party'' la plus chic de Paris.
INSERT INTO places_fts VALUES ('poi-bellefeuille', 'Bellefeuille', 'restaurant', 'français terrasse', '5 Pl. du Chancelier Adenauer, 75116 Paris, France', '', 'Table étoilée du mythique hôtel Saint James Paris, Bellefeuille est un écrin de verdure et de sérénité. Le chef Grégory Garimbay y déploie une cuisine inspirée par la nature, les produits de la mer et le potager de l’hôtel. La salle, entre bibliothèque et jardin d’hiver, offre une atmosphère confidentielle et luxueuse, loin du tumulte parisien.');
