ue,"ferme_tard":false,"accessibility":true,"main_action":{"type":"site","url":"https://www.peninsula.com/fr/paris/hotel-fine-dining/french-rooftop-loiseau-blanc","label":"RÉSERVER"},"terrasse":true,"viande_exception":false,"happy_hour":null}', '{"certification":"gold","avg_budget":350,"is_free":false,"last_updated":"2026-03-27","verified_at":"2026-03-27","menu_items":[{"category_type":"tasting_menu","display_label":"Le Voyage Culinaire (Menus)","items":[{"name":"Menu Dégustation","price_cents":42500,"description":"L’expérience David Bizet en 7 services face à la Tour Eiffel","is_highlight":true},{"name":"Menu Déjeuner","price_cents":18500,"description":"Entrée, Plat, Dessert (Servi du lundi au vendredi)"},{"name":"Accord Mets & Vins ’Aventure''","price_cents":19500},{"name":"Accord ’Grande Réserve''","price_cents":35000}]},{"category_type":"other","display_label":"Les Étapes de l’Envol","items":[{"name":"Prélude Gourmand","price_cents":0,"description":"Série d’amuse-bouches autour des céréales"},{"name":"Tomate de pleine terre","price_cents":0,"description":"En eau glacée, herbes du jardin"},{"name":"Langoustine Royale","price_cents":0,"description":"Celle du Guilvinec, fumée et nacrée","is_highlight":true},{"name":"Turbot de ligne","price_cents":0,"description":"Cuit sur l’arête, condiment algues et bergamote"},{"name":"Bar de Petit Bateau","price_cents":0,"description":"Écailles croustillantes, jus de coquillages"},{"name":"Poulet de Bresse en deux services","price_cents":0,"description":"La signature du chef, cuit au foin","is_highlight":true},{"name":"Ris de Veau de Lait","price_cents":0,"description":"Laqué au réglisse, déclinaison de carottes"}]},{"category_type":"dessert","display_label":"Final & Douceurs","items":[{"name":"Fromages Affinés","price_cents":3500,"description":"Sélection de la maison Quatrehomme"},{"name":"L’Oiseau Blanc au Chocolat","price_cents":0,"description":"Dessert signature rendant hommage à l’aviation","is_highlight":true},{"name":"Riz au Lait & Caramel","price_cents":0,"description":"Le souvenir d’enfance réinventé"},{"name":"Mignardises de l’Atelier","price_cents":0}]},{"category_type":"drink","display_label":"Cave & Cocktails","items":[{"name":"Coupe de Champagne Peninsula","price_cents":3200},{"name":"Cocktail ’Kléber 1927''","price_cents":2800},{"name":"Bouteille de Puligny-Montrachet","price_cents":21000},{"name":"Eau Minérale (75cl)","price_cents":1200},{"name":"Expresso Pur Origine","price_cents":1000}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/l-oiseau-blanc/gallery_4.jpg"]', NULL, '{"text":"L’Oiseau Blanc, c’est le luxe ultime. On y vient pour la vue (indiscutable), mais Bizet a réussi l’exploit de rendre l’assiette aussi mémorable que la Tour Eiffel. C’est précis, c''est riche, et le service est digne du Peninsula.","must_eat":"Cuisine française. L’Oiseau Blanc au Chocolat","le_secret":"La table près de la réplique grandeur nature du biplan au-dessus du vide.","le_son":"Le vent discret sur le rooftop et le murmure des discussions feutrées.","le_must":"Dîner au moment où la Tour Eiffel commence à scintiller."}', 'Perché au 6ème étage de l’hôtel Peninsula, L’Oiseau Blanc rend hommage à l''aviation française avec une réplique du biplan de Nungesser et Coli suspendue dans le vide. Le chef David Bizet y déploie une gastronomie de haute voltige, technique et lisible, récompensée par deux étoiles Michelin. La vue panoramique sur tout Paris et la Tour Eiffel est tout simplement la plus belle de la capitale.', '• **Le Balcon** : En été, la terrasse est un must absolu pour le coucher du soleil.
INSERT INTO places_fts VALUES ('poi-l-oiseau-blanc', 'L’Oiseau Blanc', 'restaurant', 'bar à vin terrasse', '19 Av. Kléber, 75116 Paris, France', '', 'Perché au 6ème étage de l’hôtel Peninsula, L’Oiseau Blanc rend hommage à l''aviation française avec une réplique du biplan de Nungesser et Coli suspendue dans le vide. Le chef David Bizet y déploie une gastronomie de haute voltige, technique et lisible, récompensée par deux étoiles Michelin. La vue panoramique sur tout Paris et la Tour Eiffel est tout simplement la plus belle de la capitale.');
