ception":false,"happy_hour":null}', '{"certification":"gold","avg_budget":160,"is_free":false,"last_updated":"2026-03-27","verified_at":"2026-03-27","menu_items":[{"category_type":"tasting_menu","display_label":"Les Menus Dégustation","items":[{"name":"Menu Substance (9 services)","price_cents":18800,"description":"L’expérience gastronomique ultime du soir"},{"name":"Menu Vibration (7 services)","price_cents":15800},{"name":"Menu Instant Végétal (6 services)","price_cents":13800},{"name":"Menu Essentiel (Midi)","price_cents":9800},{"name":"Menu du Marché (Midi, 3 services)","price_cents":6800}]},{"category_type":"other","display_label":"Les Incontournables","items":[{"name":"Gnocchi de Salsifis","price_cents":4500,"description":"Beurre noisette et café, une signature Matthias Marc","is_highlight":true},{"name":"Poisson de Ligne & Jura","price_cents":5200,"description":"Sauce au Vin Jaune, morilles fraîches"},{"name":"Le Bœuf de nos Terroirs","price_cents":5500,"description":"Maturation longue, jus corsé à l’ail noir"},{"name":"Pigeon de chez Mear","price_cents":5800,"description":"Cuisiné sur le coffre, betterave et cassis"},{"name":"Lieu Jaune de petits bateaux","price_cents":4800,"description":"Émulsion de sapin, poireaux brûlés"},{"name":"Tartare de Veau & Huître","price_cents":3800,"description":"Iode et terre, condiment citron"}]},{"category_type":"dessert","display_label":"Fromages & Desserts","items":[{"name":"Comté Vieilli (Jura)","price_cents":2200,"description":"Servi avec une pointe de miel de sapin"},{"name":"Le Chocolat & Topinambour","price_cents":2400,"description":"Une association audacieuse et terreuse"},{"name":"Agrumes de Saison","price_cents":2000,"description":"Sorbet herbes fraîches, meringue italienne"},{"name":"Baba au Rhum revisité","price_cents":2200,"description":"Chantilly vanille Bourbon"}]},{"category_type":"drink","display_label":"La Cave (Spécialité Jura)","items":[{"name":"Verre de Vin Jaune (Domaine Rolet)","price_cents":2400},{"name":"Verre de Savagnin","price_cents":1800},{"name":"Accord Mets & Vins (7 étapes)","price_cents":11000},{"name":"Expresso Torréfaction Artisanale","price_cents":700}]}]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/substance/gallery_4.jpg"]', NULL, '{"text":"Substance, c’est de l’émotion pure. Ça va vite, c’est précis, et les saveurs sont franches. Matthias Marc (et maintenant Flavio Lucarini) réussit à rendre la haute gastronomie accessible et ultra-fun.","must_eat":"Haute gastronomie. Gnocchi de Salsifis au Café","le_secret":"La sélection de vins au verre est pointue, n’hésitez pas à demander un accord atypique.","le_son":"Le bruit joyeux d’une cuisine ouverte en plein rush.","le_must":"Pour ceux qui aiment voir le travail des chefs et qui cherchent une table qui ’bouge'' dans le 16e."}', 'Porté par l’énergie du chef Matthias Marc (originaire du Jura), Substance est une table vibrante qui bouscule les codes du 16e arrondissement. Entre cuisine d’auteur ultra-créative et hommages appuyés aux racines francomtoises (vin jaune, sapin, fumé), l’expérience est rythmée, moderne et décomplexée. La cuisine ouverte permet d’admirer le ballet millimétré de la brigade.', '• **L''ADN Jurassien** : Ne passez pas à côté des vins du Jura, Substance possède l''une des plus belles sélections de Paris, parfaite pour accompagner le Vin Jaune.
INSERT INTO places_fts VALUES ('poi-substance', 'Substance', 'restaurant', 'gastronomique', '18 Rue de Chaillot, 75116 Paris, France', '', 'Porté par l’énergie du chef Matthias Marc (originaire du Jura), Substance est une table vibrante qui bouscule les codes du 16e arrondissement. Entre cuisine d’auteur ultra-créative et hommages appuyés aux racines francomtoises (vin jaune, sapin, fumé), l’expérience est rythmée, moderne et décomplexée. La cuisine ouverte permet d’admirer le ballet millimétré de la brigade.');
