.co/storage/v1/object/public/place-media/tse-yang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/tse-yang/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine Chinoise. Le Canard Laqué à la Pékinoise & Dim Sum Saint-Jacques.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Tse Yang est la référence absolue de la haute gastronomie chinoise à Paris depuis 1980. Dans un cadre feutré de boiseries laquées et de porcelaines précieuses, le restaurant perpétue l''art du canard pékinois et des vapeurs impériaux. Une institution de Passy où le luxe se déguste avec une précision gastronomique rare, loin des clichés, pour une clientèle internationale exigeante.', 'Le canard laqué en deux services est un rituel immanquable. Pour une expérience plus intime, demandez une table dans les alcôves du fond.', 'TODO', '[]', '[]', 'ChIJy_VA0edv5kcRYF_AiI8Qnpc', NULL, 1);
INSERT INTO places_fts VALUES ('poi-tse-yang', 'Tse Yang', 'restaurant', 'chinois terrasse', '25 Av. Pierre 1er de Serbie, 75116 Paris, France', '', 'Tse Yang est la référence absolue de la haute gastronomie chinoise à Paris depuis 1980. Dans un cadre feutré de boiseries laquées et de porcelaines précieuses, le restaurant perpétue l''art du canard pékinois et des vapeurs impériaux. Une institution de Passy où le luxe se déguste avec une précision gastronomique rare, loin des clichés, pour une clientèle internationale exigeante.');
