_label":"Les Plats","items":[{"name":"Planche Mixte (Sélection de 6 produits)","price_cents":2400},{"name":"Grande Planche de la Maison (10 produits)","price_cents":3800},{"name":"Planche 100% Fromage (Artisanal)","price_cents":2200},{"name":"Planche 100% Charcuterie (Artisanale)","price_cents":2200},{"name":"Camembert rôti au miel et romarin","price_cents":1400},{"name":"Burrata crémeuse et huile de truffe","price_cents":1200}]},{"category_type":"starter","display_label":"Pour Commencer / À Partager","items":[{"name":"Tomme fermière (Portion)","price_cents":450},{"name":"Camembert au Calvados (Portion)","price_cents":450},{"name":"Saucisson artisanal (Jésus de Lyon)","price_cents":500},{"name":"Coppa de Corse (Portion)","price_cents":550},{"name":"Jambon Serrano affiné 18 mois","price_cents":600},{"name":"Terrine de campagne maison","price_cents":650},{"name":"Houmous et gressins","price_cents":600}]},{"category_type":"dessert","display_label":"Douceurs","items":[{"name":"Moelleux au chocolat et crème anglaise","price_cents":800},{"name":"Cheesecake aux coulis de fruits rouges","price_cents":800}]},{"category_type":"drink","display_label":"La Cave & Boissons","items":[{"name":"Verre de vin rouge (AOC Morgon)","price_cents":700},{"name":"Verre de vin blanc (Chardonnay)","price_cents":650},{"name":"Pinte de bière artisanale (Lager)","price_cents":800},{"name":"Cocktail Spritz","price_cents":1000}]}],"dish_price":22}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/le-17-45/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine française. Apéro à composer. Le camembert rôti ou la planche mixte personnalisée.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Le 17.45 est le spécialiste des planches à composer selon vos envies. Situé dans la vivante Rue des Dames aux Batignolles, ce lieu est devenu le repaire incontournable des amateurs d’apéro dînatoire. On y choisit ses fromages et ses charcuteries à la pièce sur une fiche de commande, le tout provenant de petits producteurs passionnés. L’ambiance est jeune, décontractée et souvent très animée en fin de semaine.', '• **Timing Stratégique** : Arrivez dès l’ouverture à 17h45 (d''où le nom !) pour décrocher l''une des tables en terrasse très convoitées.
INSERT INTO places_fts VALUES ('poi-le-17-45', 'Le 17.45 Batignolles', 'restaurant', 'français terrasse ferme tard', '45 Rue des Dames, 75017 Paris, France', '', 'Le 17.45 est le spécialiste des planches à composer selon vos envies. Situé dans la vivante Rue des Dames aux Batignolles, ce lieu est devenu le repaire incontournable des amateurs d’apéro dînatoire. On y choisit ses fromages et ses charcuteries à la pièce sur une fiche de commande, le tout provenant de petits producteurs passionnés. L’ambiance est jeune, décontractée et souvent très animée en fin de semaine.');
