llery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-rostang/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie française. La canette au sang à la presse ou la quenelle de brochet.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Maison Rostang est l’un des joyaux de la haute gastronomie parisienne, doublement étoilé au Guide Michelin. Sous la houlette du chef Nicolas Beaumann, cette institution du 17ème arrondissement perpétue un héritage de classicisme magnifié par une créativité contemporaine sans faille. Le cadre est feutré, riche de collections d’objets d''art, offrant un théâtre idéal pour des plats de légende comme la canette au sang ou le cigare au chocolat.', '• **Timing Stratégique** : Le menu déjeuner à 105€ est l’une des meilleures façons de découvrir l''excellence Rostang sans l''addition du soir.
INSERT INTO places_fts VALUES ('poi-maison-rostang', 'Maison Rostang', 'restaurant', 'gastronomique', '20 Rue Rennequin, 75017 Paris, France', '', 'Maison Rostang est l’un des joyaux de la haute gastronomie parisienne, doublement étoilé au Guide Michelin. Sous la houlette du chef Nicolas Beaumann, cette institution du 17ème arrondissement perpétue un héritage de classicisme magnifié par une créativité contemporaine sans faille. Le cadre est feutré, riche de collections d’objets d''art, offrant un théâtre idéal pour des plats de légende comme la canette au sang ou le cigare au chocolat.');
