korhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/mallory-gabsi/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie. La langoustine au foin ou le turbot au caviar.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Mallory Gabsi propose une expérience gastronomique instinctive et poétique au cœur du 17e. Récipiendaire d''une étoile Michelin à seulement 26 ans, le jeune prodige belge déploie une cuisine spectaculaire où le terroir français rencontre des influences contemporaines audacieuses. Le cadre, intimiste et tamisé, sert de théâtre à des assiettes graphiques aux saveurs tranchées.', '• **Plat Signature** : La langoustine au foin, une claque olfactive et gustative qui a fait la renommée du chef.
INSERT INTO places_fts VALUES ('poi-mallory-gabsi', 'Mallory Gabsi', 'restaurant', 'gastronomique', '28 Rue des Acacias, 75017 Paris, France', '', 'Mallory Gabsi propose une expérience gastronomique instinctive et poétique au cœur du 17e. Récipiendaire d''une étoile Michelin à seulement 26 ans, le jeune prodige belge déploie une cuisine spectaculaire où le terroir français rencontre des influences contemporaines audacieuses. Le cadre, intimiste et tamisé, sert de théâtre à des assiettes graphiques aux saveurs tranchées.');
