INSERT INTO places_fts VALUES ('poi-oxte', 'Oxte', 'restaurant', 'mexicain', '5 Rue Troyon, 75017 Paris, France', '', 'Oxte est le terrain d’expression étoilé du chef Enrique Casarrubias, qui marie avec brio la haute gastronomie française et les saveurs vibrantes de son Mexique natal. Dans un cadre intimiste à quelques pas de l’Arc de Triomphe, chaque plat raconte une histoire de métissage, où le mole traditionnel rencontre le turbot de ligne. Une cuisine colorée, épicée avec une finesse rare, et profondément authentique.');
