INSERT INTO places_fts VALUES ('poi-papillon', 'Papillon', 'restaurant', 'français', '8 Rue Meissonier, 75017 Paris, France', '', 'Papillon est l’écrin de Christophe Saintagne, ancien chef de file de l’écurie Ducasse. Ici, la gastronomie se dépouille de ses artifices pour revenir à l’essentiel : le goût juste et le produit magnifié. Le cadre minimaliste et élégant du quartier Wagram sert de théâtre à une partition culinaire d’une précision chirurgicale.');
