tion":false,"happy_hour":null}', '{"certification":"gold","is_free":false,"last_updated":"2026-03-27","verified_at":"2026-03-27","menu_items":[{"category_type":"tasting_menu","display_label":"Les Formules & Menus","items":[{"name":"Menu Initiation (Matinée/Midi)","price_cents":6500},{"name":"Menu Signature (Soirée)","price_cents":12000},{"name":"Menu Dégustation Anona","price_cents":15500},{"name":"Accord Boissons Sans Alcool","price_cents":4500},{"name":"Accord Vins Bio & Engagés","price_cents":6000}]},{"category_type":"starter","display_label":"Les Entrées","items":[{"name":"Le Maïs : bœuf Wagyu, maïs habañero, tortilla croustillante","price_cents":1900},{"name":"Le Canard Mulard : à la moutarde, en raviole, figues","price_cents":2200},{"name":"Les Couteaux : vinaigrette à l’huile de graines de courge","price_cents":1700},{"name":"La Carotte des Sables (Vegan) : cuite au jus de carotte","price_cents":2400},{"name":"Asperges Blanches, sabayon agrumes et oxalis","price_cents":2100},{"name":"Betterave rôtie au feu de bois, brebis de l’Aveyron","price_cents":1800}]},{"category_type":"main","display_label":"Les Plats","items":[{"name":"Le Cabillaud : pané, chou rouge et kale, pomme de terre","price_cents":3800},{"name":"Le Pigeon : rôti sur l’os et cuisse confite à la noisette","price_cents":3800},{"name":"Le Cochon Montalet : noix d’entrecôte rôtie, haricots coco","price_cents":4900},{"name":"Poisson de Petit Bateau, émulsion d’arêtes grillées","price_cents":3600},{"name":"Céleri-Rave en croûte de sel, truffe noire d’hiver","price_cents":3500},{"name":"Risotto de petit épeautre, champignons des bois","price_cents":3200}]},{"category_type":"dessert","display_label":"Les Desserts","items":[{"name":"Dessert du Chariot selon l’humeur du Chef","price_cents":1400},{"name":"Le Soufflé Anona : création de saison","price_cents":1600},{"name":"Mignardises de la Maison Spiwack","price_cents":1000},{"name":"Poire Confite, sorbet verveine du jardin","price_cents":1400}]}],"dish_price":37}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/anona/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Haute gastronomie. Le cabillaud pané ou les créations au maïs.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Anona est la table engagée du chef Thibaut Spiwack (Top Chef), récompensée d’une étoile Michelin et d’une étoile verte. Situé face au square des Batignolles, ce restaurant sublime la gastronomie durable avec une éthique radicale : approvisionnement local féroce, réduction totale des déchets et technique de haut vol. Un lieu où l''excellence ne sacrifie jamais la conscience écologique.', '• **Engagement** : La démarche éco-responsable est poussée à l’extrême, n''hésitez pas à poser des questions sur l''origine des produits.
INSERT INTO places_fts VALUES ('poi-anona', 'ANONA', 'restaurant', 'gastronomique terrasse', '80 Bd des Batignolles, 75017 Paris, France', '', 'Anona est la table engagée du chef Thibaut Spiwack (Top Chef), récompensée d’une étoile Michelin et d’une étoile verte. Situé face au square des Batignolles, ce restaurant sublime la gastronomie durable avec une éthique radicale : approvisionnement local féroce, réduction totale des déchets et technique de haut vol. Un lieu où l''excellence ne sacrifie jamais la conscience écologique.');
