INSERT INTO places_fts VALUES ('poi-brasserie-barbes', 'Brasserie Barbès', 'restaurant', 'français brasserie rooftop festif cocktails terrasse ferme tard', '2 Bd Barbès, 75018 Paris, France', '', 'Installée dans un ancien magasin Tati mémorable, cette brasserie géante sur quatre niveaux est le cœur battant du carrefour Barbès. Entre déco industrielle, rooftop végétalisé et dancing, on y vient pour un cocktail, un burger ou un plat de saison dans une atmosphère ultra-parisienne et métissée.');
