INSERT INTO places_fts VALUES ('poi-chantoiseau', 'Chantoiseau', 'restaurant', 'français terrasse', '63 Rue Lepic, 75018 Paris, France', '', 'Une pépite bistronomique perchée sur la Butte. Chantoiseau propose une cuisine d’auteur, précise et saisonnière, dans un cadre épuré et chaleureux. Le chef magnifie des produits d’exception avec des associations audacieuses, faisant de cette adresse l’une des plus excitantes du 18e.');
