INSERT INTO places_fts VALUES ('poi-le-relais-gascon', 'Le Relais Gascon', 'restaurant', 'français gascon sud-ouest salades-geantes montmartre terrasse ferme tard', '6 Rue des Abbesses, 75018 Paris, France', '', 'Une institution montmartroise célèbre pour ses salades XXL servies dans des bols géants, accompagnées de pommes de terre sautées à l''ail. L''ambiance y est conviviale, rustique et chaleureuse, typique des bistrots de quartier où l''on vient pour la générosité des portions et l''accueil sans chichis.');
