INSERT INTO places_fts VALUES ('poi-popine-sacre-coeur', 'Popine Sacré Coeur', 'restaurant', 'pizzas terrasse', '10 Rue Dancourt, 75018 Paris, France', '', 'Popine apporte l''excellence de la pizza napolitaine au cœur de Montmartre. Dans un décor moderne et chaleureux, les pizzas à la pâte légère et aux ingrédients sourcés directement en Italie sortent d''un impressionnant four à bois. Une valeur sûre pour les amateurs de margherita authentique.');
