INSERT INTO places_fts VALUES ('poi-sacree-fleur-montmartre', 'Sacrée Fleur Montmartre', 'restaurant', 'bistrot', '50 Rue de Clignancourt, 75018 Paris, France', '', 'Sacré Fleur est une adresse sacrée pour les amateurs de viande à Montmartre. Situé au pied de la Butte, ce restaurant familial se spécialise dans les pièces de bœuf d’exception (Charolais) accompagnées de frites maison et de sauces traditionnelles. Une ambiance de bistrot parisien chaleureux et sans chichis.');
