pabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/bulot-bulot/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Cuisine de la mer. Poissons et Crustacés. Huîtres de Blainville & Lobster Roll","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'À deux pas de Pigalle, Bulot Bulot est l’ambassade de la côte normande dans le 18e. Ici, pas de chichis : on s’installe au bar ou en terrasse pour déguster des huîtres ultra-fraîches, des bulots à l’aïoli et surtout leurs célèbres Lobster Rolls. L''ambiance est iodée, conviviale et délicieusement rétro. Une escale maritime indispensable en plein Paris.', '• Pas de réservation : venez tôt pour choper une place en terrasse rue des Martyrs.
INSERT INTO places_fts VALUES ('poi-bulot-bulot', 'Bulot Bulot Seafood Bar', 'restaurant', 'mer terrasse ferme tard', '83 Rue des Martyrs, 75018 Paris, France', '', 'À deux pas de Pigalle, Bulot Bulot est l’ambassade de la côte normande dans le 18e. Ici, pas de chichis : on s’installe au bar ou en terrasse pour déguster des huîtres ultra-fraîches, des bulots à l’aïoli et surtout leurs célèbres Lobster Rolls. L''ambiance est iodée, conviviale et délicieusement rétro. Une escale maritime indispensable en plein Paris.');
