rnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-marmite/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Bistrot. La Marmite.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Bistrot de quartier planté juste à la sortie du métro Pigalle, La Marmite joue la carte du bistrot parisien classique sans chichi. On y vient pour un déjeuner express avec la formule à 19,50€, pour le couscous du lundi qui fait venir les réguliers de tout le 18ème, ou simplement pour un Happy Hour de 7 heures (16h-23h) où tous les cocktails tombent à 5€. La terrasse spacieuse est le spot idéal pour observer le ballet permanent du boulevard de Clichy, entre touristes du Moulin Rouge et habitués du quartier.', 'Le couscous n’est servi que le lundi — les habitués le savent et débarquent en masse, note le dans ton agenda. La formule express du midi (entrée+plat ou plat+dessert à 19,50€) est un rapport qualité-prix imbattable pour le quartier. Un avis Google récent recommande la soupe à l''oignon et la salade montmartroise comme alternatives aux classiques.', 'Pigalle', '[2,12]', '[]', 'TODO', NULL, 1);
INSERT INTO places_fts VALUES ('poi-308', 'La Marmite', 'restaurant', 'bistrot bar afterwork terrasse', '2 Boulevard de Clichy', '', 'Bistrot de quartier planté juste à la sortie du métro Pigalle, La Marmite joue la carte du bistrot parisien classique sans chichi. On y vient pour un déjeuner express avec la formule à 19,50€, pour le couscous du lundi qui fait venir les réguliers de tout le 18ème, ou simplement pour un Happy Hour de 7 heures (16h-23h) où tous les cocktails tombent à 5€. La terrasse spacieuse est le spot idéal pour observer le ballet permanent du boulevard de Clichy, entre touristes du Moulin Rouge et habitués du quartier.');
