nsa-montmartre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/maison-pinsa-montmartre/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Pizzeria. Maison Pinsa Montmartre.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Niché au pied de Montmartre, Maison Pinsa est le temple de la Pinsa Romana, cette pizza ancestrale réinventée avec un mélange de trois farines pour une légèreté absolue. Le cadre est adorable, la décoration soignée avec des touches végétales et l’accueil toujours chaleureux. Un spot parfait pour un date ou un dîner entre amis après une balade dans le 18e.', '• Ne passez pas à côté de la Pinsa Romana : sa pâte est bien plus digeste et croustillante que la Napolitaine classique.
INSERT INTO places_fts VALUES ('poi-maison-pinsa-montmartre', 'Maison Pinsa Montmartre', 'restaurant', 'pizzeria pinsa italien', '94 Rue des Martyrs, 75018 Paris', '', 'Niché au pied de Montmartre, Maison Pinsa est le temple de la Pinsa Romana, cette pizza ancestrale réinventée avec un mélange de trois farines pour une légèreté absolue. Le cadre est adorable, la décoration soignée avec des touches végétales et l’accueil toujours chaleureux. Un spot parfait pour un date ou un dîner entre amis après une balade dans le 18e.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-079', 'La Station — Gare des Mines', 'la-station', 'bar', 'friche-culturelle', 'festif', 48.901224, 2.369937, 18, '29 Av. de la Prte d’Aubervilliers', '#ffab60', 'pin', 1, 4.4, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/hero.jpg', NULL, 6, 0, '€', 6, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["bar","friche-culturelle"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":6,"is_free":false,"pint_price":6,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-station/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Friche-culturelle. La Station — Gare des Mines.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Née dans une ancienne gare de charbons à la lisière d’Aubervilliers, La Station est le projet fou du collectif MU. C’est une friche culturelle à l’état pur, où l’esthétique industrielle et bétonnée sert de décor à l’avant-garde musicale et artistique. Pendant les mois d’été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C’est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l’imprévu, le son fort, et cette vibration brute qu’on ne trouve plus nulle part ailleurs.', 'Prévoyez vos bouchons d’oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-079', 'La Station — Gare des Mines', 'bar', 'friche-culturelle', '29 Av. de la Prte d’Aubervilliers', '', 'Née dans une ancienne gare de charbons à la lisière d’Aubervilliers, La Station est le projet fou du collectif MU. C’est une friche culturelle à l’état pur, où l’esthétique industrielle et bétonnée sert de décor à l’avant-garde musicale et artistique. Pendant les mois d’été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C’est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l’imprévu, le son fort, et cette vibration brute qu’on ne trouve plus nulle part ailleurs.');
