mmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/pizza-del-mondo/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Italien. Pizza del Mondo.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Situé dans la charmante rue des Trois Frères, à quelques volées de marches du Sacré-Cœur, Pizza Del Mondo est l’archétype du petit italien de quartier sans prétention mais extrêmement généreux. Connu pour son ambiance intime et son accueil familial, l’établissement mise sur une cuisson au four à pierre pour des pizzas croustillantes. C’est l''escale idéale après une balade dans les ruelles de Montmartre, loin des pièges à touristes de la Place du Tertre.', '• La pâte est cuite au four à pierre, garantissant un croustillant parfait.
INSERT INTO places_fts VALUES ('poi-pizza-del-mondo', 'Pizza del Mondo', 'restaurant', 'italien pizza pates montmartre fait-maison', '16 Rue des Trois Frères, 75018 Paris', '', 'Situé dans la charmante rue des Trois Frères, à quelques volées de marches du Sacré-Cœur, Pizza Del Mondo est l’archétype du petit italien de quartier sans prétention mais extrêmement généreux. Connu pour son ambiance intime et son accueil familial, l’établissement mise sur une cuisson au four à pierre pour des pizzas croustillantes. C’est l''escale idéale après une balade dans les ruelles de Montmartre, loin des pièges à touristes de la Place du Tertre.');
