"VOIR LA CARTE"},"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"last_updated":"2026-03-22","menu_items":[{"category_type":"starter","display_label":"Entrées","items":[{"name":"Salade de Tofu frité","price_cents":480},{"name":"Algues marinées au sésame","price_cents":450},{"name":"Pommes de terre à la vinaigrette de Xi’an","price_cents":420},{"name":"Oreilles de porc pimentées","price_cents":550},{"name":"Concombre frappé à l’ail","price_cents":450},{"name":"Raviolis Porc & Chou (8 pièces)","price_cents":1200},{"name":"Raviolis Poulet & Champignon (8 pièces)","price_cents":1200},{"name":"Raviolis Végétariens (8 pièces)","price_cents":1150},{"name":"Assiette dégustation (12 pièces)","price_cents":1600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Mo au Porc mijoté","price_cents":650,"description":"Pain pita croustillant"},{"name":"Mo au Bœuf au curry","price_cents":700},{"name":"Mo au Canard laqué","price_cents":750},{"name":"Mo Végétarien","price_cents":600}]},{"category_type":"main","display_label":"Plats","items":[{"name":"Biang Biang au Bœuf mijoté","price_cents":1280,"description":"Nouilles larges maison, épices"},{"name":"Biang Biang au Porc haché","price_cents":1150},{"name":"Biang Biang Poulet croustillant","price_cents":1300},{"name":"Biang Biang Tomate & Œuf","price_cents":1080,"description":"Option végétarienne iconique"},{"name":"Biang Biang Canard laqué","price_cents":1450}]},{"category_type":"dessert","display_label":"Desserts","items":[{"name":"Mochi glacé (2)","price_cents":450},{"name":"Perles de coco","price_cents":480}]}],"dish_price":11.5}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-taverne-de-zhao-menilmontant/gallery_4.jpg"]', NULL, '{"text":"Une taverne vibrante dédiée aux saveurs de Xi''an, où l''authenticité se goûte dans chaque bol de nouilles tirées à la main.","must_eat":"Cuisine chinoise. Biang Biang & Mo (Pain traditionnel).","le_secret":"La pâte est pétrie et étirée sous vos yeux, une technique ancestrale qui donne aux nouilles cette mâche unique.","le_son":"Le bruit sourd des pâtes que l''on claque sur le plan de travail et l''animation joyeuse des convives.","le_must":"Le Mo au porc mijoté, un réconfort absolu."}', 'Dernière-née du groupe, la Taverne Ménilmontant apporte les saveurs de Xi’an dans l’est parisien. Le décor y est particulièrement chaleureux, parfaitement intégré à l’esprit populaire et artistique du 20e arrondissement. On y retrouve l''excellence des Biang Biang tirées à la main.', '• Sa salle spacieuse en fait l’adresse la plus confortable du groupe pour les grandes tablées d’amis.
INSERT INTO places_fts VALUES ('poi-zhao-menilmontant', 'La Taverne de Zhao', 'restaurant', 'chinois', '42 rue de Ménilmontant, 75020 Paris, France', '', 'Dernière-née du groupe, la Taverne Ménilmontant apporte les saveurs de Xi’an dans l’est parisien. Le décor y est particulièrement chaleureux, parfaitement intégré à l’esprit populaire et artistique du 20e arrondissement. On y retrouve l''excellence des Biang Biang tirées à la main.');
INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-006', 'La Bellevilloise', 'la-bellevilloise', 'bar', 'espace-culturel', 'festif', 48.868351, 2.392157, 20, '19-21 Rue Boyer', '#ffab60', 'pin', 1, 4.3, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/hero.jpg', NULL, 8, 0, '€', 8, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["bar","espace-culturel"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":8,"is_free":false,"pint_price":8,"cocktail_price":0,"coffee_price":0,"dish_price":0,"menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/la-bellevilloise/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Espace-culturel. La Bellevilloise.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Fondée en 1877 comme première coopérative ouvrière de Paris, la Bellevilloise est devenue un haut lieu culturel indépendant. Dans ses halles majestueuses plantées d’oliviers centenaires, on vient écouter du jazz lors du brunch dominical, découvrir une expo engagée ou danser lors des soirées clubbing. Un lieu chargé d’histoire sociale qui continue de faire vibrer l’est parisien avec une programmation éclectique et ouverte.', 'Le brunch du dimanche avec jazz live est magique, mais réservez 2 semaines à l avance.', 'Ménilmontant', '[2]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-006', 'La Bellevilloise', 'bar', 'espace-culturel', '19-21 Rue Boyer', '', 'Fondée en 1877 comme première coopérative ouvrière de Paris, la Bellevilloise est devenue un haut lieu culturel indépendant. Dans ses halles majestueuses plantées d’oliviers centenaires, on vient écouter du jazz lors du brunch dominical, découvrir une expo engagée ou danser lors des soirées clubbing. Un lieu chargé d’histoire sociale qui continue de faire vibrer l’est parisien avec une programmation éclectique et ouverte.');
