INSERT INTO places (id, name, slug, category, subcategory, dominant_mood, lat, lng, arrondissement, address, main_color, map_icon, verified, rating, user_ratings_total, hero_image, instagram_handle, budget_avg, is_free, budget_unit, pint_price, cocktail_price, wine_glass, coffee_price, main_dish_price, category_percentile, mood_scores_json, social_json, categories_json, hours_json, editorial_json, pricing_json, media_json, google_photos_json, ai_insights_json, real_talk_json, description, insider_tip, nearest_metro, metro_line_json, vibes_json, google_id, michelin_stars, has_terrace) VALUES ('poi-080', 'Aux Folies', 'aux-folies', 'bar', 'friche-culturelle', 'festif', 48.872244, 2.378063, 20, '8 Rue de Belleville', '#ffab60', 'pin', 1, 4, 0, 'https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/hero.jpg', NULL, 5, 0, '€', 5, NULL, NULL, 1.6, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["bar","friche-culturelle"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"terrasse":false,"viande_exception":false,"happy_hour":null}', '{"avg_budget":5.5,"is_free":false,"pint_price":5,"cocktail_price":0,"coffee_price":1.6,"dish_price":0,"menu_items":[]}', '{"hero":"https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/hero.jpg","gallery":["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_4.jpg"]}', '["https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/hero.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_1.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_2.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_3.jpg","https://sfirkmmgkorhblpejrnw.supabase.co/storage/v1/object/public/place-media/aux-folies/gallery_4.jpg"]', NULL, '{"text":"Une adresse de caractère, authentique et d''une grande sincérité.","must_eat":"Friche-culturelle. Aux Folies.","le_secret":"L''ambiance unique du quartier.","le_son":"Brouhaha joyeux et convivial.","le_must":"L''accueil chaleureux."}', 'Ancienne guinguette puis cabaret où Édith Piaf et Maurice Chevalier ont fait leurs débuts, Aux Folies est l’épicentre social de Belleville. Sa terrasse tentaculaire, qui déborde sur la rue Denoyez et ses graffitis, est un spectacle permanent. C’est un lieu de mixité totale où se côtoient habitués kabyles, étudiants fauchés et bobos inspirés. L’enseigne au néon rouge brille comme un phare dans la nuit parisienne. On y boit son café à 1,60€ au soleil ou sa bière à 4€ dans le brouhaha, savourant l''un des derniers bastions du Paris populaire et insoumis.', 'Prévoyez vos bouchons d’oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', 'TODO', NULL, 0);
INSERT INTO places_fts VALUES ('poi-080', 'Aux Folies', 'bar', 'friche-culturelle', '8 Rue de Belleville', '', 'Ancienne guinguette puis cabaret où Édith Piaf et Maurice Chevalier ont fait leurs débuts, Aux Folies est l’épicentre social de Belleville. Sa terrasse tentaculaire, qui déborde sur la rue Denoyez et ses graffitis, est un spectacle permanent. C’est un lieu de mixité totale où se côtoient habitués kabyles, étudiants fauchés et bobos inspirés. L’enseigne au néon rouge brille comme un phare dans la nuit parisienne. On y boit son café à 1,60€ au soleil ou sa bière à 4€ dans le brouhaha, savourant l''un des derniers bastions du Paris populaire et insoumis.');
